/* AUTO-GENERATED — South Dakota Special Requirements bank (lazy-loaded by the CDL app). */
window.STATE_SPECIAL = window.STATE_SPECIAL || {};
window.STATE_SPECIAL["SD"] = {"code":"SD","name":"South Dakota","agency":"South Dakota DPS","agencyShort":"DPS","handbook":"https://dps.sd.gov/driver-licensing/commercial-drivers-license/cdl-manual","links":{},"en":[{"q":"What is the maximum legal width of a vehicle and its load on South Dakota highways without a permit?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"answer":1,"explanation":"South Dakota limits the maximum width of any vehicle, including its load, to 102 inches (8 feet 6 inches). Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"What is the maximum legal height for a vehicle including its load on South Dakota highways?","options":["13 feet 6 inches","13 feet","14 feet","15 feet"],"answer":2,"explanation":"South Dakota sets the maximum height for any vehicle, including load, at 14 feet. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"In South Dakota, a vehicle carrying a load of baled hay may legally reach what maximum height?","options":["14 feet","14 feet 6 inches","15 feet","16 feet"],"answer":2,"explanation":"While the general height limit is 14 feet, South Dakota allows a vehicle with a load of baled hay to be up to 15 feet high. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"What is the maximum legal weight on a single axle on South Dakota highways?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"answer":1,"explanation":"South Dakota limits a single axle to 20,000 pounds, matching the federal standard. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"What is the maximum legal weight on a tandem axle group on South Dakota highways?","options":["32,000 pounds","33,000 pounds","34,000 pounds","36,000 pounds"],"answer":2,"explanation":"South Dakota limits a tandem axle group to 34,000 pounds, matching the federal standard. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"Without a special permit, what is the maximum gross vehicle weight allowed on South Dakota Interstate highways?","options":["73,280 pounds","80,000 pounds","90,000 pounds","105,500 pounds"],"answer":1,"explanation":"The maximum gross weight on South Dakota Interstate highways is 80,000 pounds unless the vehicle holds an annual Over 80,000 Pounds on Interstate permit. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"What is the maximum length of a semitrailer operating in a truck tractor-semitrailer combination in South Dakota?","options":["48 feet","53 feet","57 feet","60 feet"],"answer":1,"explanation":"South Dakota allows a semitrailer up to 53 feet in length when operated in a truck tractor-semitrailer combination. Source: SDCL 32-22-8.1 (Length limitations on trailers and semitrailers).","handbook":"","hbref":""},{"q":"On a load being transported in South Dakota, how far may the load extend beyond the rear of the vehicle?","options":["Not more than 3 feet","Not more than 4 feet","Not more than 6 feet","Not more than 8 feet"],"answer":1,"explanation":"A load or its retractable extensions may not extend more than 4 feet beyond the rear bumper, bed, or body of the vehicle. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"In South Dakota, how far may a load extend beyond the front of the vehicle carrying it?","options":["Not more than 2 feet","Not more than 3 feet","Not more than 4 feet","Not more than 5 feet"],"answer":1,"explanation":"A load may not extend more than 3 feet beyond the front bumper, bed, or body of the vehicle. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"What is the maximum weight that may be supported by a steering axle tire in South Dakota, expressed per inch of tire width?","options":["400 pounds per inch","500 pounds per inch","600 pounds per inch","650 pounds per inch"],"answer":2,"explanation":"South Dakota limits steering axle and dual-tire axle loads to 600 pounds per inch of tire width. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"For tires mounted on axles other than steering or dual-tire axles, what is South Dakota's maximum tire weight per inch of tire width?","options":["450 pounds per inch","500 pounds per inch","550 pounds per inch","600 pounds per inch"],"answer":1,"explanation":"South Dakota limits tires on axles other than steering and dual-tire axles to 500 pounds per inch of tire width. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"South Dakota uses the federal Bridge Gross Weight Formula to limit axle-group weight. The formula determines the maximum weight based on which factors?","options":["Only the total number of axles on the vehicle","The distance between extreme axles of a group and the number of axles in that group","The vehicle's registered weight and engine horsepower","The tire width and the posted speed limit of the highway"],"answer":1,"explanation":"South Dakota applies the federal Bridge Formula W = 500[(L x N)/(N-1) + 12N + 36], where L is the distance between the extreme axles of a group and N is the number of axles in that group. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"A South Dakota agricultural producer hauling a harvested crop within 50 miles of the field (not on an Interstate) is allowed what weight tolerance over the legal limits?","options":["5 percent over legal limits","10 percent over legal limits","15 percent over legal limits","No tolerance is allowed"],"answer":1,"explanation":"South Dakota allows up to 10 percent over legal weight limits when hauling a harvested crop within 50 miles of the harvested field, except on the Interstate system. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"South Dakota allows a 5 percent weight tolerance over legal limits for certain farm storage and livestock hauls. What distance and road restriction applies?","options":["Within 25 miles of loading, including Interstates","Within 50 miles of loading, but not on Interstates","Within 100 miles of loading, including Interstates","Anywhere in the state, but not on Interstates"],"answer":1,"explanation":"The 5 percent tolerance for hauling to farm storage or for livestock applies within 50 miles of the loading site and is not allowed on the Interstate system (and is excluded during spring load restrictions). Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"On South Dakota non-Interstate highways, what is the maximum gross weight a properly configured Longer Combination Vehicle with sufficient axles may reach by permit?","options":["80,000 pounds","105,500 pounds","129,000 pounds","164,000 pounds"],"answer":2,"explanation":"South Dakota allows certain Longer Combination Vehicles with enough axles to gross up to 129,000 pounds on non-Interstate roads, provided axle, tire, and bridge formula limits are met. Source: SDCL 32-22-16/32-22-16.1 and ARSD 70:03:01:61.","handbook":"","hbref":""},{"q":"Which South Dakota online system is used to apply for and obtain oversize/overweight vehicle permits?","options":["The IRP Clearinghouse","The SDAPS Permitting System","The FMCSA Portal","The UCR National Registry"],"answer":1,"explanation":"Oversize and overweight permits in South Dakota are obtained through the SDAPS (South Dakota Automated Permitting System) online portal. Source: SD Truck Information Permitting pages, sdtruckinfo.sd.gov; SDAPS at sdaps.sd.gov.","handbook":"","hbref":""},{"q":"When is a South Dakota state oversize/overweight permit generally required for a load on state highways?","options":["Only when the cargo is hazardous material","When transporting a non-divisible load that exceeds size, weight, or both limits","For any commercial vehicle over 26,001 pounds GVWR","Only when crossing a state line into South Dakota"],"answer":1,"explanation":"A permit is required for the movement on state highways of a vehicle transporting a non-divisible load that exceeds legal size, weight, or size-and-weight limitations. Source: SD Truck Information Permitting pages, sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"An Over 80,000 Pounds on Interstate permit in South Dakota allows additional gross weight, but the vehicle still must NOT exceed which of the following?","options":["Its legal axle weight, legal tire weight, or the Bridge Formula weight","A speed of 55 miles per hour","A total length of 53 feet","Travel during daylight hours only"],"answer":0,"explanation":"The Over 80,000 Pounds on Interstate permit does not allow a vehicle to exceed its legal axle weight, legal tire weight, or the weight allowed by the Bridge Gross Weight Formula. Source: SD Truck Information Permitting pages, sdtruckinfo.sd.gov; SDCL 32-22-42.","handbook":"","hbref":""},{"q":"In South Dakota, the length limit that applies to a tractor-semitrailer combination is measured by the trailer length rather than overall length. For a semitrailer-trailer combination (excluding the truck-tractor), what is the maximum combined length?","options":["65 feet, with neither unit over 28.5 feet","75 feet, with neither unit over 40 feet","81.5 feet, with neither unit over 45 feet","85 feet, with neither unit over 48 feet"],"answer":2,"explanation":"A semitrailer-semitrailer or semitrailer-trailer combination (excluding the truck-tractor) may not exceed 81 feet 6 inches, provided neither unit exceeds 45 feet. Source: SDCL 32-22-8.1.","handbook":"","hbref":""},{"q":"Under South Dakota's farm machinery exemption, a farmer operating farm machinery may exceed the 102-inch width limit during daylight hours, except on which roads?","options":["All paved state highways","Interstate highways","County gravel roads","Roads within city limits"],"answer":1,"explanation":"Farm machinery operated by a farmer has no width limit during daylight hours, except on Interstate highways, where the standard limits apply. Source: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov.","handbook":"","hbref":""},{"q":"In South Dakota, what is the minimum age to obtain a CDL to operate a commercial motor vehicle in INTERSTATE commerce?","options":["18 years old","19 years old","21 years old","25 years old"],"answer":2,"explanation":"South Dakota follows the federal rule: a driver must be at least 21 years of age to obtain a CDL for interstate commerce. Drivers 18-20 may be issued a CDL for intrastate operation only. Source: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 391.11.","handbook":"","hbref":""},{"q":"A South Dakota applicant who is 18 to 20 years old may be issued a CDL, but it is restricted to what type of operation?","options":["Intrastate commerce only (within South Dakota)","Interstate commerce only","Farm vehicles only","Daytime driving only"],"answer":0,"explanation":"South Dakota allows applicants aged 18-20 to receive a CDL valid only for intrastate commerce (driving within South Dakota). Interstate operation requires age 21. Source: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"Under South Dakota's CDL classifications, which combination defines a CLASS A license?","options":["Any single vehicle with a GVWR exceeding 26,000 pounds","Any combination of vehicles with a GCWR exceeding 26,000 pounds where the towed unit has a GVWR exceeding 10,000 pounds","Any vehicle placarded for hazardous materials","Any vehicle designed to carry 16 or more passengers"],"answer":1,"explanation":"South Dakota defines Class A as any combination of vehicles with a Gross Combination Weight Rating (GCWR) exceeding 26,000 lbs, provided the towed vehicle has a GVWR exceeding 10,000 lbs. Source: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"How does South Dakota define a CLASS B commercial driver license?","options":["A combination with a GCWR over 26,000 pounds towing a unit over 10,000 pounds","A single vehicle with a GVWR over 26,000 pounds, or such a vehicle towing a unit not over 10,000 pounds","Any vehicle carrying hazardous waste","Any vehicle with a GVWR under 10,000 pounds"],"answer":1,"explanation":"South Dakota defines Class B as any single vehicle with a GVWR exceeding 26,000 lbs, or any such vehicle towing a vehicle not exceeding 10,000 lbs GVWR. Source: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"In South Dakota, a CLASS C CDL applies to a vehicle that does not meet Class A or B but is either placarded for hazardous materials or designed to transport how many people?","options":["8 or more, including the driver","12 or more, including the driver","16 or more, including the driver","24 or more, including the driver"],"answer":2,"explanation":"South Dakota defines Class C as a single vehicle or combination not meeting Class A or B that is either required to be placarded for hazardous materials or is designed to transport 16 or more passengers, including the driver. Source: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"Which endorsement code does South Dakota place on a CDL for a driver who hauls placarded HAZARDOUS MATERIALS (not in a tank)?","options":["N","T","H","P"],"answer":2,"explanation":"South Dakota uses the H endorsement for transporting placarded hazardous materials. The N endorsement is for tank vehicles, T for doubles/triples, and P for passengers. Source: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Ch. 8 (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"Before South Dakota will add a HazMat (H) endorsement to a CDL, the applicant must complete which federal step in addition to passing the knowledge test?","options":["A TSA security threat assessment including fingerprinting","A 100-hour apprenticeship","An eye surgery clearance","A separate road test in a tank vehicle"],"answer":0,"explanation":"South Dakota cannot issue the HazMat endorsement until the applicant passes the federal TSA Hazardous Materials Endorsement Threat Assessment Program, which requires fingerprinting and a background check, in addition to the written knowledge test. Source: TSA HME program; SD DPS CDL Endorsements; 49 CFR 1572.","handbook":"","hbref":""},{"q":"South Dakota's TANKER (N) endorsement is required for vehicles hauling liquids or gases in a permanent tank rated at 119 gallons or more, or portable tanks with an aggregate rated capacity of at least how many gallons?","options":["500 gallons","750 gallons","1,000 gallons","1,500 gallons"],"answer":2,"explanation":"South Dakota requires the N (tank) endorsement for permanent tanks rated 119 gallons (450 liters) or more, or portable tanks with an aggregate rated capacity of 1,000 gallons or more. Source: SD CDL Manual / SD DPS CDL Endorsements; FMCSA definition of tank vehicle, 49 CFR 383.5.","handbook":"","hbref":""},{"q":"A South Dakota driver who hauls hazardous materials IN A TANK VEHICLE should carry which combined endorsement?","options":["T","X","S","P"],"answer":1,"explanation":"South Dakota uses the X endorsement to represent the combination of tank (N) and hazardous materials (H) for drivers who haul hazardous materials in a tank vehicle. Source: SD Motor Carrier Handbook, Ch. 8, CDL Classifications & Endorsements (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"Which endorsement does South Dakota require for a driver pulling DOUBLE or TRIPLE trailers?","options":["P","N","T","H"],"answer":2,"explanation":"South Dakota requires the T endorsement for double and triple trailers; the applicant must pass a special knowledge examination on the problems of pulling multiple trailers. There is no separate skills test for T. Source: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Ch. 8.","handbook":"","hbref":""},{"q":"To obtain the South Dakota PASSENGER (P) endorsement, a driver must pass a special knowledge test AND what else?","options":["A skills test in a passenger vehicle","A 50-hour ride-along","A TSA background check","A separate vision test in a bus"],"answer":0,"explanation":"South Dakota requires drivers seeking the P endorsement (vehicles designed for 16 or more passengers including the driver) to pass both a special knowledge examination and a skills test conducted in a passenger vehicle. Source: SD DPS CDL Endorsements; SD CDL Manual.","handbook":"","hbref":""},{"q":"In South Dakota, before a driver can be issued the SCHOOL BUS (S) endorsement, the CDL must already carry which other endorsement?","options":["The H (HazMat) endorsement","The T (doubles/triples) endorsement","The P (passenger) endorsement","The N (tank) endorsement"],"answer":2,"explanation":"South Dakota requires the passenger (P) endorsement as a prerequisite to the school bus (S) endorsement; the S applicant must also pass a school bus knowledge test and a skills test. Source: SD DPS CDL Endorsements; SD CDL Manual.","handbook":"","hbref":""},{"q":"For how long is a South Dakota Commercial Learner's Permit (CLP) valid?","options":["60 days","6 months","1 year","5 years"],"answer":2,"explanation":"A South Dakota CLP is issued for a one-year period for behind-the-wheel training. Source: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 383.25.","handbook":"","hbref":""},{"q":"After receiving a Commercial Learner's Permit, how long must a South Dakota applicant wait before being eligible to take the CDL skills test?","options":["At least 7 days","At least 14 days","At least 30 days","At least 90 days"],"answer":1,"explanation":"South Dakota applies the federal rule that a CLP must be held for at least 14 days before the holder is eligible to take the CDL skills (road) test. Source: SD DPS Driver Licensing; 49 CFR 383.25(e).","handbook":"","hbref":""},{"q":"While driving on a South Dakota CLP, the permit holder must be accompanied by a person who holds a valid CDL of the proper class and is seated where?","options":["In the front seat next to the driver","Anywhere in the cab","In a separate escort vehicle","In the sleeper berth"],"answer":0,"explanation":"A South Dakota CLP holder may operate a CMV only when accompanied by a person holding a valid CDL of the appropriate class/endorsements who occupies the front seat beside the driver. Source: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications; 49 CFR 383.25(a).","handbook":"","hbref":""},{"q":"Which set of documents must a South Dakota CDL applicant present at a driver exam station to establish eligibility?","options":["Only a Social Security card","Proof of identity/lawful presence, Social Security number, and South Dakota residency","A passport and a credit card","A high school diploma and a vehicle title"],"answer":1,"explanation":"South Dakota requires proof of identity and lawful presence (date of birth), a Social Security number, and two documents proving South Dakota residency; documents must be originals, not photocopies. Source: SD DPS Required Driver's Licensing Documents (dps.sd.gov).","handbook":"","hbref":""},{"q":"Most CDL applicants in South Dakota who received their CLP after February 7, 2022 must complete Entry-Level Driver Training (ELDT) from a provider listed where?","options":["Any private trucking company's website","The FMCSA Training Provider Registry (TPR)","The South Dakota Secretary of State","The local county sheriff's office"],"answer":1,"explanation":"Federal ELDT rules adopted in South Dakota require theory and behind-the-wheel training from an entity on the FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) for applicants who obtained a CLP on or after February 7, 2022, before taking the skills test. Source: FMCSA ELDT; SD DPS CDL information.","handbook":"","hbref":""},{"q":"Which medical self-certification category applies to a South Dakota driver who operates in interstate commerce and MUST meet the federal DOT medical card requirement?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"answer":1,"explanation":"Non-Excepted Interstate (NI) covers drivers operating in interstate commerce who must meet the federal DOT physical/medical examiner's certificate requirement. EI is excepted interstate, NA/EA are intrastate categories. Source: 49 CFR 383.71; SD DPS Driver Licensing self-certification.","handbook":"","hbref":""},{"q":"A South Dakota CDL or CLP applicant who self-certifies as Non-Excepted Interstate must provide a medical certificate from an examiner listed where?","options":["The FMCSA National Registry of Certified Medical Examiners","Any walk-in urgent care clinic","The South Dakota Department of Health roster","A hospital of the driver's choosing"],"answer":0,"explanation":"South Dakota requires interstate (non-excepted) drivers and school bus operators to obtain certification from a medical professional listed on the FMCSA National Registry of Certified Medical Examiners, and the certificate must be on file with Driver Licensing. Source: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications; 49 CFR 391.41.","handbook":"","hbref":""},{"q":"For how many years is a South Dakota Commercial Driver License (CDL) issued before it must be renewed?","options":["3 years","4 years","5 years","8 years"],"answer":2,"explanation":"South Dakota issues CDLs for a 5-year period, after which the license must be renewed. (Non-commercial SD licenses are issued for longer terms, but CDLs are 5 years.) Source: SD DPS Driver Licensing fees/information (dps.sd.gov).","handbook":"","hbref":""},{"q":"In South Dakota, what is the maximum blood alcohol concentration (BAC) at which a person may legally operate a commercial motor vehicle (CMV)?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"answer":0,"explanation":"South Dakota follows the federal CMV standard: it is illegal to operate a CMV with a BAC of 0.04 percent or more, half the 0.08 limit for non-commercial drivers. Source: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Ch. 8 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"A South Dakota CDL driver is found operating a CMV with a detectable amount of alcohol below 0.04 percent BAC. What is the immediate consequence?","options":["Placed out of service for 24 hours","One-year CDL disqualification","60-day CDL disqualification","Permanent loss of the CDL"],"answer":0,"explanation":"In South Dakota, a CMV driver with any detectable alcohol under 0.04 percent is placed out of service for 24 hours rather than disqualified. A BAC of 0.04 or more triggers a one-year disqualification. Source: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Ch. 8.","handbook":"","hbref":""},{"q":"Under South Dakota's implied consent law, what does a driver agree to by operating any vehicle on a public highway?","options":["To submit to chemical testing for alcohol or drugs","To carry a medical examiner's certificate","To waive the right to a license hearing","To random employer drug screening"],"answer":0,"explanation":"South Dakota's implied consent law means anyone driving on a public highway has consented to a chemical test for alcohol or drugs. Refusal carries its own penalties even if no alcohol was consumed. Source: South Dakota CDL Manual; SDCL 32-23-10 (implied consent).","handbook":"","hbref":""},{"q":"For a FIRST major offense (such as a 0.04+ BAC in a CMV) not involving placarded hazardous materials, how long is a South Dakota CDL holder disqualified?","options":["1 year","60 days","3 years","Lifetime"],"answer":0,"explanation":"A first major offense in South Dakota results in a minimum one-year CDL disqualification. The period rises to three years if the offense occurred while transporting placarded hazardous materials. Source: South Dakota CDL Manual (49 CFR 383.51).","handbook":"","hbref":""},{"q":"How long is a South Dakota CDL driver disqualified for a FIRST major offense committed while transporting hazardous materials required to be placarded?","options":["3 years","1 year","120 days","Lifetime"],"answer":0,"explanation":"In South Dakota the standard one-year disqualification for a first major offense is increased to three years when the violation occurs while operating a CMV transporting placarded hazardous materials. Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"What is the disqualification period in South Dakota for a SECOND major offense arising from a separate incident?","options":["Lifetime","10 years","3 years","1 year"],"answer":0,"explanation":"A second major offense (such as a second DUI in any vehicle, test refusal, or leaving the scene) from a separate incident results in a lifetime CDL disqualification in South Dakota, though reinstatement may be possible after 10 years in some cases. Source: South Dakota CDL Manual (49 CFR 383.51).","handbook":"","hbref":""},{"q":"A South Dakota CDL driver refuses to submit to a chemical test for alcohol. What is the minimum disqualification period?","options":["At least 1 year","60 days","90 days","30 days"],"answer":0,"explanation":"Refusal to submit to required alcohol/drug testing is treated as a major offense in South Dakota and results in a disqualification of at least one year, the same as a 0.04+ BAC. A driver can lose the CDL even if not drinking. Source: South Dakota CDL Manual; SDCL implied consent provisions.","handbook":"","hbref":""},{"q":"How long is a South Dakota CDL driver disqualified upon conviction of TWO serious traffic violations within a 3-year period?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"Two serious traffic violations in separate incidents within three years results in a 60-day disqualification in South Dakota. A third within three years adds 120 days. Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"How long is a South Dakota CDL driver disqualified upon conviction of THREE serious traffic violations within a 3-year period?","options":["120 days","60 days","90 days","1 year"],"answer":0,"explanation":"A third serious traffic violation in separate incidents within three years results in a 120-day disqualification in South Dakota (in addition to the 60 days for the second). Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8.","handbook":"","hbref":""},{"q":"Which of the following is classified as a SERIOUS traffic violation for a South Dakota CDL holder?","options":["Speeding 15 mph or more over the posted limit","Driving with a BAC of 0.04 or more","Refusing a chemical test","Leaving the scene of an accident"],"answer":0,"explanation":"In South Dakota, speeding 15 mph or more over the limit is a serious traffic violation. The other listed offenses are MAJOR offenses carrying one-year or lifetime disqualification, not the serious-violation category. Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8.","handbook":"","hbref":""},{"q":"Which violation is NOT counted among South Dakota's serious traffic violations for CDL purposes?","options":["Operating a CMV with a 0.04+ BAC","Following another vehicle too closely","Improper or erratic lane change","Driving a CMV without holding a CDL"],"answer":0,"explanation":"Operating a CMV with a 0.04+ BAC is a MAJOR offense (one-year disqualification), not a serious traffic violation. Following too closely, improper lane changes, and driving a CMV without a CDL are serious traffic violations. Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8.","handbook":"","hbref":""},{"q":"What is the disqualification period for a FIRST railroad-highway grade crossing violation by a South Dakota CDL driver?","options":["60 days","30 days","120 days","1 year"],"answer":0,"explanation":"A first railroad-highway grade crossing violation results in a 60-day disqualification in South Dakota. A second within three years is 120 days and a third is one year. Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"What is the disqualification period for a SECOND railroad-highway grade crossing violation within 3 years for a South Dakota CDL driver?","options":["120 days","60 days","90 days","1 year"],"answer":0,"explanation":"A second railroad-grade-crossing violation within three years results in a 120-day disqualification in South Dakota. A third within three years results in a one-year disqualification. Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8.","handbook":"","hbref":""},{"q":"What is the disqualification period for a THIRD railroad-highway grade crossing violation within 3 years in South Dakota?","options":["1 year","120 days","180 days","60 days"],"answer":0,"explanation":"A third railroad-grade-crossing violation within a three-year period results in a one-year CDL disqualification in South Dakota. Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"What is the minimum disqualification for a FIRST violation of an out-of-service order by a South Dakota CDL driver (no hazmat or passengers)?","options":["180 days","90 days","60 days","30 days"],"answer":0,"explanation":"A first conviction for violating an out-of-service order results in a disqualification of at least 180 days (up to one year) in South Dakota. The minimum rises to 3 years if hazmat/passengers were involved. Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8.","handbook":"","hbref":""},{"q":"A South Dakota CDL driver commits a SECOND out-of-service order violation within 10 years (no hazmat or passengers). What is the disqualification period?","options":["2 years","1 year","180 days","3 years"],"answer":0,"explanation":"A second out-of-service order violation in separate incidents within 10 years results in a 2-year disqualification in South Dakota. A third within 10 years is 3 years. Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"Using a CMV in the commission of a felony involving manufacturing or distributing a controlled substance results in what disqualification in South Dakota?","options":["Lifetime with no reinstatement","1 year","3 years","10 years then reinstatement"],"answer":0,"explanation":"Using a CMV to commit a felony involving manufacture, distribution, or dispensing of a controlled substance results in a lifetime CDL disqualification with NO possibility of reinstatement in South Dakota. Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51).","handbook":"","hbref":""},{"q":"Under federal rules applied in South Dakota, how many texting convictions while driving a CMV within 3 years trigger a 120-day disqualification?","options":["3 or more","2","5","4"],"answer":0,"explanation":"Two texting violations within three years cause a 60-day disqualification and three or more cause a 120-day disqualification for South Dakota CDL drivers. Texting while driving a CMV is also a serious traffic violation. Source: South Dakota CDL Manual (49 CFR 392.80 / 383.51).","handbook":"","hbref":""},{"q":"For a South Dakota CDL driver, using a hand-held mobile telephone while operating a CMV is best described as which type of violation?","options":["A serious traffic violation","A major offense (1-year disqualification)","An out-of-service order violation","A non-reportable equipment violation"],"answer":0,"explanation":"Using a hand-held mobile phone while driving a CMV is a serious traffic violation in South Dakota; two within 3 years cause a 60-day disqualification and three cause 120 days. Source: South Dakota CDL Manual (49 CFR 392.82 / 383.51).","handbook":"","hbref":""},{"q":"Within how many days must a South Dakota CDL holder notify their employer after being convicted of a traffic violation (other than parking) in any vehicle?","options":["30 days","10 days","15 days","60 days"],"answer":0,"explanation":"South Dakota requires a CDL holder to notify their employer within 30 days of a conviction for any traffic violation (except parking), in any state and in any vehicle. Source: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8.","handbook":"","hbref":""},{"q":"Under South Dakota's Move Over law (updated July 1, 2025), how far ahead of a stopped vehicle displaying amber, yellow, or blue warning lights must a driver begin to respond?","options":["100 feet","200 feet","300 feet","500 feet"],"answer":2,"explanation":"SDCL 32-31-6.1 requires drivers to take action at least 300 feet before the vehicle. Source: SDCL 32-31-6.1; SDDOT Move Over law (eff. July 1, 2025).","handbook":"","hbref":""},{"q":"On a South Dakota multi-lane highway, what does the Move Over law require when approaching a vehicle stopped on the shoulder with warning lights flashing?","options":["Stop completely until the lights are turned off","Merge into the lane farthest from the vehicle and proceed with caution","Slow to 30 mph and stay in the right lane","Honk the horn and pass at the posted limit"],"answer":1,"explanation":"On a road with two or more lanes in the same direction, SDCL 32-31-6.1 requires the driver to merge into the lane farthest from the stopped vehicle at least 300 feet before it and proceed with caution. Source: SDCL 32-31-6.1; SDDOT.","handbook":"","hbref":""},{"q":"On a South Dakota two-lane highway where moving over is not possible, the Move Over law requires a driver to slow to at least how much below the posted speed limit when passing a vehicle with warning lights on the shoulder?","options":["At least 10 mph below the posted limit","At least 15 mph below the posted limit","At least 20 mph below the posted limit","At least 25 mph below the posted limit"],"answer":2,"explanation":"On a two-lane road, SDCL 32-31-6.1 requires slowing to a speed at least 20 mph less than the posted limit (or 5 mph if the limit is 20 mph or less). Source: SDCL 32-31-6.1; SDDOT.","handbook":"","hbref":""},{"q":"Which categories of stopped vehicles are protected by South Dakota's expanded Move Over law?","options":["Only marked law-enforcement vehicles","Only ambulances and fire trucks","Any vehicle on the shoulder displaying flashing amber, yellow, or blue lights, including tow trucks, maintenance vehicles, and disabled vehicles","Only vehicles displaying red and blue emergency lights"],"answer":2,"explanation":"The July 1, 2025 expansion of SDCL 32-31-6.1 covers any vehicle on the shoulder showing flashing amber, yellow, or blue warning lights, including tow trucks, highway maintenance, and disabled motorists. Source: SDCL 32-31-6.1; SDDOT.","handbook":"","hbref":""},{"q":"On a South Dakota two-lane highway, when meeting or overtaking a school bus that has its amber warning lights flashing, a driver must reduce speed to no more than what?","options":["35 mph","25 mph","20 mph","15 mph"],"answer":3,"explanation":"SDCL 32-32-6 requires a motorist to reduce speed to 15 mph or less when a school bus's amber caution lights are flashing. Source: SDCL 32-32-6.","handbook":"","hbref":""},{"q":"When a South Dakota school bus is stopped on a two-lane road with its RED signal lights flashing, an approaching driver must stop at least how far from the bus?","options":["10 feet","15 feet","20 feet","30 feet"],"answer":1,"explanation":"SDCL 32-32-6 requires motorists to bring the vehicle to a complete stop at least 15 feet from the school bus and remain stopped until the red lights stop flashing. Source: SDCL 32-32-6.","handbook":"","hbref":""},{"q":"Under South Dakota law, on which type of roadway may a driver traveling in the OPPOSITE direction proceed without stopping for a school bus that is stopped with red lights flashing?","options":["Any highway with a painted center line","A highway providing two or more lanes of travel in each direction","Any road with a posted limit above 45 mph","Only a fully access-controlled interstate"],"answer":1,"explanation":"SDCL 32-32-6 exempts a driver approaching from the opposite direction on a highway with two or more lanes of travel in each direction from stopping for a school bus with red lights flashing. Source: SDCL 32-32-6.","handbook":"","hbref":""},{"q":"At what distance before a stop must a South Dakota school bus operator activate the amber caution lights?","options":["Not less than 100 nor more than 300 feet","Not less than 200 nor more than 400 feet","Not less than 300 nor more than 500 feet","Not less than 500 nor more than 700 feet"],"answer":2,"explanation":"SDCL 32-32-5.2 requires the amber caution lights to be lit not less than 300 feet nor more than 500 feet before the point where pupils are received or discharged. Source: SDCL 32-32-5.2.","handbook":"","hbref":""},{"q":"On South Dakota's rural interstate highways posted at the maximum, what is the speed limit for a tractor-trailer compared with a passenger car?","options":["Trucks 65 mph; cars 80 mph","Trucks 70 mph; cars 75 mph","Trucks 75 mph; cars 80 mph","Trucks 80 mph; cars 80 mph (the same limit)"],"answer":3,"explanation":"South Dakota posts 80 mph on most rural interstates and applies the same limit to trucks and cars; there is no separate lower truck speed limit. Source: SDCL ch. 32-25; SDDOT speed regulations.","handbook":"","hbref":""},{"q":"In South Dakota, a Longer Combination Vehicle (LCV) operating on the interstate may not exceed what maximum speed?","options":["55 mph","60 mph","65 mph","70 mph"],"answer":2,"explanation":"South Dakota Administrative Rule 70:03:01:61 limits Longer Combination Vehicles to a maximum of 65 mph on interstate highways, even where the posted limit is higher. Source: ARSD 70:03:01:61.","handbook":"","hbref":""},{"q":"In South Dakota, when a placarded hazardous-materials vehicle approaches a railroad crossing required to stop, where must it stop?","options":["Within 5 to 25 feet of the nearest rail","Within 15 to 50 feet of the nearest rail","Within 25 to 75 feet of the nearest rail","Within 50 to 100 feet of the nearest rail"],"answer":1,"explanation":"A placarded vehicle must stop within 15 to 50 feet of the nearest rail, then look and listen before crossing. Source: SD CDL Manual; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"While crossing railroad tracks in South Dakota, what must the driver of a bus or placarded vehicle NOT do?","options":["Look and listen for trains","Shift gears while on the tracks","Use a low gear to maintain power","Make sure there is room to clear the tracks"],"answer":1,"explanation":"Drivers must not shift gears while crossing the tracks, to avoid stalling on the crossing; cross in a gear that need not be changed. Source: SD CDL Manual; 49 CFR 392.10/392.11.","handbook":"","hbref":""},{"q":"At which railroad crossing is a South Dakota bus driver generally NOT required to make the mandatory stop?","options":["A crossing controlled by a police officer or flagger directing traffic through","A multi-track crossing in open country","A crossing with no automatic gates","A crossing on a steep downgrade"],"answer":0,"explanation":"The mandatory stop is not required where a police officer or flagger is directing traffic, at an exempt/abandoned or industrial-spur crossing, or when a green traffic signal controls the crossing. Source: SD CDL Manual; 49 CFR 392.10.","handbook":"","hbref":""},{"q":"How many reflective warning triangles must a South Dakota commercial driver carry and place when stopped on the roadside?","options":["One triangle","Two triangles","Three triangles","Four triangles"],"answer":2,"explanation":"A CMV must carry and deploy three reflective triangles (or equivalent devices), placed within 10 minutes of stopping. Source: SD CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On a two-lane, two-way South Dakota highway, where should the three warning triangles be placed when a truck is stopped?","options":["All three about 100 feet behind the vehicle","About 10 feet, 100 feet, and 200 feet behind the vehicle","Within 10 feet on the traffic side, and about 100 feet ahead of and 100 feet behind the vehicle","About 50 feet ahead, beside, and behind the vehicle"],"answer":2,"explanation":"On a two-lane, two-way road, place one triangle within 10 feet on the traffic side and one about 100 feet behind and one about 100 feet ahead of the vehicle. Source: SD CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"On a South Dakota divided or one-way highway, where are the three warning triangles placed behind a stopped truck?","options":["At 10, 50, and 100 feet","At 10, 100, and 200 feet","At 25, 100, and 300 feet","At 50, 150, and 250 feet"],"answer":1,"explanation":"On a divided or one-way roadway, place the triangles about 10 feet, 100 feet, and 200 feet toward the approaching traffic behind the vehicle. Source: SD CDL Manual; 49 CFR 392.22.","handbook":"","hbref":""},{"q":"Under South Dakota's keep-right rule, when must a driver use the right-hand lane or portion of the roadway?","options":["Only on interstate highways","When proceeding slower than the normal speed of traffic, except when overtaking or when the right lane is impracticable","Only between sunset and sunrise","Only when a truck is following"],"answer":1,"explanation":"SDCL 32-26-1 requires driving on the right half of the roadway and, for slower-than-normal traffic, keeping right except when passing or where using the right lane is impracticable. Source: SDCL 32-26-1.","handbook":"","hbref":""},{"q":"What is the maximum legal vehicle width in South Dakota before an oversize permit is required?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"answer":1,"explanation":"South Dakota's legal width limit without a permit is 8 feet 6 inches (102 inches); anything wider requires an oversize permit. Source: SDDOT/SD Highway Patrol oversize permit rules; SDCL ch. 32-22.","handbook":"","hbref":""},{"q":"In South Dakota, during what hours may an oversize-load (non-divisible width) permit holder generally travel?","options":["24 hours a day, any day","Only Monday through Friday, daylight only","One-half hour before sunrise to one-half hour after sunset, including weekends","Only between 9 a.m. and 4 p.m. on weekdays"],"answer":2,"explanation":"Oversize loads may move from one-half hour before sunrise to one-half hour after sunset, including Saturday and Sunday; overweight-only loads may move continuously. Source: SDDOT/SD Highway Patrol oversize permit rules.","handbook":"","hbref":""},{"q":"Which South Dakota agency issues Commercial Driver Licenses?","options":["The South Dakota Department of Public Safety, Driver Licensing Program","The South Dakota Department of Transportation","The county sheriff's office where the applicant lives","The Federal Motor Carrier Safety Administration"],"answer":0,"explanation":"In South Dakota, CDLs are issued by the Department of Public Safety through its Driver Licensing Program (Pierre, SD). SD DOT handles permits and roads, not driver licensing. Source: SD DPS Driver Licensing / SD Truck Information (sdtruckinfo.sd.gov), Motor Carrier Handbook Ch. 8.","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a South Dakota CDL to drive only in intrastate commerce (within South Dakota)?","options":["16","18","19","21"],"answer":1,"explanation":"South Dakota allows a CDL at age 18 for intrastate commerce; interstate (across state lines) commerce requires age 21. Source: SD Motor Carrier Handbook Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"What is the minimum age to obtain a South Dakota CDL for interstate commerce (driving across state lines)?","options":["18","19","20","21"],"answer":3,"explanation":"Driving in interstate commerce requires a minimum age of 21 in South Dakota; drivers 18 to 20 are limited to intrastate operations. Source: SD Motor Carrier Handbook Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"How long is a South Dakota Commercial Learner's Permit (CLP) valid?","options":["30 days","6 months","1 year","2 years"],"answer":2,"explanation":"A South Dakota CLP is issued for a one-year period for behind-the-wheel training on public roads. Source: SD Motor Carrier Handbook Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"In South Dakota, how long after a Commercial Learner's Permit is issued must an applicant wait before taking the CDL skills test?","options":["No waiting period is required","At least 7 days","At least 14 days","At least 30 days"],"answer":2,"explanation":"There is a 14-day waiting period between the date the CLP is issued and the date the skills test may be completed. Source: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov); reflects federal 49 CFR 383.25.","handbook":"","hbref":""},{"q":"How many self-certification categories must a South Dakota CDL applicant choose from regarding the type of commerce and medical requirements?","options":["Two","Three","Four","Five"],"answer":2,"explanation":"There are four self-certification categories: Non-excepted Interstate (NI), Excepted Interstate (EI), Non-excepted Intrastate (NA), and Excepted Intrastate (EA). Source: SD DPS CDL Medical Certification; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"A South Dakota driver who operates across state lines and is required to meet the federal DOT physical qualification standards self-certifies as which category?","options":["Non-excepted Interstate (NI)","Excepted Interstate (EI)","Non-excepted Intrastate (NA)","Excepted Intrastate (EA)"],"answer":0,"explanation":"Non-excepted Interstate (NI) means the driver operates in interstate commerce and must meet the federal DOT medical certificate requirements (a current medical examiner's certificate). Source: SD DPS CDL Medical Certification; 49 CFR 383.71.","handbook":"","hbref":""},{"q":"When a South Dakota CDL applicant self-certifies as Non-excepted Interstate, what document must be kept on file with the state to remain valid?","options":["A vision waiver from an eye doctor","A current DOT medical examiner's certificate","A signed employer affidavit","A notarized driving log"],"answer":1,"explanation":"Non-excepted drivers must maintain a valid medical examiner's certificate (DOT medical card) on file with the Driver Licensing Program; without it the CDL is downgraded. Source: SD DPS CDL Medical Certification.","handbook":"","hbref":""},{"q":"Who is authorized to perform the physical examination for a South Dakota CDL holder's DOT medical certificate?","options":["Any licensed physician of the driver's choosing","A medical examiner listed on the FMCSA National Registry of Certified Medical Examiners","Only a physician employed by the SD Department of Public Safety","A nurse at any urgent care clinic"],"answer":1,"explanation":"The exam must be performed by a medical professional listed on the FMCSA National Registry of Certified Medical Examiners. Source: SD Motor Carrier Handbook Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); National Registry (nationalregistry.fmcsa.dot.gov).","handbook":"","hbref":""},{"q":"After a South Dakota CDL holder's DOT physical, how does the medical examiner's certificate generally reach the state's Driver Licensing Program?","options":["The driver must hand-deliver it to a courthouse","The examiner submits it electronically to Driver Licensing within 2 business days via the National Registry","It is mailed only by the driver's employer","It is automatically valid without any submission"],"answer":1,"explanation":"Certified medical examiners submit the certificate electronically to South Dakota Driver Licensing within 2 business days through the FMCSA National Registry; drivers may also submit a copy by fax, email, or mail. Source: SD DPS / SD Truck Information (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"What is the maximum period a DOT medical examiner's certificate may be valid for a South Dakota CDL holder?","options":["6 months","1 year","2 years","5 years"],"answer":2,"explanation":"A medical examiner's certificate is valid for up to two years, and may be issued for a shorter period depending on the driver's medical condition. Source: SD Motor Carrier Handbook Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 391.43.","handbook":"","hbref":""},{"q":"Which knowledge test must EVERY South Dakota CDL applicant pass, regardless of vehicle class or endorsements?","options":["The air brakes test","The general knowledge test","The hazardous materials test","The doubles/triples test"],"answer":1,"explanation":"The general knowledge test is taken by all applicants; the other tests are required only for specific vehicles or endorsements. Source: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"The South Dakota CDL skills test consists of which three parts, given in order?","options":["Written exam, vision screening, and road test","Pre-trip inspection, basic vehicle control, and on-road driving","Air brake test, coupling test, and backing test","Knowledge test, simulator test, and night-driving test"],"answer":1,"explanation":"The skills test has three parts: the pre-trip (vehicle) inspection, basic vehicle control maneuvers, and the on-road driving test. Source: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"During the basic vehicle control portion of the South Dakota CDL skills test, what is the applicant primarily asked to demonstrate?","options":["Reciting the entire CDL manual from memory","Moving the vehicle forward, backward, and turning it within a defined area marked by cones","Repairing a brake system","Loading and securing hazardous cargo"],"answer":1,"explanation":"Basic vehicle control evaluates the driver's ability to move the vehicle forward and backward and turn it within a defined area marked with cones or barriers. Source: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"In the pre-trip inspection portion of the South Dakota CDL skills test, what must the applicant do?","options":["Drive through highway traffic","Identify the vehicle components they would inspect and explain what they are checking and why","Demonstrate parallel parking only","Pass a separate written hazmat exam"],"answer":1,"explanation":"The pre-trip inspection requires the driver to demonstrate the ability to evaluate vehicle safety, identifying inspection items and explaining what they would check and why. Source: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"In South Dakota, if an applicant fails a CDL knowledge or skills test, when is the earliest they may retest?","options":["Immediately, the same day","Not before the next working day","After a 30-day waiting period","After a full 6 months"],"answer":1,"explanation":"If you fail any of the tests you may not re-test before the next working day; you may wait longer if you want more study or practice. Source: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"In South Dakota, how many opportunities to test does each test fee cover within a six-month period?","options":["One","Two","Three","Unlimited"],"answer":2,"explanation":"Applicants are allowed three opportunities to test for each fee paid within a six-month period. Exact fee amounts can change, so process rules rather than dollar figures should be relied upon. Source: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov).","handbook":"","hbref":""},{"q":"Under the federal Entry-Level Driver Training (ELDT) rule that South Dakota enforces, where must a first-time CDL applicant complete required training?","options":["Any online course of their choosing","A training provider listed on the FMCSA Training Provider Registry (TPR)","A course offered only by the SD DPS","No formal training is required before testing"],"answer":1,"explanation":"ELDT (effective Feb. 7, 2022) requires entry-level applicants to complete theory and behind-the-wheel training from a provider on the FMCSA Training Provider Registry before taking the CDL skills test (or, for hazmat, the knowledge test). Source: FMCSA ELDT rule (49 CFR Part 380), enforced by SD DPS.","handbook":"","hbref":""},{"q":"To which applicants does the federal ELDT requirement apply when obtaining a South Dakota CDL?","options":["Only drivers over age 65","Applicants obtaining a Class A or B CDL for the first time, upgrading class, or seeking a school bus, passenger, or hazmat endorsement for the first time","Only out-of-state transfer applicants","Only drivers renewing an existing CDL"],"answer":1,"explanation":"ELDT applies to those getting a first Class A or B CDL, upgrading (e.g., B to A), or obtaining a first-time school bus, passenger, or hazardous materials endorsement; it is a one-time requirement, not for routine renewals. Source: FMCSA ELDT rule (49 CFR Part 380), enforced by SD DPS.","handbook":"","hbref":""},{"q":"How long is a South Dakota Commercial Driver License valid before it must be renewed?","options":["1 year","2 years","4 years","5 years"],"answer":3,"explanation":"A South Dakota CDL is valid for five years and expires on the holder's birthday; holders may renew up to 180 days before expiration, typically in person at a DPS exam station with a vision screening. Source: SD DPS Driver Licensing (renewal guidance).","handbook":"","hbref":""}],"ru":{"0":{"q":"Какова максимальная разрешённая ширина транспортного средства вместе с грузом на автомагистралях Южной Дакоты без специального разрешения?","options":["96 дюймов (8 футов)","102 дюйма (8 футов 6 дюймов)","108 дюймов (9 футов)","120 дюймов (10 футов)"],"explanation":"Южная Дакота ограничивает максимальную ширину любого транспортного средства, включая груз, до 102 дюймов (8 футов 6 дюймов). Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"1":{"q":"Какова максимальная разрешённая высота транспортного средства вместе с грузом на автомагистралях Южной Дакоты?","options":["13 футов 6 дюймов","13 футов","14 футов","15 футов"],"explanation":"Южная Дакота устанавливает максимальную высоту любого транспортного средства, включая груз, в 14 футов. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"2":{"q":"В Южной Дакоте транспортное средство, перевозящее груз тюкованного сена, может законно достигать какой максимальной высоты?","options":["14 футов","14 футов 6 дюймов","15 футов","16 футов"],"explanation":"Хотя общий предел высоты составляет 14 футов, Южная Дакота разрешает транспортному средству с грузом тюкованного сена иметь высоту до 15 футов. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"3":{"q":"Каков максимальный разрешённый вес на одиночную ось на автомагистралях Южной Дакоты?","options":["18 000 фунтов","20 000 фунтов","22 400 фунтов","34 000 фунтов"],"explanation":"Южная Дакота ограничивает одиночную ось до 20 000 фунтов, что соответствует федеральному стандарту. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"4":{"q":"Каков максимальный разрешённый вес на сдвоенную группу осей на автомагистралях Южной Дакоты?","options":["32 000 фунтов","33 000 фунтов","34 000 фунтов","36 000 фунтов"],"explanation":"Южная Дакота ограничивает сдвоенную группу осей до 34 000 фунтов, что соответствует федеральному стандарту. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"5":{"q":"Без специального разрешения, какова максимальная полная масса транспортного средства, допустимая на межштатных автомагистралях Южной Дакоты?","options":["73 280 фунтов","80 000 фунтов","90 000 фунтов","105 500 фунтов"],"explanation":"Максимальная полная масса на межштатных автомагистралях Южной Дакоты составляет 80 000 фунтов, если только у транспортного средства нет годового разрешения Over 80,000 Pounds on Interstate. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"6":{"q":"Какова максимальная длина полуприцепа, эксплуатируемого в составе автопоезда «тягач-полуприцеп» в Южной Дакоте?","options":["48 футов","53 фута","57 футов","60 футов"],"explanation":"Южная Дакота разрешает полуприцеп длиной до 53 футов при эксплуатации в составе автопоезда «тягач-полуприцеп». Источник: SDCL 32-22-8.1 (Length limitations on trailers and semitrailers)."},"7":{"q":"Насколько груз, перевозимый в Южной Дакоте, может выступать за заднюю часть транспортного средства?","options":["Не более чем на 3 фута","Не более чем на 4 фута","Не более чем на 6 футов","Не более чем на 8 футов"],"explanation":"Груз или его выдвижные удлинители не могут выступать более чем на 4 фута за задний бампер, платформу или кузов транспортного средства. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"8":{"q":"В Южной Дакоте насколько груз может выступать за переднюю часть перевозящего его транспортного средства?","options":["Не более чем на 2 фута","Не более чем на 3 фута","Не более чем на 4 фута","Не более чем на 5 футов"],"explanation":"Груз не может выступать более чем на 3 фута за передний бампер, платформу или кузов транспортного средства. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"9":{"q":"Какой максимальный вес может выдерживать шина управляемой оси в Южной Дакоте в расчёте на дюйм ширины шины?","options":["400 фунтов на дюйм","500 фунтов на дюйм","600 фунтов на дюйм","650 фунтов на дюйм"],"explanation":"Южная Дакота ограничивает нагрузку на управляемую ось и ось со сдвоенными шинами до 600 фунтов на дюйм ширины шины. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"10":{"q":"Для шин, установленных на осях, отличных от управляемых осей или осей со сдвоенными шинами, каков максимальный вес на шину в расчёте на дюйм ширины шины в Южной Дакоте?","options":["450 фунтов на дюйм","500 фунтов на дюйм","550 фунтов на дюйм","600 фунтов на дюйм"],"explanation":"Южная Дакота ограничивает нагрузку на шины на осях, отличных от управляемых осей и осей со сдвоенными шинами, до 500 фунтов на дюйм ширины шины. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"11":{"q":"Южная Дакота использует федеральную формулу полной массы для мостов (Bridge Gross Weight Formula) для ограничения веса группы осей. Эта формула определяет максимальный вес на основе каких факторов?","options":["Только общего числа осей на транспортном средстве","Расстояния между крайними осями группы и числа осей в этой группе","Зарегистрированной массы транспортного средства и мощности двигателя","Ширины шины и установленного ограничения скорости на автомагистрали"],"explanation":"Южная Дакота применяет федеральную формулу для мостов W = 500[(L x N)/(N-1) + 12N + 36], где L — расстояние между крайними осями группы, а N — число осей в этой группе. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"12":{"q":"Сельскохозяйственный производитель Южной Дакоты, перевозящий собранный урожай в пределах 50 миль от поля (не по межштатной автомагистрали), имеет право на какой допуск превышения веса сверх законных пределов?","options":["5 процентов сверх законных пределов","10 процентов сверх законных пределов","15 процентов сверх законных пределов","Допуск не разрешается"],"explanation":"Южная Дакота допускает превышение законных пределов веса до 10 процентов при перевозке собранного урожая в пределах 50 миль от убранного поля, за исключением системы межштатных автомагистралей. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"13":{"q":"Южная Дакота допускает допуск превышения веса на 5 процентов сверх законных пределов для определённых перевозок к фермерским хранилищам и перевозок скота. Какое расстояние и ограничение по дорогам применяется?","options":["В пределах 25 миль от места погрузки, включая межштатные автомагистрали","В пределах 50 миль от места погрузки, но не по межштатным автомагистралям","В пределах 100 миль от места погрузки, включая межштатные автомагистрали","В любой точке штата, но не по межштатным автомагистралям"],"explanation":"Допуск в 5 процентов для перевозки к фермерскому хранилищу или для перевозки скота применяется в пределах 50 миль от места погрузки и не разрешается на системе межштатных автомагистралей (а также исключается в период весенних ограничений нагрузки). Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"14":{"q":"На немежштатных автомагистралях Южной Дакоты, какой максимальной полной массы может достигать по разрешению должным образом сконфигурированное автотранспортное средство удлинённой комбинации (Longer Combination Vehicle) с достаточным числом осей?","options":["80 000 фунтов","105 500 фунтов","129 000 фунтов","164 000 фунтов"],"explanation":"Южная Дакота допускает, чтобы определённые автотранспортные средства удлинённой комбинации (Longer Combination Vehicles) с достаточным числом осей имели полную массу до 129 000 фунтов на немежштатных дорогах, при условии соблюдения пределов по осям, шинам и формуле для мостов. Источник: SDCL 32-22-16/32-22-16.1 и ARSD 70:03:01:61."},"15":{"q":"Какая онлайн-система Южной Дакоты используется для подачи заявок и получения разрешений на негабаритные/тяжеловесные транспортные средства?","options":["The IRP Clearinghouse","The SDAPS Permitting System","The FMCSA Portal","The UCR National Registry"],"explanation":"Разрешения на негабаритные и тяжеловесные перевозки в Южной Дакоте оформляются через онлайн-портал SDAPS (South Dakota Automated Permitting System). Источник: SD Truck Information Permitting pages, sdtruckinfo.sd.gov; SDAPS на sdaps.sd.gov."},"16":{"q":"Когда в Южной Дакоте, как правило, требуется государственное разрешение на негабаритную/тяжеловесную перевозку для груза на автомагистралях штата?","options":["Только когда груз является опасным материалом","При перевозке неделимого груза, превышающего пределы по размеру, весу или по обоим параметрам","Для любого коммерческого транспортного средства с GVWR свыше 26 001 фунта","Только при пересечении границы штата при въезде в Южную Дакоту"],"explanation":"Разрешение требуется для перемещения по автомагистралям штата транспортного средства, перевозящего неделимый груз, который превышает законные пределы по размеру, весу или по размеру и весу. Источник: SD Truck Information Permitting pages, sdtruckinfo.sd.gov."},"17":{"q":"Разрешение Over 80,000 Pounds on Interstate в Южной Дакоте допускает дополнительную полную массу, но транспортное средство по-прежнему НЕ должно превышать что из перечисленного?","options":["Свой законный вес на ось, законный вес на шину или вес по формуле для мостов","Скорость 55 миль в час","Общую длину 53 фута","Движение только в светлое время суток"],"explanation":"Разрешение Over 80,000 Pounds on Interstate не позволяет транспортному средству превышать свой законный вес на ось, законный вес на шину или вес, допускаемый формулой полной массы для мостов (Bridge Gross Weight Formula). Источник: SD Truck Information Permitting pages, sdtruckinfo.sd.gov; SDCL 32-22-42."},"18":{"q":"В Южной Дакоте предел длины, применяемый к автопоезду «тягач-полуприцеп», измеряется по длине прицепа, а не по общей длине. Для комбинации «полуприцеп-прицеп» (без учёта тягача) какова максимальная суммарная длина?","options":["65 футов, при этом ни один из элементов не превышает 28,5 фута","75 футов, при этом ни один из элементов не превышает 40 футов","81,5 фута, при этом ни один из элементов не превышает 45 футов","85 футов, при этом ни один из элементов не превышает 48 футов"],"explanation":"Комбинация «полуприцеп-полуприцеп» или «полуприцеп-прицеп» (без учёта тягача) не может превышать 81 фут 6 дюймов при условии, что ни один из элементов не превышает 45 футов. Источник: SDCL 32-22-8.1."},"19":{"q":"Согласно исключению для сельскохозяйственной техники в Южной Дакоте, фермер, управляющий сельскохозяйственной техникой, может превышать предел ширины в 102 дюйма в светлое время суток, за исключением каких дорог?","options":["Все асфальтированные автомагистрали штата","Межштатные автомагистрали","Окружные гравийные дороги","Дороги в черте города"],"explanation":"Сельскохозяйственная техника, управляемая фермером, не имеет ограничения по ширине в светлое время суток, за исключением межштатных автомагистралей, где применяются стандартные пределы. Источник: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"20":{"q":"Каков в Южной Дакоте минимальный возраст для получения CDL для управления коммерческим транспортным средством в МЕЖШТАТНЫХ перевозках?","options":["18 лет","19 лет","21 год","25 лет"],"explanation":"Южная Дакота следует федеральному правилу: водителю должно быть не менее 21 года, чтобы получить CDL для межштатных перевозок. Водителям 18-20 лет CDL может быть выдан только для внутриштатных перевозок. Источник: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 391.11."},"21":{"q":"Заявителю в Южной Дакоте в возрасте от 18 до 20 лет может быть выдан CDL, но он ограничен каким типом эксплуатации?","options":["Только внутриштатные перевозки (в пределах Южной Дакоты)","Только межштатные перевозки","Только сельскохозяйственные транспортные средства","Только вождение в дневное время"],"explanation":"Южная Дакота разрешает заявителям в возрасте 18-20 лет получать CDL, действительный только для внутриштатных перевозок (вождение в пределах Южной Дакоты). Для межштатных перевозок требуется возраст 21 год. Источник: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"22":{"q":"Согласно классификациям CDL Южной Дакоты, какая комбинация определяет КЛАСС A?","options":["Любое одиночное транспортное средство с GVWR, превышающим 26 000 фунтов","Любая комбинация транспортных средств с GCWR, превышающим 26 000 фунтов, где буксируемый элемент имеет GVWR, превышающий 10 000 фунтов","Любое транспортное средство с табличками о перевозке опасных материалов","Любое транспортное средство, рассчитанное на перевозку 16 или более пассажиров"],"explanation":"Южная Дакота определяет Класс A как любую комбинацию транспортных средств с полной массой автопоезда (GCWR), превышающей 26 000 фунтов, при условии, что буксируемое транспортное средство имеет GVWR, превышающий 10 000 фунтов. Источник: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov)."},"23":{"q":"Как Южная Дакота определяет коммерческие водительские права КЛАССА B?","options":["Комбинация с GCWR свыше 26 000 фунтов, буксирующая элемент свыше 10 000 фунтов","Одиночное транспортное средство с GVWR свыше 26 000 фунтов или такое транспортное средство, буксирующее элемент не свыше 10 000 фунтов","Любое транспортное средство, перевозящее опасные отходы","Любое транспортное средство с GVWR менее 10 000 фунтов"],"explanation":"Южная Дакота определяет Класс B как любое одиночное транспортное средство с GVWR, превышающим 26 000 фунтов, или любое такое транспортное средство, буксирующее транспортное средство с GVWR не более 10 000 фунтов. Источник: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov)."},"24":{"q":"В Южной Дакоте CDL КЛАССА C применяется к транспортному средству, которое не подпадает под Класс A или B, но либо имеет таблички о перевозке опасных материалов, либо рассчитано на перевозку какого числа людей?","options":["8 или более, включая водителя","12 или более, включая водителя","16 или более, включая водителя","24 или более, включая водителя"],"explanation":"Южная Дакота определяет Класс C как одиночное транспортное средство или комбинацию, не подпадающую под Класс A или B, которое либо обязано иметь таблички о перевозке опасных материалов, либо рассчитано на перевозку 16 или более пассажиров, включая водителя. Источник: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov)."},"25":{"q":"Какой код подтверждения (endorsement) Южная Дакота проставляет в CDL водителю, который перевозит ОПАСНЫЕ МАТЕРИАЛЫ с табличками (не в цистерне)?","options":["N","T","H","P"],"explanation":"Южная Дакота использует подтверждение H для перевозки опасных материалов с табличками. Подтверждение N предназначено для транспортных средств-цистерн, T — для двойных/тройных прицепов, а P — для пассажиров. Источник: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Ch. 8 (sdtruckinfo.sd.gov)."},"26":{"q":"Прежде чем Южная Дакота добавит подтверждение HazMat (H) в CDL, заявитель должен пройти какой федеральный этап в дополнение к сдаче теоретического экзамена?","options":["Оценку угрозы безопасности TSA, включая снятие отпечатков пальцев","100-часовую стажировку","Допуск после операции на глазах","Отдельный экзамен по вождению на транспортном средстве-цистерне"],"explanation":"Южная Дакота не может выдать подтверждение HazMat до тех пор, пока заявитель не пройдёт федеральную программу оценки угрозы для подтверждения на опасные материалы TSA (Hazardous Materials Endorsement Threat Assessment Program), которая требует снятия отпечатков пальцев и проверки данных, в дополнение к письменному теоретическому экзамену. Источник: TSA HME program; SD DPS CDL Endorsements; 49 CFR 1572."},"27":{"q":"Подтверждение ЦИСТЕРНА (N) в Южной Дакоте требуется для транспортных средств, перевозящих жидкости или газы в стационарной цистерне с номинальной вместимостью 119 галлонов или более, либо в переносных цистернах с совокупной номинальной вместимостью не менее скольких галлонов?","options":["500 галлонов","750 галлонов","1 000 галлонов","1 500 галлонов"],"explanation":"Южная Дакота требует подтверждение N (цистерна) для стационарных цистерн с номинальной вместимостью 119 галлонов (450 литров) или более, либо для переносных цистерн с совокупной номинальной вместимостью 1 000 галлонов или более. Источник: SD CDL Manual / SD DPS CDL Endorsements; определение транспортного средства-цистерны FMCSA, 49 CFR 383.5."},"28":{"q":"Водитель в Южной Дакоте, который перевозит опасные материалы В ТРАНСПОРТНОМ СРЕДСТВЕ-ЦИСТЕРНЕ, должен иметь какое объединённое подтверждение?","options":["T","X","S","P"],"explanation":"Южная Дакота использует подтверждение X для обозначения комбинации цистерны (N) и опасных материалов (H) для водителей, которые перевозят опасные материалы в транспортном средстве-цистерне. Источник: SD Motor Carrier Handbook, Ch. 8, CDL Classifications & Endorsements (sdtruckinfo.sd.gov)."},"29":{"q":"Какое подтверждение требуется в Южной Дакоте для водителя, буксирующего ДВОЙНЫЕ или ТРОЙНЫЕ прицепы?","options":["P","N","T","H"],"explanation":"Южная Дакота требует подтверждение T для двойных и тройных прицепов; заявитель должен сдать специальный теоретический экзамен по проблемам буксировки нескольких прицепов. Отдельного практического экзамена для T не предусмотрено. Источник: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Ch. 8."},"30":{"q":"Чтобы получить подтверждение ПАССАЖИР (P) в Южной Дакоте, водитель должен сдать специальный теоретический экзамен И что ещё?","options":["Практический экзамен на пассажирском транспортном средстве","50-часовую поездку в качестве наблюдателя","Проверку данных TSA","Отдельную проверку зрения в автобусе"],"explanation":"Южная Дакота требует от водителей, желающих получить подтверждение P (транспортные средства, рассчитанные на 16 или более пассажиров, включая водителя), сдать как специальный теоретический экзамен, так и практический экзамен, проводимый на пассажирском транспортном средстве. Источник: SD DPS CDL Endorsements; SD CDL Manual."},"31":{"q":"В Южной Дакоте, прежде чем водителю может быть выдано подтверждение ШКОЛЬНЫЙ АВТОБУС (S), CDL уже должен содержать какое другое подтверждение?","options":["Подтверждение H (HazMat)","Подтверждение T (двойные/тройные)","Подтверждение P (пассажир)","Подтверждение N (цистерна)"],"explanation":"Южная Дакота требует наличия подтверждения «пассажир» (P) в качестве предварительного условия для подтверждения «школьный автобус» (S); заявитель на S также должен сдать теоретический экзамен по школьным автобусам и практический экзамен. Источник: SD DPS CDL Endorsements; SD CDL Manual."},"32":{"q":"Как долго действует временное коммерческое ученическое разрешение (CLP) Южной Дакоты?","options":["60 дней","6 месяцев","1 год","5 лет"],"explanation":"CLP Южной Дакоты выдаётся на один год для обучения вождению. Источник: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 383.25."},"33":{"q":"После получения коммерческого ученического разрешения (CLP), сколько времени должен подождать заявитель в Южной Дакоте, прежде чем он сможет сдавать практический экзамен на CDL?","options":["Не менее 7 дней","Не менее 14 дней","Не менее 30 дней","Не менее 90 дней"],"explanation":"Южная Дакота применяет федеральное правило, согласно которому CLP должно удерживаться не менее 14 дней, прежде чем его обладатель сможет сдавать практический (дорожный) экзамен на CDL. Источник: SD DPS Driver Licensing; 49 CFR 383.25(e)."},"34":{"q":"При вождении по CLP Южной Дакоты обладатель разрешения должен сопровождаться лицом, имеющим действительный CDL надлежащего класса, которое находится где?","options":["На переднем сиденье рядом с водителем","В любом месте кабины","В отдельном сопровождающем транспортном средстве","В спальном отсеке"],"explanation":"Обладатель CLP Южной Дакоты может управлять CMV только в сопровождении лица, имеющего действительный CDL надлежащего класса/подтверждений, которое занимает переднее сиденье рядом с водителем. Источник: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications; 49 CFR 383.25(a)."},"35":{"q":"Какой набор документов должен предъявить заявитель на CDL в Южной Дакоте на пункте приёма экзаменов, чтобы подтвердить право на получение?","options":["Только карту социального страхования","Подтверждение личности/законного пребывания, номер социального страхования и проживания в Южной Дакоте","Паспорт и кредитную карту","Аттестат об окончании средней школы и техпаспорт транспортного средства"],"explanation":"Южная Дакота требует подтверждение личности и законного пребывания (даты рождения), номер социального страхования и два документа, подтверждающих проживание в Южной Дакоте; документы должны быть оригиналами, а не фотокопиями. Источник: SD DPS Required Driver's Licensing Documents (dps.sd.gov)."},"36":{"q":"Большинство заявителей на CDL в Южной Дакоте, получивших CLP после 7 февраля 2022 года, должны пройти обучение водителей начального уровня (ELDT) у провайдера, указанного где?","options":["На сайте любой частной транспортной компании","В реестре провайдеров обучения FMCSA (Training Provider Registry, TPR)","У Государственного секретаря Южной Дакоты","В местном окружном офисе шерифа"],"explanation":"Федеральные правила ELDT, принятые в Южной Дакоте, требуют теоретического и практического обучения вождению у организации, входящей в реестр провайдеров обучения FMCSA (tpr.fmcsa.dot.gov), для заявителей, получивших CLP 7 февраля 2022 года или позднее, до сдачи практического экзамена. Источник: FMCSA ELDT; SD DPS CDL information."},"37":{"q":"Какая категория медицинской самосертификации применяется к водителю в Южной Дакоте, который работает в межштатных перевозках и ДОЛЖЕН соответствовать требованию о федеральной медицинской карте DOT?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"explanation":"Категория Non-Excepted Interstate (NI) охватывает водителей, работающих в межштатных перевозках, которые должны соответствовать требованию о федеральном медицинском свидетельстве/справке DOT. EI — это исключённые межштатные перевозки, NA/EA — внутриштатные категории. Источник: 49 CFR 383.71; SD DPS Driver Licensing self-certification."},"38":{"q":"Заявитель на CDL или CLP в Южной Дакоте, который самостоятельно сертифицируется как Non-Excepted Interstate, должен предоставить медицинскую справку от врача, указанного где?","options":["В Национальном реестре сертифицированных медицинских экспертов FMCSA (National Registry of Certified Medical Examiners)","В любой клинике неотложной помощи без записи","В списке Департамента здравоохранения Южной Дакоты","В больнице по выбору водителя"],"explanation":"Южная Дакота требует от водителей межштатных (неисключённых) перевозок и водителей школьных автобусов получать сертификацию от медицинского специалиста, указанного в Национальном реестре сертифицированных медицинских экспертов FMCSA (National Registry of Certified Medical Examiners), и справка должна храниться в Driver Licensing. Источник: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications; 49 CFR 391.41."},"39":{"q":"На сколько лет выдаётся коммерческое водительское удостоверение (CDL) Южной Дакоты, прежде чем его необходимо продлить?","options":["3 года","4 года","5 лет","8 лет"],"explanation":"Южная Дакота выдаёт CDL на 5-летний период, после чего удостоверение необходимо продлить. (Некоммерческие удостоверения SD выдаются на более длительные сроки, но CDL — на 5 лет.) Источник: SD DPS Driver Licensing fees/information (dps.sd.gov)."},"40":{"q":"Какова в Южной Дакоте максимальная концентрация алкоголя в крови (BAC), при которой лицо может законно управлять коммерческим транспортным средством (CMV)?","options":["0,04 процента","0,08 процента","0,02 процента","0,10 процента"],"explanation":"Южная Дакота следует федеральному стандарту для CMV: незаконно управлять CMV с BAC 0,04 процента или более, что составляет половину предела 0,08 для некоммерческих водителей. Источник: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"41":{"q":"Водитель с CDL в Южной Дакоте уличён в управлении CMV с обнаруживаемым количеством алкоголя ниже 0,04 процента BAC. Каково непосредственное последствие?","options":["Отстранение от эксплуатации на 24 часа","Дисквалификация CDL на один год","Дисквалификация CDL на 60 дней","Постоянная потеря CDL"],"explanation":"В Южной Дакоте водитель CMV с любым обнаруживаемым количеством алкоголя ниже 0,04 процента отстраняется от эксплуатации на 24 часа, а не дисквалифицируется. BAC 0,04 или более влечёт дисквалификацию на один год. Источник: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Ch. 8."},"42":{"q":"Согласно закону Южной Дакоты о подразумеваемом согласии (implied consent), на что соглашается водитель, управляя любым транспортным средством на дороге общего пользования?","options":["Пройти химический тест на алкоголь или наркотики","Иметь при себе медицинское свидетельство эксперта","Отказаться от права на слушание по удостоверению","Пройти случайную проверку на наркотики со стороны работодателя"],"explanation":"Закон Южной Дакоты о подразумеваемом согласии означает, что любой, кто управляет транспортным средством на дороге общего пользования, дал согласие на химический тест на алкоголь или наркотики. Отказ влечёт собственные наказания, даже если алкоголь не употреблялся. Источник: South Dakota CDL Manual; SDCL 32-23-10 (implied consent)."},"43":{"q":"За ПЕРВОЕ серьёзное правонарушение (например, BAC 0,04+ в CMV), не связанное с опасными материалами с табличками, на какой срок дисквалифицируется обладатель CDL в Южной Дакоте?","options":["1 год","60 дней","3 года","Пожизненно"],"explanation":"Первое серьёзное правонарушение в Южной Дакоте влечёт минимальную дисквалификацию CDL на один год. Срок увеличивается до трёх лет, если правонарушение было совершено при перевозке опасных материалов с табличками. Источник: South Dakota CDL Manual (49 CFR 383.51)."},"44":{"q":"На какой срок дисквалифицируется водитель с CDL в Южной Дакоте за ПЕРВОЕ серьёзное правонарушение, совершённое при перевозке опасных материалов, требующих наличия табличек?","options":["3 года","1 год","120 дней","Пожизненно"],"explanation":"В Южной Дакоте стандартная дисквалификация на один год за первое серьёзное правонарушение увеличивается до трёх лет, когда нарушение происходит при управлении CMV, перевозящим опасные материалы с табличками. Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"45":{"q":"Каков срок дисквалификации в Южной Дакоте за ВТОРОЕ серьёзное правонарушение, возникшее в результате отдельного инцидента?","options":["Пожизненно","10 лет","3 года","1 год"],"explanation":"Второе серьёзное правонарушение (например, второе вождение в нетрезвом виде на любом транспортном средстве, отказ от теста или оставление места происшествия), возникшее в результате отдельного инцидента, влечёт пожизненную дисквалификацию CDL в Южной Дакоте, хотя в некоторых случаях восстановление может быть возможно по истечении 10 лет. Источник: South Dakota CDL Manual (49 CFR 383.51)."},"46":{"q":"Водитель с CDL в Южной Дакоте отказывается пройти химический тест на алкоголь. Каков минимальный срок дисквалификации?","options":["Не менее 1 года","60 дней","90 дней","30 дней"],"explanation":"Отказ от прохождения обязательного теста на алкоголь/наркотики рассматривается как серьёзное правонарушение в Южной Дакоте и влечёт дисквалификацию не менее одного года, так же как и BAC 0,04+. Водитель может лишиться CDL, даже если не употреблял алкоголь. Источник: South Dakota CDL Manual; положения SDCL о подразумеваемом согласии."},"47":{"q":"На какой срок дисквалифицируется водитель с CDL в Южной Дакоте при осуждении за ДВА серьёзных нарушения ПДД в течение 3-летнего периода?","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Два серьёзных нарушения ПДД в отдельных инцидентах в течение трёх лет влекут дисквалификацию на 60 дней в Южной Дакоте. Третье в течение трёх лет добавляет 120 дней. Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"48":{"q":"На какой срок дисквалифицируется водитель с CDL в Южной Дакоте при осуждении за ТРИ серьёзных нарушения ПДД в течение 3-летнего периода?","options":["120 дней","60 дней","90 дней","1 год"],"explanation":"Третье серьёзное нарушение ПДД в отдельных инцидентах в течение трёх лет влечёт дисквалификацию на 120 дней в Южной Дакоте (в дополнение к 60 дням за второе). Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"49":{"q":"Что из перечисленного классифицируется как СЕРЬЁЗНОЕ нарушение ПДД для обладателя CDL в Южной Дакоте?","options":["Превышение скорости на 15 миль/ч или более сверх установленного предела","Вождение с BAC 0,04 или более","Отказ от химического теста","Оставление места ДТП"],"explanation":"В Южной Дакоте превышение скорости на 15 миль/ч или более сверх предела является серьёзным нарушением ПДД. Остальные перечисленные правонарушения относятся к КРУПНЫМ правонарушениям, влекущим дисквалификацию на один год или пожизненно, а не к категории серьёзных нарушений. Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"50":{"q":"Какое нарушение НЕ относится к серьёзным нарушениям ПДД Южной Дакоты для целей CDL?","options":["Управление CMV с BAC 0,04+","Слишком близкое следование за другим транспортным средством","Неправильная или беспорядочная смена полосы движения","Управление CMV без наличия CDL"],"explanation":"Управление CMV с BAC 0,04+ является КРУПНЫМ правонарушением (дисквалификация на один год), а не серьёзным нарушением ПДД. Слишком близкое следование, неправильная смена полосы и управление CMV без CDL являются серьёзными нарушениями ПДД. Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"51":{"q":"Каков срок дисквалификации за ПЕРВОЕ нарушение правил пересечения железнодорожного переезда водителем с CDL в Южной Дакоте?","options":["60 дней","30 дней","120 дней","1 год"],"explanation":"Первое нарушение правил пересечения железнодорожного переезда влечёт дисквалификацию на 60 дней в Южной Дакоте. Второе в течение трёх лет — 120 дней, а третье — один год. Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"52":{"q":"Каков срок дисквалификации за ВТОРОЕ нарушение правил пересечения железнодорожного переезда в течение 3 лет для водителя с CDL в Южной Дакоте?","options":["120 дней","60 дней","90 дней","1 год"],"explanation":"Второе нарушение правил пересечения железнодорожного переезда в течение трёх лет влечёт дисквалификацию на 120 дней в Южной Дакоте. Третье в течение трёх лет влечёт дисквалификацию на один год. Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"53":{"q":"Каков срок дисквалификации за ТРЕТЬЕ нарушение правил пересечения железнодорожного переезда в течение 3 лет в Южной Дакоте?","options":["1 год","120 дней","180 дней","60 дней"],"explanation":"Третье нарушение правил пересечения железнодорожного переезда в течение трёхлетнего периода влечёт дисквалификацию CDL на один год в Южной Дакоте. Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"54":{"q":"Какова минимальная дисквалификация за ПЕРВОЕ нарушение предписания об отстранении от эксплуатации (out-of-service order) водителем с CDL в Южной Дакоте (без опасных материалов или пассажиров)?","options":["180 дней","90 дней","60 дней","30 дней"],"explanation":"Первое осуждение за нарушение предписания об отстранении от эксплуатации влечёт дисквалификацию не менее 180 дней (до одного года) в Южной Дакоте. Минимум увеличивается до 3 лет, если были задействованы опасные материалы/пассажиры. Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"55":{"q":"Водитель с CDL в Южной Дакоте совершает ВТОРОЕ нарушение предписания об отстранении от эксплуатации в течение 10 лет (без опасных материалов или пассажиров). Каков срок дисквалификации?","options":["2 года","1 год","180 дней","3 года"],"explanation":"Второе нарушение предписания об отстранении от эксплуатации в отдельных инцидентах в течение 10 лет влечёт дисквалификацию на 2 года в Южной Дакоте. Третье в течение 10 лет — 3 года. Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"56":{"q":"Использование CMV при совершении тяжкого преступления, связанного с производством или распространением контролируемого вещества, влечёт какую дисквалификацию в Южной Дакоте?","options":["Пожизненно без восстановления","1 год","3 года","10 лет с последующим восстановлением"],"explanation":"Использование CMV для совершения тяжкого преступления, связанного с производством, распространением или сбытом контролируемого вещества, влечёт пожизненную дисквалификацию CDL БЕЗ возможности восстановления в Южной Дакоте. Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"57":{"q":"Согласно федеральным правилам, применяемым в Южной Дакоте, сколько осуждений за отправку текстовых сообщений во время управления CMV в течение 3 лет влечёт дисквалификацию на 120 дней?","options":["3 или более","2","5","4"],"explanation":"Два нарушения за отправку текстовых сообщений в течение трёх лет влекут дисквалификацию на 60 дней, а три или более — дисквалификацию на 120 дней для водителей с CDL в Южной Дакоте. Отправка текстовых сообщений во время управления CMV также является серьёзным нарушением ПДД. Источник: South Dakota CDL Manual (49 CFR 392.80 / 383.51)."},"58":{"q":"Для водителя с CDL в Южной Дакоте использование ручного мобильного телефона во время управления CMV лучше всего описывается как какой тип нарушения?","options":["Серьёзное нарушение ПДД","Крупное правонарушение (дисквалификация на 1 год)","Нарушение предписания об отстранении от эксплуатации","Несообщаемое нарушение по оборудованию"],"explanation":"Использование ручного мобильного телефона во время управления CMV является серьёзным нарушением ПДД в Южной Дакоте; два в течение 3 лет влекут дисквалификацию на 60 дней, а три — на 120 дней. Источник: South Dakota CDL Manual (49 CFR 392.82 / 383.51)."},"59":{"q":"В течение скольких дней обладатель CDL в Южной Дакоте должен уведомить своего работодателя после осуждения за нарушение ПДД (кроме парковки) на любом транспортном средстве?","options":["30 дней","10 дней","15 дней","60 дней"],"explanation":"Южная Дакота требует, чтобы обладатель CDL уведомил своего работодателя в течение 30 дней с момента осуждения за любое нарушение ПДД (кроме парковки), в любом штате и на любом транспортном средстве. Источник: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"60":{"q":"Согласно закону «Move Over» Южной Дакоты (обновлён 1 июля 2025 года), на каком расстоянии перед остановившимся транспортным средством с включёнными жёлтыми, оранжевыми или синими предупреждающими огнями водитель должен начать реагировать?","options":["100 feet","200 feet","300 feet","500 feet"],"explanation":"SDCL 32-31-6.1 требует, чтобы водители предпринимали действия не менее чем за 300 feet до транспортного средства. Источник: SDCL 32-31-6.1; закон «Move Over» SDDOT (вступил в силу 1 июля 2025 года)."},"61":{"q":"Что требует закон «Move Over» на многополосной автомагистрали Южной Дакоты при приближении к транспортному средству, остановившемуся на обочине с мигающими предупреждающими огнями?","options":["Полностью остановиться, пока огни не будут выключены","Перестроиться в полосу, наиболее удалённую от транспортного средства, и продолжить движение с осторожностью","Сбросить скорость до 30 mph и оставаться в правой полосе","Подать звуковой сигнал и проехать с разрешённой скоростью"],"explanation":"На дороге с двумя или более полосами в одном направлении SDCL 32-31-6.1 требует, чтобы водитель перестроился в полосу, наиболее удалённую от остановившегося транспортного средства, не менее чем за 300 feet до него и продолжил движение с осторожностью. Источник: SDCL 32-31-6.1; SDDOT."},"62":{"q":"На двухполосной автомагистрали Южной Дакоты, где перестроение невозможно, закон «Move Over» требует от водителя снизить скорость как минимум на сколько ниже разрешённого предела при проезде мимо транспортного средства с предупреждающими огнями на обочине?","options":["Не менее чем на 10 mph ниже разрешённого предела","Не менее чем на 15 mph ниже разрешённого предела","Не менее чем на 20 mph ниже разрешённого предела","Не менее чем на 25 mph ниже разрешённого предела"],"explanation":"На двухполосной дороге SDCL 32-31-6.1 требует снизить скорость как минимум на 20 mph меньше разрешённого предела (или на 5 mph, если предел составляет 20 mph или менее). Источник: SDCL 32-31-6.1; SDDOT."},"63":{"q":"Какие категории остановившихся транспортных средств защищены расширенным законом «Move Over» Южной Дакоты?","options":["Только маркированные транспортные средства правоохранительных органов","Только машины скорой помощи и пожарные машины","Любое транспортное средство на обочине с мигающими жёлтыми, оранжевыми или синими огнями, включая эвакуаторы, ремонтные машины и неисправные транспортные средства","Только транспортные средства с красными и синими аварийными огнями"],"explanation":"Расширение SDCL 32-31-6.1 от 1 июля 2025 года охватывает любое транспортное средство на обочине с мигающими жёлтыми, оранжевыми или синими предупреждающими огнями, включая эвакуаторы, машины дорожного обслуживания и водителей с неисправными автомобилями. Источник: SDCL 32-31-6.1; SDDOT."},"64":{"q":"На двухполосной автомагистрали Южной Дакоты при встрече или обгоне школьного автобуса с мигающими жёлтыми предупреждающими огнями водитель должен снизить скорость не более чем до сколько?","options":["35 mph","25 mph","20 mph","15 mph"],"explanation":"SDCL 32-32-6 требует, чтобы водитель снизил скорость до 15 mph или менее, когда мигают жёлтые предупреждающие огни школьного автобуса. Источник: SDCL 32-32-6."},"65":{"q":"Когда школьный автобус Южной Дакоты остановился на двухполосной дороге с мигающими КРАСНЫМИ сигнальными огнями, приближающийся водитель должен остановиться на расстоянии не менее скольких от автобуса?","options":["10 feet","15 feet","20 feet","30 feet"],"explanation":"SDCL 32-32-6 требует, чтобы водители полностью остановили транспортное средство на расстоянии не менее 15 feet от школьного автобуса и оставались на месте, пока красные огни не перестанут мигать. Источник: SDCL 32-32-6."},"66":{"q":"Согласно закону Южной Дакоты, на каком типе проезжей части водитель, движущийся в ПРОТИВОПОЛОЖНОМ направлении, может продолжить движение, не останавливаясь перед школьным автобусом, остановившимся с мигающими красными огнями?","options":["Любая автомагистраль с нанесённой центральной линией","Автомагистраль, имеющая две или более полос движения в каждом направлении","Любая дорога с разрешённым пределом выше 45 mph","Только автомагистраль между штатами с полностью контролируемым доступом"],"explanation":"SDCL 32-32-6 освобождает водителя, приближающегося с противоположного направления по автомагистрали с двумя или более полосами движения в каждом направлении, от обязанности останавливаться перед школьным автобусом с мигающими красными огнями. Источник: SDCL 32-32-6."},"67":{"q":"На каком расстоянии до остановки оператор школьного автобуса Южной Дакоты должен включить жёлтые предупреждающие огни?","options":["Не менее 100 и не более 300 feet","Не менее 200 и не более 400 feet","Не менее 300 и не более 500 feet","Не менее 500 и не более 700 feet"],"explanation":"SDCL 32-32-5.2 требует, чтобы жёлтые предупреждающие огни были включены не менее чем за 300 feet и не более чем за 500 feet до места, где принимаются или высаживаются ученики. Источник: SDCL 32-32-5.2."},"68":{"q":"На сельских автомагистралях между штатами Южной Дакоты с максимальным разрешённым пределом, каков предел скорости для тягача с прицепом по сравнению с легковым автомобилем?","options":["Грузовики 65 mph; легковые автомобили 80 mph","Грузовики 70 mph; легковые автомобили 75 mph","Грузовики 75 mph; легковые автомобили 80 mph","Грузовики 80 mph; легковые автомобили 80 mph (один и тот же предел)"],"explanation":"Южная Дакота устанавливает 80 mph на большинстве сельских автомагистралей между штатами и применяет один и тот же предел к грузовикам и легковым автомобилям; отдельного более низкого предела скорости для грузовиков нет. Источник: SDCL гл. 32-25; правила скорости SDDOT."},"69":{"q":"В Южной Дакоте более длинное комбинированное транспортное средство (LCV), движущееся по автомагистрали между штатами, не может превышать какую максимальную скорость?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"Административное правило Южной Дакоты 70:03:01:61 ограничивает более длинные комбинированные транспортные средства максимальной скоростью 65 mph на автомагистралях между штатами, даже там, где разрешённый предел выше. Источник: ARSD 70:03:01:61."},"70":{"q":"В Южной Дакоте, когда транспортное средство с табличками опасных грузов приближается к железнодорожному переезду, где требуется остановка, где оно должно остановиться?","options":["В пределах от 5 до 25 feet от ближайшего рельса","В пределах от 15 до 50 feet от ближайшего рельса","В пределах от 25 до 75 feet от ближайшего рельса","В пределах от 50 до 100 feet от ближайшего рельса"],"explanation":"Транспортное средство с табличками должно остановиться в пределах от 15 до 50 feet от ближайшего рельса, а затем посмотреть и прислушаться перед пересечением. Источник: SD CDL Manual; 49 CFR 392.10."},"71":{"q":"При пересечении железнодорожных путей в Южной Дакоте, что водитель автобуса или транспортного средства с табличками НЕ должен делать?","options":["Смотреть и прислушиваться к поездам","Переключать передачи, находясь на путях","Использовать пониженную передачу для поддержания мощности","Убедиться, что есть место для полного освобождения путей"],"explanation":"Водители не должны переключать передачи при пересечении путей, чтобы избежать остановки двигателя на переезде; пересекайте на передаче, которую не нужно менять. Источник: SD CDL Manual; 49 CFR 392.10/392.11."},"72":{"q":"На каком железнодорожном переезде водитель автобуса в Южной Дакоте, как правило, НЕ обязан совершать обязательную остановку?","options":["Переезд, регулируемый сотрудником полиции или регулировщиком, направляющим движение","Многопутный переезд в открытой местности","Переезд без автоматических шлагбаумов","Переезд на крутом спуске"],"explanation":"Обязательная остановка не требуется там, где сотрудник полиции или регулировщик направляет движение, на освобождённом/заброшенном переезде или промышленном тупиковом переезде, либо когда переезд регулируется зелёным светофором. Источник: SD CDL Manual; 49 CFR 392.10."},"73":{"q":"Сколько светоотражающих предупреждающих треугольников должен иметь и устанавливать коммерческий водитель Южной Дакоты при остановке на обочине?","options":["Один треугольник","Два треугольника","Три треугольника","Четыре треугольника"],"explanation":"CMV должно иметь и устанавливать три светоотражающих треугольника (или эквивалентные устройства), размещённые в течение 10 минут после остановки. Источник: SD CDL Manual; 49 CFR 392.22."},"74":{"q":"На двухполосной дороге с двусторонним движением в Южной Дакоте, где следует размещать три предупреждающих треугольника, когда грузовик остановился?","options":["Все три примерно в 100 feet позади транспортного средства","Примерно в 10 feet, 100 feet и 200 feet позади транспортного средства","В пределах 10 feet со стороны движения, и примерно в 100 feet впереди и в 100 feet позади транспортного средства","Примерно в 50 feet впереди, рядом и позади транспортного средства"],"explanation":"На двухполосной дороге с двусторонним движением разместите один треугольник в пределах 10 feet со стороны движения, один примерно в 100 feet позади и один примерно в 100 feet впереди транспортного средства. Источник: SD CDL Manual; 49 CFR 392.22."},"75":{"q":"На разделённой автомагистрали или дороге с односторонним движением в Южной Дакоте, где размещаются три предупреждающих треугольника позади остановившегося грузовика?","options":["В 10, 50 и 100 feet","В 10, 100 и 200 feet","В 25, 100 и 300 feet","В 50, 150 и 250 feet"],"explanation":"На разделённой проезжей части или дороге с односторонним движением разместите треугольники примерно в 10 feet, 100 feet и 200 feet в сторону приближающегося движения позади транспортного средства. Источник: SD CDL Manual; 49 CFR 392.22."},"76":{"q":"Согласно правилу Южной Дакоты о движении по правой стороне, когда водитель должен использовать правую полосу или правую часть проезжей части?","options":["Только на автомагистралях между штатами","Когда движется медленнее обычной скорости потока, за исключением случаев обгона или когда использование правой полосы нецелесообразно","Только между закатом и восходом солнца","Только когда сзади следует грузовик"],"explanation":"SDCL 32-26-1 требует движения по правой половине проезжей части и, для более медленного, чем обычно, движения, держаться правее, за исключением обгона или там, где использование правой полосы нецелесообразно. Источник: SDCL 32-26-1."},"77":{"q":"Какова максимальная допустимая ширина транспортного средства в Южной Дакоте, прежде чем потребуется разрешение на негабаритный груз?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"Допустимый предел ширины в Южной Дакоте без разрешения составляет 8 feet 6 inches (102 inches); всё, что шире, требует разрешения на негабаритный груз. Источник: правила выдачи разрешений на негабаритный груз SDDOT/SD Highway Patrol; SDCL гл. 32-22."},"78":{"q":"В Южной Дакоте, в какие часы держатель разрешения на негабаритный груз (неделимый по ширине), как правило, может передвигаться?","options":["24 часа в сутки, в любой день","Только с понедельника по пятницу, только в светлое время суток","С получаса до восхода солнца до получаса после заката, включая выходные","Только с 9 утра до 4 дня по будням"],"explanation":"Негабаритные грузы могут перемещаться с получаса до восхода солнца до получаса после заката, включая субботу и воскресенье; грузы только с превышением веса могут перемещаться непрерывно. Источник: правила выдачи разрешений на негабаритный груз SDDOT/SD Highway Patrol."},"79":{"q":"Какое ведомство Южной Дакоты выдаёт коммерческие водительские удостоверения?","options":["Department of Public Safety Южной Дакоты, Driver Licensing Program","Department of Transportation Южной Дакоты","Офис шерифа округа, где проживает заявитель","Federal Motor Carrier Safety Administration"],"explanation":"В Южной Дакоте CDL выдаются Department of Public Safety через его Driver Licensing Program (Пирр, Южная Дакота). SD DOT занимается разрешениями и дорогами, а не выдачей водительских удостоверений. Источник: SD DPS Driver Licensing / SD Truck Information (sdtruckinfo.sd.gov), Motor Carrier Handbook гл. 8."},"80":{"q":"Каков минимальный возраст для получения CDL Южной Дакоты для вождения только во внутриштатной торговле (в пределах Южной Дакоты)?","options":["16","18","19","21"],"explanation":"Южная Дакота разрешает получение CDL в возрасте 18 лет для внутриштатной торговли; межштатная (через границы штатов) торговля требует возраста 21 год. Источник: SD Motor Carrier Handbook гл. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"81":{"q":"Каков минимальный возраст для получения CDL Южной Дакоты для межштатной торговли (вождение через границы штатов)?","options":["18","19","20","21"],"explanation":"Вождение в межштатной торговле требует минимального возраста 21 год в Южной Дакоте; водители от 18 до 20 лет ограничены внутриштатными операциями. Источник: SD Motor Carrier Handbook гл. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"82":{"q":"Сколько времени действует коммерческое ученическое разрешение (CLP) Южной Дакоты?","options":["30 days","6 months","1 year","2 years"],"explanation":"CLP Южной Дакоты выдаётся на период в один год для обучения вождению на дорогах общего пользования. Источник: SD Motor Carrier Handbook гл. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"83":{"q":"В Южной Дакоте, сколько времени после выдачи коммерческого ученического разрешения заявитель должен ждать, прежде чем сдавать практический экзамен на CDL?","options":["Период ожидания не требуется","Не менее 7 days","Не менее 14 days","Не менее 30 days"],"explanation":"Существует период ожидания 14 days между датой выдачи CLP и датой, когда может быть сдан практический экзамен. Источник: SD Motor Carrier Handbook гл. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov); отражает федеральное 49 CFR 383.25."},"84":{"q":"Из скольких категорий самосертификации должен выбирать заявитель на CDL Южной Дакоты в отношении типа торговли и медицинских требований?","options":["Двух","Трёх","Четырёх","Пяти"],"explanation":"Существует четыре категории самосертификации: Non-excepted Interstate (NI), Excepted Interstate (EI), Non-excepted Intrastate (NA) и Excepted Intrastate (EA). Источник: SD DPS CDL Medical Certification; 49 CFR 383.71."},"85":{"q":"Водитель Южной Дакоты, который работает через границы штатов и обязан соответствовать федеральным стандартам медицинской пригодности DOT, самосертифицируется как какая категория?","options":["Non-excepted Interstate (NI)","Excepted Interstate (EI)","Non-excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Non-excepted Interstate (NI) означает, что водитель работает в межштатной торговле и должен соответствовать федеральным требованиям к медицинскому сертификату DOT (действующий сертификат медицинского эксперта). Источник: SD DPS CDL Medical Certification; 49 CFR 383.71."},"86":{"q":"Когда заявитель на CDL Южной Дакоты самосертифицируется как Non-excepted Interstate, какой документ должен храниться в файле штата, чтобы оставаться действительным?","options":["Отказ по зрению от окулиста","Действующий сертификат медицинского эксперта DOT","Подписанный аффидевит работодателя","Нотариально заверенный журнал вождения"],"explanation":"Non-excepted водители должны хранить действующий сертификат медицинского эксперта (медицинская карта DOT) в файле Driver Licensing Program; без него CDL понижается. Источник: SD DPS CDL Medical Certification."},"87":{"q":"Кто уполномочен проводить медицинский осмотр для медицинского сертификата DOT держателя CDL Южной Дакоты?","options":["Любой лицензированный врач по выбору водителя","Медицинский эксперт из FMCSA National Registry of Certified Medical Examiners","Только врач, работающий в SD Department of Public Safety","Медсестра в любой клинике неотложной помощи"],"explanation":"Осмотр должен проводиться медицинским специалистом, внесённым в FMCSA National Registry of Certified Medical Examiners. Источник: SD Motor Carrier Handbook гл. 8, CDL Qualifications (sdtruckinfo.sd.gov); National Registry (nationalregistry.fmcsa.dot.gov)."},"88":{"q":"После медосмотра DOT держателя CDL Южной Дакоты, как сертификат медицинского эксперта обычно попадает в Driver Licensing Program штата?","options":["Водитель должен лично доставить его в здание суда","Эксперт подаёт его в электронном виде в Driver Licensing в течение 2 business days через National Registry","Он отправляется по почте только работодателем водителя","Он автоматически действителен без какой-либо подачи"],"explanation":"Сертифицированные медицинские эксперты подают сертификат в электронном виде в Driver Licensing Южной Дакоты в течение 2 business days через FMCSA National Registry; водители также могут подать копию по факсу, электронной почте или почтой. Источник: SD DPS / SD Truck Information (sdtruckinfo.sd.gov)."},"89":{"q":"Каков максимальный период, на который может быть действителен сертификат медицинского эксперта DOT для держателя CDL Южной Дакоты?","options":["6 months","1 year","2 years","5 years"],"explanation":"Сертификат медицинского эксперта действителен до двух лет и может быть выдан на более короткий срок в зависимости от состояния здоровья водителя. Источник: SD Motor Carrier Handbook гл. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 391.43."},"90":{"q":"Какой теоретический экзамен должен сдать КАЖДЫЙ заявитель на CDL Южной Дакоты, независимо от класса транспортного средства или дополнительных категорий?","options":["Экзамен по пневматическим тормозам","Общий теоретический экзамен","Экзамен по опасным материалам","Экзамен по сдвоенным/строенным прицепам"],"explanation":"Общий теоретический экзамен сдают все заявители; остальные экзамены требуются только для конкретных транспортных средств или дополнительных категорий. Источник: SD Motor Carrier Handbook гл. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"91":{"q":"Из каких трёх частей, идущих по порядку, состоит практический экзамен на CDL Южной Дакоты?","options":["Письменный экзамен, проверка зрения и дорожный тест","Предрейсовый осмотр, базовое управление транспортным средством и вождение по дороге","Тест на пневматические тормоза, тест на сцепку и тест на движение задним ходом","Теоретический экзамен, тест на симуляторе и тест на вождение ночью"],"explanation":"Практический экзамен состоит из трёх частей: предрейсовый осмотр (транспортного средства), базовые манёвры управления транспортным средством и дорожный тест вождения. Источник: SD Motor Carrier Handbook гл. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"92":{"q":"Во время части практического экзамена на CDL Южной Дакоты по базовому управлению транспортным средством, что заявителя в основном просят продемонстрировать?","options":["Прочитать весь CDL manual по памяти","Двигать транспортное средство вперёд, назад и поворачивать его в пределах обозначённой конусами зоны","Ремонтировать тормозную систему","Загружать и закреплять опасный груз"],"explanation":"Базовое управление транспортным средством оценивает способность водителя двигать транспортное средство вперёд и назад и поворачивать его в пределах обозначённой конусами или барьерами зоны. Источник: SD Motor Carrier Handbook гл. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"93":{"q":"В части предрейсового осмотра практического экзамена на CDL Южной Дакоты, что должен сделать заявитель?","options":["Проехать через движение на автомагистрали","Определить компоненты транспортного средства, которые он осматривал бы, и объяснить, что он проверяет и почему","Продемонстрировать только параллельную парковку","Сдать отдельный письменный экзамен по hazmat"],"explanation":"Предрейсовый осмотр требует от водителя продемонстрировать способность оценивать безопасность транспортного средства, определяя пункты осмотра и объясняя, что он проверял бы и почему. Источник: SD Motor Carrier Handbook гл. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"94":{"q":"В Южной Дакоте, если заявитель не сдаёт теоретический или практический экзамен на CDL, когда он может пересдать его раньше всего?","options":["Немедленно, в тот же день","Не ранее следующего рабочего дня","После периода ожидания 30 days","После полных 6 months"],"explanation":"Если вы не сдаёте какой-либо из экзаменов, вы не можете пересдавать его раньше следующего рабочего дня; вы можете подождать дольше, если хотите больше изучить или потренироваться. Источник: SD Motor Carrier Handbook гл. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"95":{"q":"В Южной Дакоте, сколько попыток сдачи экзамена покрывает каждый экзаменационный сбор в течение шестимесячного периода?","options":["Одну","Две","Три","Неограниченно"],"explanation":"Заявителям разрешено три попытки сдачи каждого экзамена за каждый уплаченный сбор в течение шестимесячного периода. Точные суммы сборов могут меняться, поэтому следует полагаться на процессуальные правила, а не на денежные суммы. Источник: SD Motor Carrier Handbook гл. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"96":{"q":"Согласно федеральному правилу Entry-Level Driver Training (ELDT), которое применяет Южная Дакота, где впервые подающий заявление на CDL должен пройти необходимое обучение?","options":["Любой онлайн-курс по своему выбору","У поставщика обучения, внесённого в FMCSA Training Provider Registry (TPR)","Курс, предлагаемый только SD DPS","Никакого формального обучения перед экзаменом не требуется"],"explanation":"ELDT (вступило в силу 7 февраля 2022 года) требует, чтобы заявители начального уровня прошли теоретическое и практическое обучение вождению у поставщика из FMCSA Training Provider Registry перед сдачей практического экзамена на CDL (или, для hazmat, теоретического экзамена). Источник: правило FMCSA ELDT (49 CFR Part 380), применяемое SD DPS."},"97":{"q":"К каким заявителям применяется федеральное требование ELDT при получении CDL Южной Дакоты?","options":["Только к водителям старше 65 лет","К заявителям, впервые получающим CDL класса A или B, повышающим класс или впервые получающим дополнительную категорию для школьного автобуса, пассажиров или hazmat","Только к заявителям, переводящимся из других штатов","Только к водителям, продлевающим существующий CDL"],"explanation":"ELDT применяется к тем, кто получает первый CDL класса A или B, повышает класс (например, с B на A) или впервые получает дополнительную категорию для школьного автобуса, пассажиров или опасных материалов; это одноразовое требование, не для обычного продления. Источник: правило FMCSA ELDT (49 CFR Part 380), применяемое SD DPS."},"98":{"q":"Сколько времени действует коммерческое водительское удостоверение Южной Дакоты до того, как его необходимо продлить?","options":["1 year","2 years","4 years","5 years"],"explanation":"CDL Южной Дакоты действителен пять лет и истекает в день рождения держателя; держатели могут продлить его до 180 days до истечения срока, как правило, лично на экзаменационной станции DPS с проверкой зрения. Источник: SD DPS Driver Licensing (руководство по продлению)."}},"tr":{"0":{"q":"South Dakota karayollarında bir aracın ve yükünün izin gerektirmeden sahip olabileceği maksimum yasal genişlik nedir?","options":["96 inç (8 fit)","102 inç (8 fit 6 inç)","108 inç (9 fit)","120 inç (10 fit)"],"explanation":"South Dakota, yükü dahil herhangi bir aracın maksimum genişliğini 102 inç (8 fit 6 inç) ile sınırlar. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Boyut Düzenlemeleri), sdtruckinfo.sd.gov."},"1":{"q":"South Dakota karayollarında bir aracın yükü dahil maksimum yasal yüksekliği nedir?","options":["13 fit 6 inç","13 fit","14 fit","15 fit"],"explanation":"South Dakota, yükü dahil herhangi bir aracın maksimum yüksekliğini 14 fit olarak belirler. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Boyut Düzenlemeleri), sdtruckinfo.sd.gov."},"2":{"q":"South Dakota'da balya halinde saman taşıyan bir araç yasal olarak hangi maksimum yüksekliğe ulaşabilir?","options":["14 fit","14 fit 6 inç","15 fit","16 fit"],"explanation":"Genel yükseklik sınırı 14 fit olmakla birlikte, South Dakota balya halinde saman yükü taşıyan bir aracın 15 fite kadar yüksek olmasına izin verir. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Boyut Düzenlemeleri), sdtruckinfo.sd.gov."},"3":{"q":"South Dakota karayollarında tek bir aks üzerindeki maksimum yasal ağırlık nedir?","options":["18.000 pound","20.000 pound","22.400 pound","34.000 pound"],"explanation":"South Dakota, federal standartla uyumlu olarak tek bir aksı 20.000 pound ile sınırlar. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Ağırlık Düzenlemeleri), sdtruckinfo.sd.gov."},"4":{"q":"South Dakota karayollarında bir tandem aks grubu üzerindeki maksimum yasal ağırlık nedir?","options":["32.000 pound","33.000 pound","34.000 pound","36.000 pound"],"explanation":"South Dakota, federal standartla uyumlu olarak bir tandem aks grubunu 34.000 pound ile sınırlar. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Ağırlık Düzenlemeleri), sdtruckinfo.sd.gov."},"5":{"q":"Özel bir izin olmadan, South Dakota Eyaletlerarası (Interstate) karayollarında izin verilen maksimum brüt araç ağırlığı nedir?","options":["73.280 pound","80.000 pound","90.000 pound","105.500 pound"],"explanation":"South Dakota Eyaletlerarası (Interstate) karayollarındaki maksimum brüt ağırlık, aracın yıllık Over 80,000 Pounds on Interstate iznine sahip olmadığı sürece 80.000 pounddur. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Ağırlık Düzenlemeleri), sdtruckinfo.sd.gov."},"6":{"q":"South Dakota'da çekici-yarı römork kombinasyonunda çalışan bir yarı römorkun maksimum uzunluğu nedir?","options":["48 fit","53 fit","57 fit","60 fit"],"explanation":"South Dakota, çekici-yarı römork kombinasyonunda çalıştırıldığında 53 fite kadar uzunlukta bir yarı römorka izin verir. Kaynak: SDCL 32-22-8.1 (Römorklar ve yarı römorklar için uzunluk sınırlamaları)."},"7":{"q":"South Dakota'da taşınan bir yük, aracın arkasından ne kadar dışarı taşabilir?","options":["3 fitten fazla olamaz","4 fitten fazla olamaz","6 fitten fazla olamaz","8 fitten fazla olamaz"],"explanation":"Bir yük veya geri çekilebilir uzantıları, aracın arka tamponunun, kasasının veya gövdesinin 4 fitten fazla ötesine taşamaz. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Boyut Düzenlemeleri), sdtruckinfo.sd.gov."},"8":{"q":"South Dakota'da bir yük, onu taşıyan aracın önünden ne kadar dışarı taşabilir?","options":["2 fitten fazla olamaz","3 fitten fazla olamaz","4 fitten fazla olamaz","5 fitten fazla olamaz"],"explanation":"Bir yük, aracın ön tamponunun, kasasının veya gövdesinin 3 fitten fazla ötesine taşamaz. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Boyut Düzenlemeleri), sdtruckinfo.sd.gov."},"9":{"q":"South Dakota'da bir direksiyon aksı lastiğinin lastik genişliğinin inç başına ifade edilen taşıyabileceği maksimum ağırlık nedir?","options":["İnç başına 400 pound","İnç başına 500 pound","İnç başına 600 pound","İnç başına 650 pound"],"explanation":"South Dakota, direksiyon aksı ve çift lastikli aks yüklerini lastik genişliğinin inç başına 600 pound ile sınırlar. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Ağırlık Düzenlemeleri), sdtruckinfo.sd.gov."},"10":{"q":"Direksiyon veya çift lastikli akslar dışındaki akslara takılan lastikler için, South Dakota'nın lastik genişliğinin inç başına maksimum lastik ağırlığı nedir?","options":["İnç başına 450 pound","İnç başına 500 pound","İnç başına 550 pound","İnç başına 600 pound"],"explanation":"South Dakota, direksiyon ve çift lastikli akslar dışındaki akslardaki lastikleri lastik genişliğinin inç başına 500 pound ile sınırlar. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Ağırlık Düzenlemeleri), sdtruckinfo.sd.gov."},"11":{"q":"South Dakota, aks grubu ağırlığını sınırlamak için federal Bridge Gross Weight Formula'yı (Köprü Brüt Ağırlık Formülü) kullanır. Formül, maksimum ağırlığı hangi faktörlere göre belirler?","options":["Yalnızca araçtaki toplam aks sayısı","Bir gruptaki en uçtaki akslar arasındaki mesafe ve o gruptaki aks sayısı","Aracın tescilli ağırlığı ve motor beygir gücü","Lastik genişliği ve karayolunun ilan edilen hız sınırı"],"explanation":"South Dakota, L'nin bir gruptaki en uçtaki akslar arasındaki mesafe ve N'nin o gruptaki aks sayısı olduğu federal Köprü Formülü W = 500[(L x N)/(N-1) + 12N + 36]'yı uygular. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Ağırlık Düzenlemeleri), sdtruckinfo.sd.gov."},"12":{"q":"Hasat edilmiş bir ürünü tarladan 50 mil içinde (Eyaletlerarası karayolunda değil) taşıyan bir South Dakota tarım üreticisine, yasal sınırların üzerinde ne kadar ağırlık toleransı tanınır?","options":["Yasal sınırların yüzde 5 üzerinde","Yasal sınırların yüzde 10 üzerinde","Yasal sınırların yüzde 15 üzerinde","Hiçbir tolerans tanınmaz"],"explanation":"South Dakota, Eyaletlerarası sistem hariç olmak üzere, hasat edilmiş bir ürünü hasat edilen tarladan 50 mil içinde taşırken yasal ağırlık sınırlarının yüzde 10 üzerine kadar izin verir. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Ağırlık Düzenlemeleri), sdtruckinfo.sd.gov."},"13":{"q":"South Dakota, belirli çiftlik depolama ve hayvan taşıma işleri için yasal sınırların üzerinde yüzde 5 ağırlık toleransı tanır. Hangi mesafe ve yol kısıtlaması geçerlidir?","options":["Yükleme noktasından 25 mil içinde, Eyaletlerarası karayolları dahil","Yükleme noktasından 50 mil içinde, ancak Eyaletlerarası karayollarında değil","Yükleme noktasından 100 mil içinde, Eyaletlerarası karayolları dahil","Eyaletin herhangi bir yerinde, ancak Eyaletlerarası karayollarında değil"],"explanation":"Çiftlik depolamasına taşıma veya hayvan taşıma için yüzde 5 toleransı, yükleme alanından 50 mil içinde geçerlidir ve Eyaletlerarası sistemde (ve bahar yük kısıtlamaları sırasında hariç) izin verilmez. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Ağırlık Düzenlemeleri), sdtruckinfo.sd.gov."},"14":{"q":"South Dakota'nın Eyaletlerarası olmayan karayollarında, yeterli aksa sahip uygun şekilde yapılandırılmış bir Longer Combination Vehicle (Daha Uzun Kombinasyon Aracı) izinle hangi maksimum brüt ağırlığa ulaşabilir?","options":["80.000 pound","105.500 pound","129.000 pound","164.000 pound"],"explanation":"South Dakota, aks, lastik ve köprü formülü sınırlarının karşılanması koşuluyla, yeterli aksa sahip belirli Longer Combination Vehicle'ların Eyaletlerarası olmayan yollarda 129.000 pounda kadar brüt ağırlığa ulaşmasına izin verir. Kaynak: SDCL 32-22-16/32-22-16.1 ve ARSD 70:03:01:61."},"15":{"q":"Aşırı boyutlu/aşırı ağır araç izinlerine başvurmak ve bunları almak için hangi South Dakota çevrimiçi sistemi kullanılır?","options":["The IRP Clearinghouse","The SDAPS Permitting System","The FMCSA Portal","The UCR National Registry"],"explanation":"South Dakota'da aşırı boyutlu ve aşırı ağır izinler, SDAPS (South Dakota Automated Permitting System) çevrimiçi portalı aracılığıyla alınır. Kaynak: SD Truck Information Permitting sayfaları, sdtruckinfo.sd.gov; SDAPS sdaps.sd.gov'da."},"16":{"q":"South Dakota'da eyalet karayollarındaki bir yük için ne zaman genellikle bir eyalet aşırı boyutlu/aşırı ağır iznine ihtiyaç duyulur?","options":["Yalnızca kargo tehlikeli madde olduğunda","Boyut, ağırlık veya her ikisinin sınırlarını aşan bölünemez bir yük taşırken","26.001 pound GVWR üzerindeki herhangi bir ticari araç için","Yalnızca South Dakota'ya bir eyalet sınırını geçerken"],"explanation":"Yasal boyut, ağırlık veya boyut-ağırlık sınırlamalarını aşan bölünemez bir yük taşıyan bir aracın eyalet karayollarında hareketi için bir izin gereklidir. Kaynak: SD Truck Information Permitting sayfaları, sdtruckinfo.sd.gov."},"17":{"q":"South Dakota'daki bir Over 80,000 Pounds on Interstate izni ek brüt ağırlığa izin verir, ancak araç yine de aşağıdakilerden hangisini AŞMAMALIDIR?","options":["Yasal aks ağırlığını, yasal lastik ağırlığını veya Köprü Formülü ağırlığını","Saatte 55 mil hızı","53 fitlik toplam uzunluğu","Yalnızca gündüz saatlerinde seyahati"],"explanation":"Over 80,000 Pounds on Interstate izni, bir aracın yasal aks ağırlığını, yasal lastik ağırlığını veya Bridge Gross Weight Formula tarafından izin verilen ağırlığı aşmasına izin vermez. Kaynak: SD Truck Information Permitting sayfaları, sdtruckinfo.sd.gov; SDCL 32-22-42."},"18":{"q":"South Dakota'da bir çekici-yarı römork kombinasyonuna uygulanan uzunluk sınırı, toplam uzunluk yerine römork uzunluğuyla ölçülür. Bir yarı römork-römork kombinasyonu için (çekici hariç), maksimum birleşik uzunluk nedir?","options":["65 fit, hiçbir ünite 28,5 fiti aşmamak kaydıyla","75 fit, hiçbir ünite 40 fiti aşmamak kaydıyla","81,5 fit, hiçbir ünite 45 fiti aşmamak kaydıyla","85 fit, hiçbir ünite 48 fiti aşmamak kaydıyla"],"explanation":"Bir yarı römork-yarı römork veya yarı römork-römork kombinasyonu (çekici hariç), hiçbir ünite 45 fiti aşmamak kaydıyla 81 fit 6 inçi aşamaz. Kaynak: SDCL 32-22-8.1."},"19":{"q":"South Dakota'nın tarım makineleri muafiyeti kapsamında, tarım makinesi kullanan bir çiftçi gündüz saatlerinde 102 inçlik genişlik sınırını aşabilir, hangi yollar hariç?","options":["Tüm asfalt eyalet karayolları","Eyaletlerarası (Interstate) karayolları","İlçe çakıl yolları","Şehir sınırları içindeki yollar"],"explanation":"Bir çiftçi tarafından kullanılan tarım makinesinin, standart sınırların geçerli olduğu Eyaletlerarası (Interstate) karayolları hariç, gündüz saatlerinde genişlik sınırı yoktur. Kaynak: SD Commercial and Agricultural Vehicle Handbook, Bölüm 5 (Araç Boyut Düzenlemeleri), sdtruckinfo.sd.gov."},"20":{"q":"South Dakota'da, EYALETLERARASI (interstate) ticarette ticari bir motorlu aracı kullanmak için CDL almanın asgari yaşı nedir?","options":["18 yaş","19 yaş","21 yaş","25 yaş"],"explanation":"South Dakota federal kuralı izler: bir sürücünün eyaletlerarası ticaret için CDL alabilmesi için en az 21 yaşında olması gerekir. 18-20 yaş arası sürücülere yalnızca eyalet içi (intrastate) operasyon için CDL verilebilir. Kaynak: SD Motor Carrier Handbook, Böl. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 391.11."},"21":{"q":"18 ila 20 yaşları arasındaki bir South Dakota başvuru sahibine CDL verilebilir, ancak bu hangi tür operasyonla sınırlıdır?","options":["Yalnızca eyalet içi (intrastate) ticaret (South Dakota içinde)","Yalnızca eyaletlerarası (interstate) ticaret","Yalnızca çiftlik araçları","Yalnızca gündüz sürüşü"],"explanation":"South Dakota, 18-20 yaş arası başvuru sahiplerinin yalnızca eyalet içi (intrastate) ticaret için geçerli (South Dakota içinde sürüş) bir CDL almasına izin verir. Eyaletlerarası operasyon 21 yaş gerektirir. Kaynak: SD Motor Carrier Handbook, Böl. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"22":{"q":"South Dakota'nın CDL sınıflandırmalarında, hangi kombinasyon bir CLASS A (A Sınıfı) lisansını tanımlar?","options":["GVWR'si 26.000 poundu aşan herhangi bir tek araç","Çekilen ünitenin GVWR'sinin 10.000 poundu aştığı, GCWR'si 26.000 poundu aşan herhangi bir araç kombinasyonu","Tehlikeli maddeler için plakartlanmış herhangi bir araç","16 veya daha fazla yolcu taşımak üzere tasarlanmış herhangi bir araç"],"explanation":"South Dakota, Class A'yı, çekilen aracın GVWR'sinin 10.000 lb'yi aşması koşuluyla, Gross Combination Weight Rating (GCWR - Brüt Kombinasyon Ağırlık Derecesi) 26.000 lb'yi aşan herhangi bir araç kombinasyonu olarak tanımlar. Kaynak: SD Motor Carrier Handbook, Böl. 8, CDL Classifications (sdtruckinfo.sd.gov)."},"23":{"q":"South Dakota bir CLASS B (B Sınıfı) ticari sürücü lisansını nasıl tanımlar?","options":["10.000 poundu aşan bir üniteyi çeken, GCWR'si 26.000 poundu aşan bir kombinasyon","GVWR'si 26.000 poundu aşan tek bir araç veya 10.000 poundu aşmayan bir üniteyi çeken böyle bir araç","Tehlikeli atık taşıyan herhangi bir araç","GVWR'si 10.000 poundun altında olan herhangi bir araç"],"explanation":"South Dakota, Class B'yi, GVWR'si 26.000 lb'yi aşan herhangi bir tek araç veya GVWR'si 10.000 lb'yi aşmayan bir aracı çeken böyle herhangi bir araç olarak tanımlar. Kaynak: SD Motor Carrier Handbook, Böl. 8, CDL Classifications (sdtruckinfo.sd.gov)."},"24":{"q":"South Dakota'da, bir CLASS C (C Sınıfı) CDL, Class A veya B'yi karşılamayan ancak ya tehlikeli maddeler için plakartlanmış olan ya da kaç kişiyi taşımak üzere tasarlanmış bir araca uygulanır?","options":["Sürücü dahil 8 veya daha fazla","Sürücü dahil 12 veya daha fazla","Sürücü dahil 16 veya daha fazla","Sürücü dahil 24 veya daha fazla"],"explanation":"South Dakota, Class C'yi, Class A veya B'yi karşılamayan ve ya tehlikeli maddeler için plakartlanması gereken ya da sürücü dahil 16 veya daha fazla yolcu taşımak üzere tasarlanmış tek bir araç veya kombinasyon olarak tanımlar. Kaynak: SD Motor Carrier Handbook, Böl. 8, CDL Classifications (sdtruckinfo.sd.gov)."},"25":{"q":"South Dakota, plakartlanmış TEHLİKELİ MADDELER taşıyan (tankta değil) bir sürücü için CDL'ye hangi onay kodunu (endorsement) yerleştirir?","options":["N","T","H","P"],"explanation":"South Dakota, plakartlanmış tehlikeli maddelerin taşınması için H onayını kullanır. N onayı tank araçları, T çiftli/üçlü için ve P yolcular içindir. Kaynak: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Böl. 8 (sdtruckinfo.sd.gov)."},"26":{"q":"South Dakota bir CDL'ye HazMat (H) onayı eklemeden önce, başvuru sahibinin bilgi testini geçmenin yanı sıra hangi federal adımı tamamlaması gerekir?","options":["Parmak izi alma dahil bir TSA güvenlik tehdit değerlendirmesi","100 saatlik bir çıraklık","Bir göz ameliyatı onayı","Bir tank aracında ayrı bir yol testi"],"explanation":"South Dakota, başvuru sahibi parmak izi alma ve geçmiş kontrolü gerektiren federal TSA Hazardous Materials Endorsement Threat Assessment Program'ı geçene kadar, yazılı bilgi testine ek olarak HazMat onayını veremez. Kaynak: TSA HME programı; SD DPS CDL Endorsements; 49 CFR 1572."},"27":{"q":"South Dakota'nın TANKER (N) onayı, 119 galon veya daha fazla kapasiteye sahip kalıcı bir tankta sıvı veya gaz taşıyan araçlar için ya da toplam derecelendirilmiş kapasitesi en az kaç galon olan taşınabilir tanklar için gereklidir?","options":["500 galon","750 galon","1.000 galon","1.500 galon"],"explanation":"South Dakota, 119 galon (450 litre) veya daha fazla kapasiteye sahip kalıcı tanklar ya da toplam derecelendirilmiş kapasitesi 1.000 galon veya daha fazla olan taşınabilir tanklar için N (tank) onayını gerektirir. Kaynak: SD CDL Manual / SD DPS CDL Endorsements; FMCSA tank aracı tanımı, 49 CFR 383.5."},"28":{"q":"Bir TANK ARACINDA tehlikeli maddeler taşıyan bir South Dakota sürücüsü hangi birleşik onayı taşımalıdır?","options":["T","X","S","P"],"explanation":"South Dakota, bir tank aracında tehlikeli maddeler taşıyan sürücüler için tank (N) ve tehlikeli maddeler (H) kombinasyonunu temsil etmek üzere X onayını kullanır. Kaynak: SD Motor Carrier Handbook, Böl. 8, CDL Classifications & Endorsements (sdtruckinfo.sd.gov)."},"29":{"q":"South Dakota, ÇİFTLİ veya ÜÇLÜ römork çeken bir sürücü için hangi onayı gerektirir?","options":["P","N","T","H"],"explanation":"South Dakota, çiftli ve üçlü römorklar için T onayını gerektirir; başvuru sahibinin birden fazla römork çekmenin sorunları hakkında özel bir bilgi sınavını geçmesi gerekir. T için ayrı bir beceri testi yoktur. Kaynak: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Böl. 8."},"30":{"q":"South Dakota YOLCU (P) onayını almak için, bir sürücünün özel bir bilgi testini geçmesinin yanı sıra başka ne yapması gerekir?","options":["Bir yolcu aracında beceri testi","50 saatlik bir araçta gözlemci olarak bulunma","Bir TSA geçmiş kontrolü","Bir otobüste ayrı bir görme testi"],"explanation":"South Dakota, P onayını (sürücü dahil 16 veya daha fazla yolcu için tasarlanmış araçlar) almak isteyen sürücülerin hem özel bir bilgi sınavını hem de bir yolcu aracında yapılan bir beceri testini geçmesini gerektirir. Kaynak: SD DPS CDL Endorsements; SD CDL Manual."},"31":{"q":"South Dakota'da, bir sürücüye OKUL OTOBÜSÜ (S) onayı verilmeden önce, CDL'nin halihazırda hangi diğer onayı taşıması gerekir?","options":["H (HazMat) onayı","T (çiftli/üçlü) onayı","P (yolcu) onayı","N (tank) onayı"],"explanation":"South Dakota, okul otobüsü (S) onayı için ön koşul olarak yolcu (P) onayını gerektirir; S başvuru sahibi ayrıca bir okul otobüsü bilgi testini ve bir beceri testini geçmelidir. Kaynak: SD DPS CDL Endorsements; SD CDL Manual."},"32":{"q":"Bir South Dakota Commercial Learner's Permit (CLP - Ticari Öğrenci Belgesi) ne kadar süreyle geçerlidir?","options":["60 gün","6 ay","1 yıl","5 yıl"],"explanation":"Bir South Dakota CLP, direksiyon başında eğitim için bir yıllık süre için verilir. Kaynak: SD Motor Carrier Handbook, Böl. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 383.25."},"33":{"q":"Bir Commercial Learner's Permit aldıktan sonra, bir South Dakota başvuru sahibi CDL beceri testine girmeye hak kazanmadan önce ne kadar beklemelidir?","options":["En az 7 gün","En az 14 gün","En az 30 gün","En az 90 gün"],"explanation":"South Dakota, bir CLP'nin sahibinin CDL beceri (yol) testine girmeye hak kazanmadan önce en az 14 gün boyunca tutulması gerektiği federal kuralı uygular. Kaynak: SD DPS Driver Licensing; 49 CFR 383.25(e)."},"34":{"q":"Bir South Dakota CLP ile sürüş yaparken, belge sahibine uygun sınıftan geçerli bir CDL'ye sahip olan ve nerede oturan bir kişi eşlik etmelidir?","options":["Sürücünün yanındaki ön koltukta","Kabinin herhangi bir yerinde","Ayrı bir refakat aracında","Yatak bölmesinde"],"explanation":"Bir South Dakota CLP sahibi, yalnızca sürücünün yanındaki ön koltukta oturan, uygun sınıfa/onaylara sahip geçerli bir CDL'ye sahip bir kişi eşlik ettiğinde bir CMV kullanabilir. Kaynak: SD Motor Carrier Handbook, Böl. 8, CDL Qualifications; 49 CFR 383.25(a)."},"35":{"q":"Bir South Dakota CDL başvuru sahibinin uygunluğunu belirlemek için bir sürücü sınav istasyonunda hangi belge setini sunması gerekir?","options":["Yalnızca bir Sosyal Güvenlik kartı","Kimlik/yasal varlık kanıtı, Sosyal Güvenlik numarası ve South Dakota ikamet kanıtı","Bir pasaport ve bir kredi kartı","Bir lise diploması ve bir araç tapusu"],"explanation":"South Dakota, kimlik ve yasal varlık (doğum tarihi) kanıtı, bir Sosyal Güvenlik numarası ve South Dakota ikametini kanıtlayan iki belge gerektirir; belgeler fotokopi değil, orijinal olmalıdır. Kaynak: SD DPS Required Driver's Licensing Documents (dps.sd.gov)."},"36":{"q":"South Dakota'da CLP'sini 7 Şubat 2022'den sonra alan çoğu CDL başvuru sahibinin, nerede listelenen bir sağlayıcıdan Entry-Level Driver Training (ELDT - Giriş Seviyesi Sürücü Eğitimi) tamamlaması gerekir?","options":["Herhangi bir özel nakliye şirketinin web sitesi","The FMCSA Training Provider Registry (TPR)","South Dakota Secretary of State","Yerel ilçe şerif ofisi"],"explanation":"South Dakota'da benimsenen federal ELDT kuralları, 7 Şubat 2022 tarihinde veya sonrasında bir CLP alan başvuru sahipleri için, beceri testine girmeden önce FMCSA Training Provider Registry'de (tpr.fmcsa.dot.gov) yer alan bir kuruluştan teori ve direksiyon başında eğitim gerektirir. Kaynak: FMCSA ELDT; SD DPS CDL bilgileri."},"37":{"q":"Eyaletlerarası ticarette çalışan ve federal DOT tıbbi kart gerekliliğini karşılaması GEREKEN bir South Dakota sürücüsüne hangi tıbbi öz-sertifikasyon kategorisi uygulanır?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"explanation":"Non-Excepted Interstate (NI), federal DOT fizik muayene/tıbbi muayene sertifikası gerekliliğini karşılaması gereken eyaletlerarası ticarette çalışan sürücüleri kapsar. EI muafiyetli eyaletlerarası, NA/EA ise eyalet içi kategorilerdir. Kaynak: 49 CFR 383.71; SD DPS Driver Licensing öz-sertifikasyon."},"38":{"q":"Non-Excepted Interstate olarak öz-sertifikasyon yapan bir South Dakota CDL veya CLP başvuru sahibi, nerede listelenen bir muayene uzmanından tıbbi sertifika sunmalıdır?","options":["The FMCSA National Registry of Certified Medical Examiners","Herhangi bir randevusuz acil bakım kliniği","South Dakota Department of Health listesi","Sürücünün seçeceği bir hastane"],"explanation":"South Dakota, eyaletlerarası (muafiyetsiz) sürücülerin ve okul otobüsü operatörlerinin FMCSA National Registry of Certified Medical Examiners'da listelenen bir tıp uzmanından sertifika almasını gerektirir ve sertifikanın Driver Licensing'de dosyada bulunması gerekir. Kaynak: SD Motor Carrier Handbook, Böl. 8, CDL Qualifications; 49 CFR 391.41."},"39":{"q":"Bir South Dakota Commercial Driver License (CDL) yenilenmesi gerekmeden önce kaç yıl için verilir?","options":["3 yıl","4 yıl","5 yıl","8 yıl"],"explanation":"South Dakota CDL'leri 5 yıllık bir süre için verir, bu sürenin ardından lisansın yenilenmesi gerekir. (Ticari olmayan SD lisansları daha uzun süreler için verilir, ancak CDL'ler 5 yıllıktır.) Kaynak: SD DPS Driver Licensing ücretleri/bilgileri (dps.sd.gov)."},"40":{"q":"South Dakota'da, bir kişinin yasal olarak ticari bir motorlu aracı (CMV) kullanabileceği maksimum kan alkol konsantrasyonu (BAC) nedir?","options":["yüzde 0,04","yüzde 0,08","yüzde 0,02","yüzde 0,10"],"explanation":"South Dakota federal CMV standardını izler: bir CMV'yi yüzde 0,04 veya daha fazla BAC ile kullanmak yasadışıdır; bu, ticari olmayan sürücüler için olan 0,08 sınırının yarısıdır. Kaynak: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Böl. 8 (49 CFR 383.51)."},"41":{"q":"Bir South Dakota CDL sürücüsü, bir CMV'yi yüzde 0,04 BAC'nin altında tespit edilebilir miktarda alkolle kullanırken yakalanır. Anlık sonuç nedir?","options":["24 saat hizmet dışı bırakılma","Bir yıllık CDL diskalifiyesi","60 günlük CDL diskalifiyesi","CDL'nin kalıcı kaybı"],"explanation":"South Dakota'da, yüzde 0,04'ün altında herhangi bir tespit edilebilir alkole sahip bir CMV sürücüsü diskalifiye edilmek yerine 24 saat hizmet dışı bırakılır. 0,04 veya daha fazla BAC bir yıllık diskalifiyeyi tetikler. Kaynak: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Böl. 8."},"42":{"q":"South Dakota'nın zımni rıza (implied consent) yasası kapsamında, bir sürücü kamuya açık bir karayolunda herhangi bir aracı kullanarak neyi kabul etmiş olur?","options":["Alkol veya uyuşturucu için kimyasal teste tabi olmayı","Bir tıbbi muayene uzmanının sertifikasını taşımayı","Bir lisans duruşması hakkından feragat etmeyi","Rastgele işveren uyuşturucu taramasını"],"explanation":"South Dakota'nın zımni rıza yasası, kamuya açık bir karayolunda sürüş yapan herkesin alkol veya uyuşturucu için bir kimyasal teste rıza göstermiş olduğu anlamına gelir. Hiç alkol alınmamış olsa bile reddetmenin kendine ait cezaları vardır. Kaynak: South Dakota CDL Manual; SDCL 32-23-10 (zımni rıza)."},"43":{"q":"Plakartlanmış tehlikeli maddeleri içermeyen İLK büyük suç için (bir CMV'de 0,04+ BAC gibi), bir South Dakota CDL sahibi ne kadar süreyle diskalifiye edilir?","options":["1 yıl","60 gün","3 yıl","Ömür boyu"],"explanation":"South Dakota'da ilk büyük suç, asgari bir yıllık CDL diskalifiyesiyle sonuçlanır. Suç, plakartlanmış tehlikeli maddeler taşınırken işlenmişse süre üç yıla çıkar. Kaynak: South Dakota CDL Manual (49 CFR 383.51)."},"44":{"q":"Plakartlanması gereken tehlikeli maddeler taşınırken işlenen İLK büyük suç için bir South Dakota CDL sürücüsü ne kadar süreyle diskalifiye edilir?","options":["3 yıl","1 yıl","120 gün","Ömür boyu"],"explanation":"South Dakota'da ilk büyük suç için standart bir yıllık diskalifiye, ihlal plakartlanmış tehlikeli maddeler taşıyan bir CMV kullanılırken meydana geldiğinde üç yıla çıkarılır. Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8 (49 CFR 383.51)."},"45":{"q":"Ayrı bir olaydan kaynaklanan İKİNCİ bir büyük suç için South Dakota'daki diskalifiye süresi nedir?","options":["Ömür boyu","10 yıl","3 yıl","1 yıl"],"explanation":"Ayrı bir olaydan kaynaklanan ikinci bir büyük suç (herhangi bir araçta ikinci bir DUI, test reddi veya olay yerinden ayrılma gibi), South Dakota'da ömür boyu CDL diskalifiyesiyle sonuçlanır, ancak bazı durumlarda 10 yıl sonra yeniden verilme mümkün olabilir. Kaynak: South Dakota CDL Manual (49 CFR 383.51)."},"46":{"q":"Bir South Dakota CDL sürücüsü, alkol için kimyasal bir teste tabi olmayı reddeder. Asgari diskalifiye süresi nedir?","options":["En az 1 yıl","60 gün","90 gün","30 gün"],"explanation":"Gerekli alkol/uyuşturucu testine tabi olmayı reddetmek South Dakota'da büyük bir suç olarak değerlendirilir ve 0,04+ BAC ile aynı şekilde en az bir yıllık diskalifiyeyle sonuçlanır. Bir sürücü, içmiyor olsa bile CDL'sini kaybedebilir. Kaynak: South Dakota CDL Manual; SDCL zımni rıza hükümleri."},"47":{"q":"Bir South Dakota CDL sürücüsü, 3 yıllık bir süre içinde İKİ ciddi trafik ihlalinden mahkum edildiğinde ne kadar süreyle diskalifiye edilir?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"Üç yıl içinde ayrı olaylarda iki ciddi trafik ihlali, South Dakota'da 60 günlük bir diskalifiyeyle sonuçlanır. Üç yıl içinde üçüncüsü 120 gün ekler. Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8 (49 CFR 383.51)."},"48":{"q":"Bir South Dakota CDL sürücüsü, 3 yıllık bir süre içinde ÜÇ ciddi trafik ihlalinden mahkum edildiğinde ne kadar süreyle diskalifiye edilir?","options":["120 gün","60 gün","90 gün","1 yıl"],"explanation":"Üç yıl içinde ayrı olaylarda üçüncü bir ciddi trafik ihlali, South Dakota'da 120 günlük bir diskalifiyeyle sonuçlanır (ikincisi için olan 60 güne ek olarak). Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8."},"49":{"q":"Aşağıdakilerden hangisi bir South Dakota CDL sahibi için CİDDİ bir trafik ihlali olarak sınıflandırılır?","options":["İlan edilen sınırın 15 mph veya daha fazla üzerinde hız yapmak","0,04 veya daha fazla BAC ile araç kullanmak","Bir kimyasal testi reddetmek","Bir kaza yerinden ayrılmak"],"explanation":"South Dakota'da, sınırın 15 mph veya daha fazla üzerinde hız yapmak ciddi bir trafik ihlalidir. Listelenen diğer suçlar, ciddi ihlal kategorisi değil, bir yıllık veya ömür boyu diskalifiye taşıyan BÜYÜK suçlardır. Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8."},"50":{"q":"Hangi ihlal, CDL amaçları için South Dakota'nın ciddi trafik ihlalleri arasında SAYILMAZ?","options":["Bir CMV'yi 0,04+ BAC ile kullanmak","Başka bir aracı çok yakından takip etmek","Hatalı veya düzensiz şerit değiştirme","CDL'ye sahip olmadan bir CMV kullanmak"],"explanation":"Bir CMV'yi 0,04+ BAC ile kullanmak BÜYÜK bir suçtur (bir yıllık diskalifiye), ciddi bir trafik ihlali değil. Çok yakından takip etmek, hatalı şerit değiştirmeler ve CDL olmadan bir CMV kullanmak ciddi trafik ihlalleridir. Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8."},"51":{"q":"Bir South Dakota CDL sürücüsü tarafından İLK demiryolu-karayolu hemzemin geçit ihlali için diskalifiye süresi nedir?","options":["60 gün","30 gün","120 gün","1 yıl"],"explanation":"İlk demiryolu-karayolu hemzemin geçit ihlali, South Dakota'da 60 günlük bir diskalifiyeyle sonuçlanır. Üç yıl içinde ikincisi 120 gün ve üçüncüsü bir yıldır. Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8 (49 CFR 383.51)."},"52":{"q":"Bir South Dakota CDL sürücüsü için 3 yıl içinde İKİNCİ demiryolu-karayolu hemzemin geçit ihlali için diskalifiye süresi nedir?","options":["120 gün","60 gün","90 gün","1 yıl"],"explanation":"Üç yıl içinde ikinci bir demiryolu hemzemin geçit ihlali, South Dakota'da 120 günlük bir diskalifiyeyle sonuçlanır. Üç yıl içinde üçüncüsü bir yıllık diskalifiyeyle sonuçlanır. Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8."},"53":{"q":"South Dakota'da 3 yıl içinde ÜÇÜNCÜ demiryolu-karayolu hemzemin geçit ihlali için diskalifiye süresi nedir?","options":["1 yıl","120 gün","180 gün","60 gün"],"explanation":"Üç yıllık bir süre içinde üçüncü bir demiryolu hemzemin geçit ihlali, South Dakota'da bir yıllık CDL diskalifiyesiyle sonuçlanır. Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8 (49 CFR 383.51)."},"54":{"q":"Bir South Dakota CDL sürücüsü tarafından bir hizmet dışı bırakma emrinin İLK ihlali için asgari diskalifiye nedir (hazmat veya yolcu yok)?","options":["180 gün","90 gün","60 gün","30 gün"],"explanation":"Bir hizmet dışı bırakma emrini ihlal etmekten ilk mahkumiyet, South Dakota'da en az 180 günlük (bir yıla kadar) bir diskalifiyeyle sonuçlanır. Hazmat/yolcu söz konusuysa asgari süre 3 yıla çıkar. Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8."},"55":{"q":"Bir South Dakota CDL sürücüsü, 10 yıl içinde İKİNCİ bir hizmet dışı bırakma emri ihlali işler (hazmat veya yolcu yok). Diskalifiye süresi nedir?","options":["2 yıl","1 yıl","180 gün","3 yıl"],"explanation":"10 yıl içinde ayrı olaylarda ikinci bir hizmet dışı bırakma emri ihlali, South Dakota'da 2 yıllık bir diskalifiyeyle sonuçlanır. 10 yıl içinde üçüncüsü 3 yıldır. Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8 (49 CFR 383.51)."},"56":{"q":"Bir CMV'yi kontrollü bir maddenin imalatı veya dağıtımını içeren bir suç işlemek için kullanmak South Dakota'da hangi diskalifiyeyle sonuçlanır?","options":["Yeniden verilme olmaksızın ömür boyu","1 yıl","3 yıl","10 yıl ardından yeniden verilme"],"explanation":"Bir kontrollü maddenin imalatı, dağıtımı veya temini içeren bir suç işlemek için bir CMV kullanmak, South Dakota'da yeniden verilme olasılığı OLMAKSIZIN ömür boyu CDL diskalifiyesiyle sonuçlanır. Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8 (49 CFR 383.51)."},"57":{"q":"South Dakota'da uygulanan federal kurallar kapsamında, bir CMV kullanırken 3 yıl içinde kaç mesajlaşma mahkumiyeti 120 günlük bir diskalifiyeyi tetikler?","options":["3 veya daha fazla","2","5","4"],"explanation":"Üç yıl içinde iki mesajlaşma ihlali 60 günlük bir diskalifiyeye ve üç veya daha fazlası South Dakota CDL sürücüleri için 120 günlük bir diskalifiyeye neden olur. Bir CMV kullanırken mesajlaşmak aynı zamanda ciddi bir trafik ihlalidir. Kaynak: South Dakota CDL Manual (49 CFR 392.80 / 383.51)."},"58":{"q":"Bir South Dakota CDL sürücüsü için, bir CMV kullanırken elde tutulan bir cep telefonu kullanmak en iyi şekilde hangi tür ihlal olarak tanımlanır?","options":["Ciddi bir trafik ihlali","Büyük bir suç (1 yıllık diskalifiye)","Bir hizmet dışı bırakma emri ihlali","Bildirilmeyen bir ekipman ihlali"],"explanation":"Bir CMV kullanırken elde tutulan bir cep telefonu kullanmak South Dakota'da ciddi bir trafik ihlalidir; 3 yıl içinde iki tanesi 60 günlük bir diskalifiyeye ve üç tanesi 120 güne neden olur. Kaynak: South Dakota CDL Manual (49 CFR 392.82 / 383.51)."},"59":{"q":"Bir South Dakota CDL sahibi, herhangi bir araçta bir trafik ihlalinden (park etme dışında) mahkum edildikten sonra işverenini kaç gün içinde bilgilendirmelidir?","options":["30 gün","10 gün","15 gün","60 gün"],"explanation":"South Dakota, bir CDL sahibinin herhangi bir eyalette ve herhangi bir araçta herhangi bir trafik ihlalinden (park etme hariç) mahkumiyetinden itibaren 30 gün içinde işverenini bilgilendirmesini gerektirir. Kaynak: South Dakota CDL Manual / Motor Carrier Handbook Böl. 8."},"60":{"q":"South Dakota'nın Move Over (Şerit Değiştir) yasası uyarınca (1 Temmuz 2025'te güncellendi), sürücü; sarı, amber veya mavi uyarı ışıklarını yakan duran bir araca ne kadar mesafe kala tepki vermeye başlamalıdır?","options":["100 feet","200 feet","300 feet","500 feet"],"explanation":"SDCL 32-31-6.1, sürücülerin araca en az 300 feet kala harekete geçmesini gerektirir. Kaynak: SDCL 32-31-6.1; SDDOT Move Over yasası (yür. 1 Temmuz 2025)."},"61":{"q":"South Dakota'da çok şeritli bir karayolunda, uyarı ışıkları yanıp sönen ve banket üzerinde duran bir araca yaklaşırken Move Over yasası neyi gerektirir?","options":["Işıklar sönene kadar tamamen durmak","Araçtan en uzak şeride geçmek ve dikkatle ilerlemek","30 mph hıza düşmek ve sağ şeritte kalmak","Korna çalmak ve belirlenen hız sınırında geçmek"],"explanation":"Aynı yönde iki veya daha fazla şeride sahip bir yolda, SDCL 32-31-6.1 sürücünün araca en az 300 feet kala duran araçtan en uzak şeride geçmesini ve dikkatle ilerlemesini gerektirir. Kaynak: SDCL 32-31-6.1; SDDOT."},"62":{"q":"South Dakota'da şerit değiştirmenin mümkün olmadığı iki şeritli bir karayolunda, Move Over yasası; banket üzerinde uyarı ışıkları yanan bir aracın yanından geçerken sürücünün belirlenen hız sınırının en az ne kadar altına yavaşlamasını gerektirir?","options":["Belirlenen sınırın en az 10 mph altına","Belirlenen sınırın en az 15 mph altına","Belirlenen sınırın en az 20 mph altına","Belirlenen sınırın en az 25 mph altına"],"explanation":"İki şeritli bir yolda, SDCL 32-31-6.1 belirlenen sınırdan en az 20 mph daha düşük bir hıza yavaşlamayı gerektirir (sınır 20 mph veya daha az ise 5 mph). Kaynak: SDCL 32-31-6.1; SDDOT."},"63":{"q":"South Dakota'nın genişletilmiş Move Over yasası tarafından hangi kategorilerdeki duran araçlar korunmaktadır?","options":["Yalnızca işaretli kolluk kuvveti araçları","Yalnızca ambulanslar ve itfaiye araçları","Banket üzerinde yanıp sönen sarı, amber veya mavi ışık gösteren herhangi bir araç; çekiciler, bakım araçları ve arızalı araçlar dahil","Yalnızca kırmızı ve mavi acil durum ışıkları gösteren araçlar"],"explanation":"SDCL 32-31-6.1'in 1 Temmuz 2025 tarihli genişletmesi, banket üzerinde yanıp sönen sarı, amber veya mavi uyarı ışıkları gösteren herhangi bir aracı kapsar; çekiciler, karayolu bakım araçları ve arızalı sürücüler dahil. Kaynak: SDCL 32-31-6.1; SDDOT."},"64":{"q":"South Dakota'da iki şeritli bir karayolunda, amber uyarı ışıkları yanıp sönen bir okul otobüsüyle karşılaşırken veya onu geçerken bir sürücü hızını en fazla ne kadara düşürmelidir?","options":["35 mph","25 mph","20 mph","15 mph"],"explanation":"SDCL 32-32-6, bir okul otobüsünün amber ikaz ışıkları yanıp sönerken sürücünün hızını 15 mph veya daha azına düşürmesini gerektirir. Kaynak: SDCL 32-32-6."},"65":{"q":"South Dakota'da bir okul otobüsü iki şeritli bir yolda KIRMIZI sinyal ışıkları yanıp sönerek durduğunda, yaklaşan bir sürücü otobüse en az ne kadar mesafede durmalıdır?","options":["10 feet","15 feet","20 feet","30 feet"],"explanation":"SDCL 32-32-6, sürücülerin aracı okul otobüsünden en az 15 feet mesafede tamamen durdurmasını ve kırmızı ışıklar yanıp sönmeyi bırakana kadar durmuş halde kalmasını gerektirir. Kaynak: SDCL 32-32-6."},"66":{"q":"South Dakota yasalarına göre, KARŞI yönde seyreden bir sürücü, kırmızı ışıkları yanıp sönerek durmuş bir okul otobüsü için durmadan hangi tür yolda ilerleyebilir?","options":["Boyalı orta çizgisi olan herhangi bir karayolu","Her yönde iki veya daha fazla seyir şeridi sağlayan bir karayolu","Belirlenen sınırı 45 mph üzerinde olan herhangi bir yol","Yalnızca tamamen erişimi kontrollü bir eyaletlerarası otoyol"],"explanation":"SDCL 32-32-6, her yönde iki veya daha fazla seyir şeridi olan bir karayolunda karşı yönden yaklaşan bir sürücüyü, kırmızı ışıkları yanıp sönen bir okul otobüsü için durma yükümlülüğünden muaf tutar. Kaynak: SDCL 32-32-6."},"67":{"q":"South Dakota'da bir okul otobüsü operatörü, bir durağın ne kadar önünde amber ikaz ışıklarını yakmalıdır?","options":["100 feet'ten az, 300 feet'ten fazla olmamak üzere","200 feet'ten az, 400 feet'ten fazla olmamak üzere","300 feet'ten az, 500 feet'ten fazla olmamak üzere","500 feet'ten az, 700 feet'ten fazla olmamak üzere"],"explanation":"SDCL 32-32-5.2, amber ikaz ışıklarının öğrencilerin alındığı veya bırakıldığı noktanın 300 feet'ten az, 500 feet'ten fazla olmamak üzere önünde yanmasını gerektirir. Kaynak: SDCL 32-32-5.2."},"68":{"q":"South Dakota'nın azami sınıra ayarlanmış kırsal eyaletlerarası otoyollarında, bir çekici-römork için hız sınırı bir binek otomobile kıyasla nedir?","options":["Kamyonlar 65 mph; otomobiller 80 mph","Kamyonlar 70 mph; otomobiller 75 mph","Kamyonlar 75 mph; otomobiller 80 mph","Kamyonlar 80 mph; otomobiller 80 mph (aynı sınır)"],"explanation":"South Dakota, çoğu kırsal eyaletlerarası otoyolda 80 mph belirler ve kamyonlara da otomobillere de aynı sınırı uygular; kamyonlar için ayrı bir daha düşük hız sınırı yoktur. Kaynak: SDCL böl. 32-25; SDDOT hız düzenlemeleri."},"69":{"q":"South Dakota'da, eyaletlerarası otoyolda çalışan bir Daha Uzun Kombinasyon Aracı (LCV) hangi azami hızı aşamaz?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"South Dakota İdari Kural 70:03:01:61, Daha Uzun Kombinasyon Araçlarını, belirlenen sınır daha yüksek olsa bile, eyaletlerarası otoyollarda azami 65 mph ile sınırlar. Kaynak: ARSD 70:03:01:61."},"70":{"q":"South Dakota'da, plakartlı tehlikeli madde taşıyan bir araç durması gereken bir demiryolu geçidine yaklaştığında nerede durmalıdır?","options":["En yakın rayın 5 ila 25 feet içinde","En yakın rayın 15 ila 50 feet içinde","En yakın rayın 25 ila 75 feet içinde","En yakın rayın 50 ila 100 feet içinde"],"explanation":"Plakartlı bir araç en yakın rayın 15 ila 50 feet içinde durmalı, ardından geçmeden önce bakıp dinlemelidir. Kaynak: SD CDL Kılavuzu; 49 CFR 392.10."},"71":{"q":"South Dakota'da demiryolu raylarından geçerken, bir otobüsün veya plakartlı aracın sürücüsü neyi YAPMAMALIDIR?","options":["Trenleri görmek için bakmak ve dinlemek","Raylar üzerindeyken vites değiştirmek","Gücü korumak için düşük vites kullanmak","Rayları geçecek kadar yer olduğundan emin olmak"],"explanation":"Sürücüler, geçitte stop etmeyi önlemek için raylardan geçerken vites değiştirmemelidir; değiştirilmesi gerekmeyen bir vitesle geçin. Kaynak: SD CDL Kılavuzu; 49 CFR 392.10/392.11."},"72":{"q":"South Dakota'da bir otobüs sürücüsünün genellikle zorunlu duruşu yapması GEREKMEDIĞI demiryolu geçidi hangisidir?","options":["Trafiği geçirerek yönlendiren bir polis memuru veya işaretçi tarafından kontrol edilen bir geçit","Açık arazide çok raylı bir geçit","Otomatik bariyeri olmayan bir geçit","Dik bir iniş eğimindeki bir geçit"],"explanation":"Zorunlu duruş; bir polis memuru veya işaretçinin trafiği yönlendirdiği yerde, muaf/terk edilmiş veya endüstriyel yan hat geçidinde ya da geçidi yeşil bir trafik sinyali kontrol ettiğinde gerekmez. Kaynak: SD CDL Kılavuzu; 49 CFR 392.10."},"73":{"q":"South Dakota'da bir ticari sürücü, yol kenarında durduğunda kaç adet yansıtıcı uyarı üçgeni taşımalı ve yerleştirmelidir?","options":["Bir üçgen","İki üçgen","Üç üçgen","Dört üçgen"],"explanation":"Bir CMV, durduktan sonraki 10 dakika içinde yerleştirilmek üzere üç yansıtıcı üçgen (veya eşdeğer cihazlar) taşımalı ve yerleştirmelidir. Kaynak: SD CDL Kılavuzu; 49 CFR 392.22."},"74":{"q":"South Dakota'da iki şeritli, çift yönlü bir karayolunda, bir kamyon durduğunda üç uyarı üçgeni nereye yerleştirilmelidir?","options":["Üçünün de aracın yaklaşık 100 feet arkasına","Aracın yaklaşık 10 feet, 100 feet ve 200 feet arkasına","Trafik tarafında 10 feet içinde ve aracın yaklaşık 100 feet önüne ve 100 feet arkasına","Aracın yaklaşık 50 feet önüne, yanına ve arkasına"],"explanation":"İki şeritli, çift yönlü bir yolda, bir üçgeni trafik tarafında 10 feet içine, birini aracın yaklaşık 100 feet arkasına ve birini yaklaşık 100 feet önüne yerleştirin. Kaynak: SD CDL Kılavuzu; 49 CFR 392.22."},"75":{"q":"South Dakota'da bölünmüş veya tek yönlü bir karayolunda, üç uyarı üçgeni durmuş bir kamyonun arkasına nereye yerleştirilir?","options":["10, 50 ve 100 feet'e","10, 100 ve 200 feet'e","25, 100 ve 300 feet'e","50, 150 ve 250 feet'e"],"explanation":"Bölünmüş veya tek yönlü bir yolda, üçgenleri aracın arkasında yaklaşan trafiğe doğru yaklaşık 10 feet, 100 feet ve 200 feet'e yerleştirin. Kaynak: SD CDL Kılavuzu; 49 CFR 392.22."},"76":{"q":"South Dakota'nın sağdan gitme kuralı uyarınca, bir sürücü ne zaman yolun sağ şeridini veya sağ kısmını kullanmalıdır?","options":["Yalnızca eyaletlerarası otoyollarda","Trafiğin normal hızından daha yavaş ilerlerken, geçiş yaparken veya sağ şeridin kullanılamayacağı durumlar hariç","Yalnızca gün batımı ile gün doğumu arasında","Yalnızca arkadan bir kamyon takip ederken"],"explanation":"SDCL 32-26-1, yolun sağ yarısında sürmeyi ve normalden yavaş trafik için, geçiş yaparken ya da sağ şeridi kullanmanın pratik olmadığı durumlar dışında sağda kalmayı gerektirir. Kaynak: SDCL 32-26-1."},"77":{"q":"South Dakota'da büyük boy (oversize) izni gerekmeden önceki azami yasal araç genişliği nedir?","options":["8 feet 0 inç","8 feet 6 inç","9 feet 0 inç","10 feet 0 inç"],"explanation":"South Dakota'nın izin gerektirmeyen yasal genişlik sınırı 8 feet 6 inç'tir (102 inches); bundan daha geniş olan herhangi bir şey büyük boy izni gerektirir. Kaynak: SDDOT/SD Highway Patrol büyük boy izin kuralları; SDCL böl. 32-22."},"78":{"q":"South Dakota'da, büyük boy yük (bölünemez genişlik) izni sahibi genellikle hangi saatlerde seyahat edebilir?","options":["Günün 24 saati, herhangi bir gün","Yalnızca Pazartesi'den Cuma'ya, sadece gündüz","Gün doğumundan yarım saat önce, gün batımından yarım saat sonrasına kadar, hafta sonları dahil","Yalnızca hafta içi sabah 9 ile öğleden sonra 4 arasında"],"explanation":"Büyük boy yükler, Cumartesi ve Pazar dahil, gün doğumundan yarım saat önce gün batımından yarım saat sonrasına kadar hareket edebilir; yalnızca ağır yükler kesintisiz hareket edebilir. Kaynak: SDDOT/SD Highway Patrol büyük boy izin kuralları."},"79":{"q":"Hangi South Dakota kurumu Ticari Sürücü Belgeleri (CDL) düzenler?","options":["South Dakota Department of Public Safety, Driver Licensing Program","South Dakota Department of Transportation","Başvuru sahibinin yaşadığı ilçe şerif ofisi","Federal Motor Carrier Safety Administration"],"explanation":"South Dakota'da CDL'ler, Department of Public Safety tarafından Driver Licensing Program aracılığıyla düzenlenir (Pierre, SD). SD DOT, sürücü ruhsatlandırmasını değil, izinleri ve yolları yönetir. Kaynak: SD DPS Driver Licensing / SD Truck Information (sdtruckinfo.sd.gov), Motor Carrier Handbook Böl. 8."},"80":{"q":"Yalnızca eyalet içi ticarette (South Dakota içinde) araç kullanmak üzere bir South Dakota CDL almak için asgari yaş nedir?","options":["16","18","19","21"],"explanation":"South Dakota, eyalet içi ticaret için 18 yaşında CDL'ye izin verir; eyaletlerarası (eyalet sınırlarını aşan) ticaret 21 yaşını gerektirir. Kaynak: SD Motor Carrier Handbook Böl. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"81":{"q":"Eyaletlerarası ticaret için (eyalet sınırlarını aşarak araç kullanma) bir South Dakota CDL almak için asgari yaş nedir?","options":["18","19","20","21"],"explanation":"South Dakota'da eyaletlerarası ticarette araç kullanmak asgari 21 yaşını gerektirir; 18 ila 20 yaş arasındaki sürücüler eyalet içi operasyonlarla sınırlıdır. Kaynak: SD Motor Carrier Handbook Böl. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"82":{"q":"Bir South Dakota Ticari Öğrenme İzni (CLP) ne kadar süre geçerlidir?","options":["30 gün","6 ay","1 yıl","2 yıl"],"explanation":"Bir South Dakota CLP, kamuya açık yollarda direksiyon başında eğitim için bir yıllık bir süre için düzenlenir. Kaynak: SD Motor Carrier Handbook Böl. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"83":{"q":"South Dakota'da bir Ticari Öğrenme İzni (CLP) düzenlendikten sonra, bir başvuru sahibinin CDL beceri sınavına girmeden önce ne kadar beklemesi gerekir?","options":["Bekleme süresi gerekmez","En az 7 gün","En az 14 gün","En az 30 gün"],"explanation":"CLP'nin düzenlendiği tarih ile beceri sınavının tamamlanabileceği tarih arasında 14 günlük bir bekleme süresi vardır. Kaynak: SD Motor Carrier Handbook Böl. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov); federal 49 CFR 383.25'i yansıtır."},"84":{"q":"Bir South Dakota CDL başvuru sahibi, ticaret türü ve tıbbi gereklilikler açısından kaç öz-sertifikasyon kategorisinden seçim yapmalıdır?","options":["İki","Üç","Dört","Beş"],"explanation":"Dört öz-sertifikasyon kategorisi vardır: Non-excepted Interstate (NI), Excepted Interstate (EI), Non-excepted Intrastate (NA) ve Excepted Intrastate (EA). Kaynak: SD DPS CDL Medical Certification; 49 CFR 383.71."},"85":{"q":"Eyalet sınırlarını aşarak çalışan ve federal DOT fiziksel yeterlilik standartlarını karşılaması gereken bir South Dakota sürücüsü hangi kategori olarak öz-sertifikasyon yapar?","options":["Non-excepted Interstate (NI)","Excepted Interstate (EI)","Non-excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Non-excepted Interstate (NI), sürücünün eyaletlerarası ticarette çalıştığı ve federal DOT tıbbi sertifika gerekliliklerini (güncel bir tıbbi muayene sertifikası) karşılaması gerektiği anlamına gelir. Kaynak: SD DPS CDL Medical Certification; 49 CFR 383.71."},"86":{"q":"Bir South Dakota CDL başvuru sahibi Non-excepted Interstate olarak öz-sertifikasyon yaptığında, geçerli kalmak için eyalette dosyada hangi belge tutulmalıdır?","options":["Bir göz doktorundan görme muafiyeti","Güncel bir DOT tıbbi muayene sertifikası","İmzalı bir işveren beyannamesi","Noter onaylı bir sürüş kaydı"],"explanation":"Non-excepted sürücüler, Driver Licensing Program ile dosyada geçerli bir tıbbi muayene sertifikası (DOT tıbbi kartı) bulundurmalıdır; bu olmadan CDL düşürülür (downgrade edilir). Kaynak: SD DPS CDL Medical Certification."},"87":{"q":"Bir South Dakota CDL sahibinin DOT tıbbi sertifikası için fiziksel muayeneyi yapmaya kim yetkilidir?","options":["Sürücünün seçtiği herhangi bir ruhsatlı hekim","FMCSA National Registry of Certified Medical Examiners'ta listelenen bir tıbbi muayene uzmanı","Yalnızca SD Department of Public Safety tarafından istihdam edilen bir hekim","Herhangi bir acil bakım kliniğindeki bir hemşire"],"explanation":"Muayene, FMCSA National Registry of Certified Medical Examiners'ta listelenen bir tıbbi profesyonel tarafından yapılmalıdır. Kaynak: SD Motor Carrier Handbook Böl. 8, CDL Qualifications (sdtruckinfo.sd.gov); National Registry (nationalregistry.fmcsa.dot.gov)."},"88":{"q":"Bir South Dakota CDL sahibinin DOT fiziksel muayenesinden sonra, tıbbi muayene sertifikası genellikle eyaletin Driver Licensing Program'ına nasıl ulaşır?","options":["Sürücü onu bir adliyeye elden teslim etmelidir","Muayene uzmanı, National Registry aracılığıyla 2 iş günü içinde elektronik olarak Driver Licensing'e gönderir","Yalnızca sürücünün işvereni tarafından postayla gönderilir","Herhangi bir gönderim olmaksızın otomatik olarak geçerlidir"],"explanation":"Sertifikalı tıbbi muayene uzmanları, sertifikayı FMCSA National Registry aracılığıyla 2 iş günü içinde elektronik olarak South Dakota Driver Licensing'e gönderir; sürücüler ayrıca bir kopyayı faks, e-posta veya postayla da gönderebilir. Kaynak: SD DPS / SD Truck Information (sdtruckinfo.sd.gov)."},"89":{"q":"Bir South Dakota CDL sahibi için bir DOT tıbbi muayene sertifikasının geçerli olabileceği azami süre nedir?","options":["6 ay","1 yıl","2 yıl","5 yıl"],"explanation":"Bir tıbbi muayene sertifikası en fazla iki yıl geçerlidir ve sürücünün tıbbi durumuna bağlı olarak daha kısa bir süre için düzenlenebilir. Kaynak: SD Motor Carrier Handbook Böl. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 391.43."},"90":{"q":"Araç sınıfı veya onayları (endorsement) ne olursa olsun, HER South Dakota CDL başvuru sahibinin geçmesi gereken bilgi sınavı hangisidir?","options":["Hava frenleri sınavı","Genel bilgi sınavı","Tehlikeli maddeler sınavı","Çiftli/üçlü römork sınavı"],"explanation":"Genel bilgi sınavı tüm başvuru sahipleri tarafından alınır; diğer sınavlar yalnızca belirli araçlar veya onaylar için gereklidir. Kaynak: SD Motor Carrier Handbook Böl. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"91":{"q":"South Dakota CDL beceri sınavı, sırasıyla hangi üç bölümden oluşur?","options":["Yazılı sınav, görme taraması ve yol sınavı","Sefer öncesi muayene, temel araç kontrolü ve yolda sürüş","Hava freni sınavı, bağlantı (coupling) sınavı ve geri manevra sınavı","Bilgi sınavı, simülatör sınavı ve gece sürüş sınavı"],"explanation":"Beceri sınavının üç bölümü vardır: sefer öncesi (araç) muayenesi, temel araç kontrol manevraları ve yolda sürüş sınavı. Kaynak: SD Motor Carrier Handbook Böl. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"92":{"q":"South Dakota CDL beceri sınavının temel araç kontrolü bölümünde, başvuru sahibinden öncelikle neyi göstermesi istenir?","options":["Tüm CDL kılavuzunu ezbere okumak","Aracı, konilerle işaretlenmiş tanımlı bir alan içinde ileri, geri hareket ettirmek ve döndürmek","Bir fren sistemini onarmak","Tehlikeli yükü yüklemek ve sabitlemek"],"explanation":"Temel araç kontrolü, sürücünün aracı ileri ve geri hareket ettirme ve konilerle veya bariyerlerle işaretlenmiş tanımlı bir alan içinde döndürme yeteneğini değerlendirir. Kaynak: SD Motor Carrier Handbook Böl. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"93":{"q":"South Dakota CDL beceri sınavının sefer öncesi muayene bölümünde, başvuru sahibi ne yapmalıdır?","options":["Karayolu trafiğinin içinden geçerek araç kullanmak","Muayene edecekleri araç bileşenlerini tanımlamak ve neyi, neden kontrol ettiklerini açıklamak","Yalnızca paralel park yapmayı göstermek","Ayrı bir yazılı hazmat sınavını geçmek"],"explanation":"Sefer öncesi muayene, sürücünün araç güvenliğini değerlendirme yeteneğini göstermesini, muayene maddelerini tanımlamasını ve neyi, neden kontrol edeceğini açıklamasını gerektirir. Kaynak: SD Motor Carrier Handbook Böl. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"94":{"q":"South Dakota'da, bir başvuru sahibi bir CDL bilgi veya beceri sınavında başarısız olursa, en erken ne zaman tekrar sınava girebilir?","options":["Hemen, aynı gün","Bir sonraki iş gününden önce değil","30 günlük bir bekleme süresinden sonra","Tam 6 ay sonra"],"explanation":"Sınavlardan herhangi birinde başarısız olursanız, bir sonraki iş gününden önce tekrar sınava giremezsiniz; daha fazla çalışmak veya pratik yapmak isterseniz daha uzun bekleyebilirsiniz. Kaynak: SD Motor Carrier Handbook Böl. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"95":{"q":"South Dakota'da, her sınav ücreti altı aylık bir süre içinde kaç sınav fırsatını kapsar?","options":["Bir","İki","Üç","Sınırsız"],"explanation":"Başvuru sahiplerine, altı aylık bir süre içinde ödenen her ücret için üç sınav fırsatı verilir. Kesin ücret tutarları değişebileceğinden, dolar rakamları yerine süreç kurallarına güvenilmelidir. Kaynak: SD Motor Carrier Handbook Böl. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"96":{"q":"South Dakota'nın uyguladığı federal Entry-Level Driver Training (ELDT) kuralı uyarınca, ilk kez CDL alacak bir başvuru sahibi gerekli eğitimi nerede tamamlamalıdır?","options":["Kendi seçtikleri herhangi bir çevrimiçi kurs","FMCSA Training Provider Registry'de (TPR) listelenen bir eğitim sağlayıcısı","Yalnızca SD DPS tarafından sunulan bir kurs","Sınavdan önce resmi bir eğitim gerekmez"],"explanation":"ELDT (7 Şubat 2022'de yürürlüğe girdi), CDL beceri sınavına (veya hazmat için bilgi sınavına) girmeden önce başlangıç seviyesindeki başvuru sahiplerinin FMCSA Training Provider Registry'de bulunan bir sağlayıcıdan teorik ve direksiyon başında eğitim tamamlamasını gerektirir. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380), SD DPS tarafından uygulanır."},"97":{"q":"Bir South Dakota CDL alırken federal ELDT gerekliliği hangi başvuru sahiplerine uygulanır?","options":["Yalnızca 65 yaşın üzerindeki sürücüler","İlk kez bir Class A veya B CDL alan, sınıf yükseltmesi yapan ya da ilk kez okul otobüsü, yolcu veya hazmat onayı talep eden başvuru sahipleri","Yalnızca eyalet dışından transfer başvurusu yapanlar","Yalnızca mevcut bir CDL'yi yenileyen sürücüler"],"explanation":"ELDT; ilk Class A veya B CDL alanlar, yükseltme yapanlar (örn. B'den A'ya) veya ilk kez okul otobüsü, yolcu ya da tehlikeli maddeler onayı alanlar için geçerlidir; rutin yenilemeler için değil, tek seferlik bir gerekliliktir. Kaynak: FMCSA ELDT kuralı (49 CFR Part 380), SD DPS tarafından uygulanır."},"98":{"q":"Bir South Dakota Ticari Sürücü Belgesi (CDL) yenilenmesi gerekmeden önce ne kadar süre geçerlidir?","options":["1 yıl","2 yıl","4 yıl","5 yıl"],"explanation":"Bir South Dakota CDL beş yıl geçerlidir ve sahibinin doğum gününde sona erer; sahipler son kullanma tarihinden 180 gün önceye kadar, genellikle bir DPS sınav istasyonunda görme taramasıyla şahsen yenileyebilir. Kaynak: SD DPS Driver Licensing (yenileme rehberi)."}},"es":{"0":{"q":"¿Cuál es el ancho máximo legal de un vehículo y su carga en las carreteras de Dakota del Sur sin un permiso?","options":["96 pulgadas (8 pies)","102 pulgadas (8 pies 6 pulgadas)","108 pulgadas (9 pies)","120 pulgadas (10 pies)"],"explanation":"Dakota del Sur limita el ancho máximo de cualquier vehículo, incluida su carga, a 102 pulgadas (8 pies 6 pulgadas). Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Tamaño de los Vehículos), sdtruckinfo.sd.gov."},"1":{"q":"¿Cuál es la altura máxima legal de un vehículo, incluida su carga, en las carreteras de Dakota del Sur?","options":["13 pies 6 pulgadas","13 pies","14 pies","15 pies"],"explanation":"Dakota del Sur establece la altura máxima de cualquier vehículo, incluida la carga, en 14 pies. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Tamaño de los Vehículos), sdtruckinfo.sd.gov."},"2":{"q":"En Dakota del Sur, un vehículo que transporta una carga de pacas de heno puede alcanzar legalmente ¿qué altura máxima?","options":["14 pies","14 pies 6 pulgadas","15 pies","16 pies"],"explanation":"Si bien el límite general de altura es de 14 pies, Dakota del Sur permite que un vehículo con una carga de pacas de heno tenga hasta 15 pies de altura. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Tamaño de los Vehículos), sdtruckinfo.sd.gov."},"3":{"q":"¿Cuál es el peso máximo legal sobre un eje sencillo en las carreteras de Dakota del Sur?","options":["18,000 libras","20,000 libras","22,400 libras","34,000 libras"],"explanation":"Dakota del Sur limita un eje sencillo a 20,000 libras, igualando el estándar federal. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Peso de los Vehículos), sdtruckinfo.sd.gov."},"4":{"q":"¿Cuál es el peso máximo legal sobre un grupo de ejes en tándem en las carreteras de Dakota del Sur?","options":["32,000 libras","33,000 libras","34,000 libras","36,000 libras"],"explanation":"Dakota del Sur limita un grupo de ejes en tándem a 34,000 libras, igualando el estándar federal. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Peso de los Vehículos), sdtruckinfo.sd.gov."},"5":{"q":"Sin un permiso especial, ¿cuál es el peso bruto vehicular máximo permitido en las autopistas interestatales de Dakota del Sur?","options":["73,280 libras","80,000 libras","90,000 libras","105,500 libras"],"explanation":"El peso bruto máximo en las autopistas interestatales de Dakota del Sur es de 80,000 libras, a menos que el vehículo cuente con un permiso anual Over 80,000 Pounds on Interstate. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Peso de los Vehículos), sdtruckinfo.sd.gov."},"6":{"q":"¿Cuál es la longitud máxima de un semirremolque que opera en una combinación de tractocamión y semirremolque en Dakota del Sur?","options":["48 pies","53 pies","57 pies","60 pies"],"explanation":"Dakota del Sur permite un semirremolque de hasta 53 pies de longitud cuando opera en una combinación de tractocamión y semirremolque. Fuente: SDCL 32-22-8.1 (Limitaciones de longitud para remolques y semirremolques)."},"7":{"q":"Para una carga que se transporta en Dakota del Sur, ¿cuánto puede sobresalir la carga por la parte trasera del vehículo?","options":["No más de 3 pies","No más de 4 pies","No más de 6 pies","No más de 8 pies"],"explanation":"Una carga o sus extensiones retráctiles no pueden sobresalir más de 4 pies por detrás del parachoques, la plataforma o la carrocería del vehículo. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Tamaño de los Vehículos), sdtruckinfo.sd.gov."},"8":{"q":"En Dakota del Sur, ¿cuánto puede sobresalir una carga por la parte delantera del vehículo que la transporta?","options":["No más de 2 pies","No más de 3 pies","No más de 4 pies","No más de 5 pies"],"explanation":"Una carga no puede sobresalir más de 3 pies por delante del parachoques, la plataforma o la carrocería del vehículo. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Tamaño de los Vehículos), sdtruckinfo.sd.gov."},"9":{"q":"¿Cuál es el peso máximo que puede soportar un neumático del eje de dirección en Dakota del Sur, expresado por pulgada de ancho del neumático?","options":["400 libras por pulgada","500 libras por pulgada","600 libras por pulgada","650 libras por pulgada"],"explanation":"Dakota del Sur limita las cargas de los ejes de dirección y de los ejes de neumáticos dobles a 600 libras por pulgada de ancho del neumático. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Peso de los Vehículos), sdtruckinfo.sd.gov."},"10":{"q":"Para los neumáticos montados en ejes que no sean de dirección ni de neumáticos dobles, ¿cuál es el peso máximo por neumático por pulgada de ancho del neumático en Dakota del Sur?","options":["450 libras por pulgada","500 libras por pulgada","550 libras por pulgada","600 libras por pulgada"],"explanation":"Dakota del Sur limita los neumáticos en ejes que no sean de dirección ni de neumáticos dobles a 500 libras por pulgada de ancho del neumático. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Peso de los Vehículos), sdtruckinfo.sd.gov."},"11":{"q":"Dakota del Sur utiliza la fórmula federal de peso bruto por puente (Bridge Gross Weight Formula) para limitar el peso de los grupos de ejes. ¿En función de qué factores determina la fórmula el peso máximo?","options":["Únicamente el número total de ejes del vehículo","La distancia entre los ejes extremos de un grupo y el número de ejes de ese grupo","El peso registrado del vehículo y la potencia del motor","El ancho del neumático y el límite de velocidad publicado de la carretera"],"explanation":"Dakota del Sur aplica la fórmula federal de puente W = 500[(L x N)/(N-1) + 12N + 36], donde L es la distancia entre los ejes extremos de un grupo y N es el número de ejes de ese grupo. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Peso de los Vehículos), sdtruckinfo.sd.gov."},"12":{"q":"Un productor agrícola de Dakota del Sur que transporta una cosecha recolectada dentro de un radio de 50 millas del campo (no en una autopista interestatal) puede tener ¿qué tolerancia de peso por encima de los límites legales?","options":["5 por ciento por encima de los límites legales","10 por ciento por encima de los límites legales","15 por ciento por encima de los límites legales","No se permite ninguna tolerancia"],"explanation":"Dakota del Sur permite hasta un 10 por ciento por encima de los límites legales de peso al transportar una cosecha recolectada dentro de un radio de 50 millas del campo cosechado, excepto en el sistema de autopistas interestatales. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Peso de los Vehículos), sdtruckinfo.sd.gov."},"13":{"q":"Dakota del Sur permite una tolerancia de peso del 5 por ciento por encima de los límites legales para ciertos transportes de almacenamiento agrícola y de ganado. ¿Qué restricción de distancia y de carretera aplica?","options":["Dentro de un radio de 25 millas del lugar de carga, incluidas las autopistas interestatales","Dentro de un radio de 50 millas del lugar de carga, pero no en autopistas interestatales","Dentro de un radio de 100 millas del lugar de carga, incluidas las autopistas interestatales","En cualquier parte del estado, pero no en autopistas interestatales"],"explanation":"La tolerancia del 5 por ciento para el transporte hacia almacenamiento agrícola o de ganado aplica dentro de un radio de 50 millas del lugar de carga y no se permite en el sistema de autopistas interestatales (y queda excluida durante las restricciones de carga de primavera). Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Peso de los Vehículos), sdtruckinfo.sd.gov."},"14":{"q":"En las carreteras de Dakota del Sur que no son interestatales, ¿cuál es el peso bruto máximo que puede alcanzar mediante permiso un Vehículo de Combinación Más Larga (Longer Combination Vehicle) correctamente configurado y con suficientes ejes?","options":["80,000 libras","105,500 libras","129,000 libras","164,000 libras"],"explanation":"Dakota del Sur permite que ciertos Vehículos de Combinación Más Larga con suficientes ejes alcancen un peso bruto de hasta 129,000 libras en carreteras que no son interestatales, siempre que se cumplan los límites de eje, neumático y de la fórmula de puente. Fuente: SDCL 32-22-16/32-22-16.1 y ARSD 70:03:01:61."},"15":{"q":"¿Qué sistema en línea de Dakota del Sur se utiliza para solicitar y obtener permisos para vehículos de tamaño o peso excesivo?","options":["El IRP Clearinghouse","El sistema de permisos SDAPS","El portal FMCSA","El registro nacional UCR"],"explanation":"Los permisos para vehículos de tamaño y peso excesivo en Dakota del Sur se obtienen a través del portal en línea SDAPS (South Dakota Automated Permitting System). Fuente: páginas de permisos de SD Truck Information, sdtruckinfo.sd.gov; SDAPS en sdaps.sd.gov."},"16":{"q":"¿Cuándo se requiere generalmente un permiso estatal de tamaño o peso excesivo de Dakota del Sur para una carga en las carreteras estatales?","options":["Únicamente cuando la carga es material peligroso","Cuando se transporta una carga indivisible que excede los límites de tamaño, peso, o ambos","Para cualquier vehículo comercial de más de 26,001 libras de GVWR","Únicamente al cruzar una línea estatal para ingresar a Dakota del Sur"],"explanation":"Se requiere un permiso para el desplazamiento por carreteras estatales de un vehículo que transporte una carga indivisible que exceda los límites legales de tamaño, peso, o de tamaño y peso. Fuente: páginas de permisos de SD Truck Information, sdtruckinfo.sd.gov."},"17":{"q":"Un permiso Over 80,000 Pounds on Interstate en Dakota del Sur permite un peso bruto adicional, pero el vehículo aún NO debe exceder ¿cuál de los siguientes?","options":["Su peso legal por eje, su peso legal por neumático, o el peso de la fórmula de puente","Una velocidad de 55 millas por hora","Una longitud total de 53 pies","Circular únicamente durante las horas de luz del día"],"explanation":"El permiso Over 80,000 Pounds on Interstate no permite que un vehículo exceda su peso legal por eje, su peso legal por neumático, ni el peso permitido por la Bridge Gross Weight Formula. Fuente: páginas de permisos de SD Truck Information, sdtruckinfo.sd.gov; SDCL 32-22-42."},"18":{"q":"En Dakota del Sur, el límite de longitud que aplica a una combinación de tractor y semirremolque se mide por la longitud del remolque en lugar de la longitud total. Para una combinación de semirremolque y remolque (excluyendo el tractocamión), ¿cuál es la longitud combinada máxima?","options":["65 pies, con ninguna unidad por encima de 28.5 pies","75 pies, con ninguna unidad por encima de 40 pies","81.5 pies, con ninguna unidad por encima de 45 pies","85 pies, con ninguna unidad por encima de 48 pies"],"explanation":"Una combinación de semirremolque con semirremolque o de semirremolque con remolque (excluyendo el tractocamión) no puede exceder los 81 pies 6 pulgadas, siempre que ninguna unidad exceda los 45 pies. Fuente: SDCL 32-22-8.1."},"19":{"q":"Bajo la exención de maquinaria agrícola de Dakota del Sur, un agricultor que opera maquinaria agrícola puede exceder el límite de ancho de 102 pulgadas durante las horas de luz del día, excepto en ¿cuáles carreteras?","options":["Todas las carreteras estatales pavimentadas","Las autopistas interestatales","Los caminos de grava del condado","Las calles dentro de los límites de la ciudad"],"explanation":"La maquinaria agrícola operada por un agricultor no tiene límite de ancho durante las horas de luz del día, excepto en las autopistas interestatales, donde aplican los límites estándar. Fuente: SD Commercial and Agricultural Vehicle Handbook, Capítulo 5 (Regulaciones sobre el Tamaño de los Vehículos), sdtruckinfo.sd.gov."},"20":{"q":"En Dakota del Sur, ¿cuál es la edad mínima para obtener una CDL y operar un vehículo motorizado comercial en el comercio INTERESTATAL?","options":["18 años","19 años","21 años","25 años"],"explanation":"Dakota del Sur sigue la norma federal: un conductor debe tener al menos 21 años de edad para obtener una CDL para el comercio interestatal. A los conductores de 18 a 20 años se les puede expedir una CDL únicamente para operación intraestatal. Fuente: SD Motor Carrier Handbook, Cap. 8, Requisitos de la CDL (sdtruckinfo.sd.gov); 49 CFR 391.11."},"21":{"q":"A un solicitante de Dakota del Sur que tiene entre 18 y 20 años se le puede expedir una CDL, pero está restringida ¿a qué tipo de operación?","options":["Únicamente comercio intraestatal (dentro de Dakota del Sur)","Únicamente comercio interestatal","Únicamente vehículos agrícolas","Únicamente conducción diurna"],"explanation":"Dakota del Sur permite que los solicitantes de 18 a 20 años reciban una CDL válida únicamente para el comercio intraestatal (conducir dentro de Dakota del Sur). La operación interestatal requiere tener 21 años. Fuente: SD Motor Carrier Handbook, Cap. 8, Requisitos de la CDL (sdtruckinfo.sd.gov)."},"22":{"q":"Bajo las clasificaciones de CDL de Dakota del Sur, ¿cuál combinación define una licencia CLASE A?","options":["Cualquier vehículo sencillo con un GVWR que exceda las 26,000 libras","Cualquier combinación de vehículos con un GCWR que exceda las 26,000 libras donde la unidad remolcada tenga un GVWR que exceda las 10,000 libras","Cualquier vehículo con placas de materiales peligrosos","Cualquier vehículo diseñado para transportar 16 o más pasajeros"],"explanation":"Dakota del Sur define la Clase A como cualquier combinación de vehículos con una Calificación de Peso Bruto Combinado (GCWR) que exceda las 26,000 lbs, siempre que el vehículo remolcado tenga un GVWR que exceda las 10,000 lbs. Fuente: SD Motor Carrier Handbook, Cap. 8, Clasificaciones de la CDL (sdtruckinfo.sd.gov)."},"23":{"q":"¿Cómo define Dakota del Sur una licencia de conductor comercial CLASE B?","options":["Una combinación con un GCWR de más de 26,000 libras que remolca una unidad de más de 10,000 libras","Un vehículo sencillo con un GVWR de más de 26,000 libras, o un vehículo de ese tipo que remolca una unidad de no más de 10,000 libras","Cualquier vehículo que transporte residuos peligrosos","Cualquier vehículo con un GVWR menor a 10,000 libras"],"explanation":"Dakota del Sur define la Clase B como cualquier vehículo sencillo con un GVWR que exceda las 26,000 lbs, o cualquier vehículo de ese tipo que remolque un vehículo que no exceda las 10,000 lbs de GVWR. Fuente: SD Motor Carrier Handbook, Cap. 8, Clasificaciones de la CDL (sdtruckinfo.sd.gov)."},"24":{"q":"En Dakota del Sur, una CDL CLASE C aplica a un vehículo que no cumple con la Clase A ni la Clase B, pero que o bien lleva placas de materiales peligrosos o está diseñado para transportar ¿cuántas personas?","options":["8 o más, incluido el conductor","12 o más, incluido el conductor","16 o más, incluido el conductor","24 o más, incluido el conductor"],"explanation":"Dakota del Sur define la Clase C como un vehículo sencillo o una combinación que no cumple con la Clase A ni la Clase B y que o bien debe llevar placas de materiales peligrosos o está diseñado para transportar 16 o más pasajeros, incluido el conductor. Fuente: SD Motor Carrier Handbook, Cap. 8, Clasificaciones de la CDL (sdtruckinfo.sd.gov)."},"25":{"q":"¿Qué código de endoso coloca Dakota del Sur en una CDL para un conductor que transporta MATERIALES PELIGROSOS con placas (no en un tanque)?","options":["N","T","H","P"],"explanation":"Dakota del Sur utiliza el endoso H para el transporte de materiales peligrosos con placas. El endoso N es para vehículos cisterna, T para dobles/triples y P para pasajeros. Fuente: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Cap. 8 (sdtruckinfo.sd.gov)."},"26":{"q":"Antes de que Dakota del Sur agregue un endoso de HazMat (H) a una CDL, el solicitante debe completar ¿qué paso federal además de aprobar el examen de conocimientos?","options":["Una evaluación de amenazas de seguridad de la TSA que incluye toma de huellas dactilares","Una pasantía de 100 horas","Una autorización de cirugía ocular","Un examen práctico de manejo aparte en un vehículo cisterna"],"explanation":"Dakota del Sur no puede expedir el endoso de HazMat hasta que el solicitante apruebe el programa federal TSA Hazardous Materials Endorsement Threat Assessment Program, que requiere toma de huellas dactilares y una verificación de antecedentes, además del examen escrito de conocimientos. Fuente: programa TSA HME; SD DPS CDL Endorsements; 49 CFR 1572."},"27":{"q":"El endoso de CISTERNA (N) de Dakota del Sur se requiere para vehículos que transportan líquidos o gases en un tanque permanente con capacidad de 119 galones o más, o tanques portátiles con una capacidad nominal total de al menos ¿cuántos galones?","options":["500 galones","750 galones","1,000 galones","1,500 galones"],"explanation":"Dakota del Sur requiere el endoso N (cisterna) para tanques permanentes con capacidad de 119 galones (450 litros) o más, o tanques portátiles con una capacidad nominal total de 1,000 galones o más. Fuente: SD CDL Manual / SD DPS CDL Endorsements; definición de vehículo cisterna de la FMCSA, 49 CFR 383.5."},"28":{"q":"Un conductor de Dakota del Sur que transporta materiales peligrosos EN UN VEHÍCULO CISTERNA debe portar ¿qué endoso combinado?","options":["T","X","S","P"],"explanation":"Dakota del Sur utiliza el endoso X para representar la combinación de cisterna (N) y materiales peligrosos (H) para conductores que transportan materiales peligrosos en un vehículo cisterna. Fuente: SD Motor Carrier Handbook, Cap. 8, Clasificaciones y Endosos de la CDL (sdtruckinfo.sd.gov)."},"29":{"q":"¿Qué endoso requiere Dakota del Sur para un conductor que remolca remolques DOBLES o TRIPLES?","options":["P","N","T","H"],"explanation":"Dakota del Sur requiere el endoso T para remolques dobles y triples; el solicitante debe aprobar un examen especial de conocimientos sobre los problemas de remolcar múltiples remolques. No hay un examen práctico de habilidades aparte para el endoso T. Fuente: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Cap. 8."},"30":{"q":"Para obtener el endoso de PASAJEROS (P) de Dakota del Sur, un conductor debe aprobar un examen especial de conocimientos Y ¿qué más?","options":["Un examen práctico de habilidades en un vehículo de pasajeros","Un acompañamiento de manejo de 50 horas","Una verificación de antecedentes de la TSA","Un examen de la vista aparte en un autobús"],"explanation":"Dakota del Sur requiere que los conductores que buscan el endoso P (vehículos diseñados para 16 o más pasajeros incluido el conductor) aprueben tanto un examen especial de conocimientos como un examen práctico de habilidades realizado en un vehículo de pasajeros. Fuente: SD DPS CDL Endorsements; SD CDL Manual."},"31":{"q":"En Dakota del Sur, antes de que se pueda expedir a un conductor el endoso de AUTOBÚS ESCOLAR (S), la CDL ya debe portar ¿cuál otro endoso?","options":["El endoso H (HazMat)","El endoso T (dobles/triples)","El endoso P (pasajeros)","El endoso N (cisterna)"],"explanation":"Dakota del Sur requiere el endoso de pasajeros (P) como requisito previo para el endoso de autobús escolar (S); el solicitante del endoso S también debe aprobar un examen de conocimientos de autobús escolar y un examen práctico de habilidades. Fuente: SD DPS CDL Endorsements; SD CDL Manual."},"32":{"q":"¿Por cuánto tiempo es válido un Permiso de Aprendizaje Comercial (CLP) de Dakota del Sur?","options":["60 días","6 meses","1 año","5 años"],"explanation":"Un CLP de Dakota del Sur se expide por un período de un año para la capacitación al volante. Fuente: SD Motor Carrier Handbook, Cap. 8, Requisitos de la CDL (sdtruckinfo.sd.gov); 49 CFR 383.25."},"33":{"q":"Después de recibir un Permiso de Aprendizaje Comercial, ¿cuánto tiempo debe esperar un solicitante de Dakota del Sur antes de ser elegible para presentar el examen práctico de habilidades de la CDL?","options":["Al menos 7 días","Al menos 14 días","Al menos 30 días","Al menos 90 días"],"explanation":"Dakota del Sur aplica la norma federal de que un CLP debe conservarse durante al menos 14 días antes de que el titular sea elegible para presentar el examen práctico de habilidades (de manejo) de la CDL. Fuente: SD DPS Driver Licensing; 49 CFR 383.25(e)."},"34":{"q":"Mientras conduce con un CLP de Dakota del Sur, el titular del permiso debe estar acompañado por una persona que posea una CDL válida de la clase apropiada y que esté sentada ¿dónde?","options":["En el asiento delantero junto al conductor","En cualquier lugar de la cabina","En un vehículo de escolta aparte","En la litera"],"explanation":"Un titular de CLP de Dakota del Sur puede operar un CMV solo cuando esté acompañado por una persona que posea una CDL válida de la clase/endosos apropiados y que ocupe el asiento delantero junto al conductor. Fuente: SD Motor Carrier Handbook, Cap. 8, Requisitos de la CDL; 49 CFR 383.25(a)."},"35":{"q":"¿Qué conjunto de documentos debe presentar un solicitante de CDL de Dakota del Sur en una estación de exámenes de conductores para establecer su elegibilidad?","options":["Únicamente una tarjeta del Seguro Social","Comprobante de identidad/presencia legal, número de Seguro Social y residencia en Dakota del Sur","Un pasaporte y una tarjeta de crédito","Un diploma de secundaria y un título de propiedad de un vehículo"],"explanation":"Dakota del Sur requiere comprobante de identidad y presencia legal (fecha de nacimiento), un número de Seguro Social y dos documentos que comprueben la residencia en Dakota del Sur; los documentos deben ser originales, no fotocopias. Fuente: SD DPS Required Driver's Licensing Documents (dps.sd.gov)."},"36":{"q":"La mayoría de los solicitantes de CDL en Dakota del Sur que recibieron su CLP después del 7 de febrero de 2022 deben completar la Capacitación de Conductores de Nivel Inicial (ELDT) de un proveedor que esté listado ¿dónde?","options":["El sitio web de cualquier empresa privada de transporte","El FMCSA Training Provider Registry (TPR)","La Secretaría de Estado de Dakota del Sur","La oficina local del alguacil del condado"],"explanation":"Las normas federales de ELDT adoptadas en Dakota del Sur requieren capacitación teórica y al volante de una entidad que esté en el FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) para los solicitantes que obtuvieron un CLP a partir del 7 de febrero de 2022, antes de presentar el examen práctico de habilidades. Fuente: FMCSA ELDT; información de la CDL de SD DPS."},"37":{"q":"¿Qué categoría de autocertificación médica aplica a un conductor de Dakota del Sur que opera en el comercio interestatal y DEBE cumplir con el requisito federal de la tarjeta médica del DOT?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"explanation":"Non-Excepted Interstate (NI) abarca a los conductores que operan en el comercio interestatal y que deben cumplir con el requisito federal del certificado del examinador médico/físico del DOT. EI es interestatal exceptuado, y NA/EA son categorías intraestatales. Fuente: 49 CFR 383.71; autocertificación de SD DPS Driver Licensing."},"38":{"q":"Un solicitante de CDL o CLP de Dakota del Sur que se autocertifica como Non-Excepted Interstate debe proporcionar un certificado médico de un examinador que esté listado ¿dónde?","options":["El FMCSA National Registry of Certified Medical Examiners","Cualquier clínica de atención urgente sin cita previa","La lista del Departamento de Salud de Dakota del Sur","Un hospital a elección del conductor"],"explanation":"Dakota del Sur requiere que los conductores interestatales (no exceptuados) y los operadores de autobuses escolares obtengan la certificación de un profesional médico que esté listado en el FMCSA National Registry of Certified Medical Examiners, y el certificado debe estar archivado con Driver Licensing. Fuente: SD Motor Carrier Handbook, Cap. 8, Requisitos de la CDL; 49 CFR 391.41."},"39":{"q":"¿Por cuántos años se expide una Licencia de Conductor Comercial (CDL) de Dakota del Sur antes de que deba renovarse?","options":["3 años","4 años","5 años","8 años"],"explanation":"Dakota del Sur expide las CDL por un período de 5 años, después del cual la licencia debe renovarse. (Las licencias no comerciales de SD se expiden por períodos más largos, pero las CDL son de 5 años.) Fuente: SD DPS Driver Licensing fees/information (dps.sd.gov)."},"40":{"q":"En Dakota del Sur, ¿cuál es la concentración máxima de alcohol en la sangre (BAC) con la que una persona puede operar legalmente un vehículo motorizado comercial (CMV)?","options":["0.04 por ciento","0.08 por ciento","0.02 por ciento","0.10 por ciento"],"explanation":"Dakota del Sur sigue el estándar federal para CMV: es ilegal operar un CMV con un BAC de 0.04 por ciento o más, la mitad del límite de 0.08 para conductores no comerciales. Fuente: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Cap. 8 (49 CFR 383.51)."},"41":{"q":"Se descubre a un conductor con CDL de Dakota del Sur operando un CMV con una cantidad detectable de alcohol por debajo de 0.04 por ciento de BAC. ¿Cuál es la consecuencia inmediata?","options":["Puesto fuera de servicio durante 24 horas","Descalificación de la CDL por un año","Descalificación de la CDL por 60 días","Pérdida permanente de la CDL"],"explanation":"En Dakota del Sur, un conductor de CMV con cualquier cantidad detectable de alcohol por debajo de 0.04 por ciento es puesto fuera de servicio durante 24 horas en lugar de ser descalificado. Un BAC de 0.04 o más provoca una descalificación de un año. Fuente: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Cap. 8."},"42":{"q":"Bajo la ley de consentimiento implícito de Dakota del Sur, ¿a qué consiente un conductor al operar cualquier vehículo en una vía pública?","options":["A someterse a pruebas químicas de alcohol o drogas","A portar un certificado de examinador médico","A renunciar al derecho a una audiencia de licencia","A pruebas aleatorias de drogas del empleador"],"explanation":"La ley de consentimiento implícito de Dakota del Sur significa que cualquier persona que conduzca en una vía pública ha consentido a una prueba química de alcohol o drogas. La negativa conlleva sus propias penalidades aunque no se haya consumido alcohol. Fuente: South Dakota CDL Manual; SDCL 32-23-10 (consentimiento implícito)."},"43":{"q":"Para una PRIMERA infracción mayor (como un BAC de 0.04+ en un CMV) que no involucre materiales peligrosos con placas, ¿por cuánto tiempo se descalifica a un titular de CDL de Dakota del Sur?","options":["1 año","60 días","3 años","De por vida"],"explanation":"Una primera infracción mayor en Dakota del Sur resulta en una descalificación mínima de la CDL de un año. El período aumenta a tres años si la infracción ocurrió mientras se transportaban materiales peligrosos con placas. Fuente: South Dakota CDL Manual (49 CFR 383.51)."},"44":{"q":"¿Por cuánto tiempo se descalifica a un conductor con CDL de Dakota del Sur por una PRIMERA infracción mayor cometida mientras transportaba materiales peligrosos que requieren placas?","options":["3 años","1 año","120 días","De por vida"],"explanation":"En Dakota del Sur, la descalificación estándar de un año por una primera infracción mayor aumenta a tres años cuando la infracción ocurre mientras se opera un CMV que transporta materiales peligrosos con placas. Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8 (49 CFR 383.51)."},"45":{"q":"¿Cuál es el período de descalificación en Dakota del Sur por una SEGUNDA infracción mayor que surge de un incidente distinto?","options":["De por vida","10 años","3 años","1 año"],"explanation":"Una segunda infracción mayor (como un segundo DUI en cualquier vehículo, negarse a una prueba, o abandonar la escena) proveniente de un incidente distinto resulta en una descalificación de la CDL de por vida en Dakota del Sur, aunque en algunos casos la reinstalación puede ser posible después de 10 años. Fuente: South Dakota CDL Manual (49 CFR 383.51)."},"46":{"q":"Un conductor con CDL de Dakota del Sur se niega a someterse a una prueba química de alcohol. ¿Cuál es el período mínimo de descalificación?","options":["Al menos 1 año","60 días","90 días","30 días"],"explanation":"Negarse a someterse a las pruebas requeridas de alcohol/drogas se trata como una infracción mayor en Dakota del Sur y resulta en una descalificación de al menos un año, igual que un BAC de 0.04+. Un conductor puede perder la CDL aunque no haya estado bebiendo. Fuente: South Dakota CDL Manual; disposiciones de consentimiento implícito de la SDCL."},"47":{"q":"¿Por cuánto tiempo se descalifica a un conductor con CDL de Dakota del Sur al ser condenado por DOS infracciones de tránsito graves dentro de un período de 3 años?","options":["60 días","30 días","120 días","1 año"],"explanation":"Dos infracciones de tránsito graves en incidentes distintos dentro de tres años resultan en una descalificación de 60 días en Dakota del Sur. Una tercera dentro de tres años agrega 120 días. Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8 (49 CFR 383.51)."},"48":{"q":"¿Por cuánto tiempo se descalifica a un conductor con CDL de Dakota del Sur al ser condenado por TRES infracciones de tránsito graves dentro de un período de 3 años?","options":["120 días","60 días","90 días","1 año"],"explanation":"Una tercera infracción de tránsito grave en incidentes distintos dentro de tres años resulta en una descalificación de 120 días en Dakota del Sur (además de los 60 días por la segunda). Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8."},"49":{"q":"¿Cuál de las siguientes se clasifica como una infracción de tránsito GRAVE para un titular de CDL de Dakota del Sur?","options":["Exceder el límite de velocidad publicado por 15 mph o más","Conducir con un BAC de 0.04 o más","Negarse a una prueba química","Abandonar la escena de un accidente"],"explanation":"En Dakota del Sur, exceder el límite de velocidad por 15 mph o más es una infracción de tránsito grave. Las otras infracciones mencionadas son infracciones MAYORES que conllevan una descalificación de un año o de por vida, no de la categoría de infracción grave. Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8."},"50":{"q":"¿Cuál infracción NO se cuenta entre las infracciones de tránsito graves de Dakota del Sur para fines de la CDL?","options":["Operar un CMV con un BAC de 0.04+","Seguir a otro vehículo demasiado de cerca","Cambio de carril indebido o errático","Conducir un CMV sin poseer una CDL"],"explanation":"Operar un CMV con un BAC de 0.04+ es una infracción MAYOR (descalificación de un año), no una infracción de tránsito grave. Seguir demasiado de cerca, los cambios de carril indebidos y conducir un CMV sin una CDL son infracciones de tránsito graves. Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8."},"51":{"q":"¿Cuál es el período de descalificación por una PRIMERA infracción en un cruce a nivel de ferrocarril y carretera por parte de un conductor con CDL de Dakota del Sur?","options":["60 días","30 días","120 días","1 año"],"explanation":"Una primera infracción en un cruce a nivel de ferrocarril y carretera resulta en una descalificación de 60 días en Dakota del Sur. Una segunda dentro de tres años es de 120 días y una tercera es de un año. Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8 (49 CFR 383.51)."},"52":{"q":"¿Cuál es el período de descalificación por una SEGUNDA infracción en un cruce a nivel de ferrocarril y carretera dentro de 3 años para un conductor con CDL de Dakota del Sur?","options":["120 días","60 días","90 días","1 año"],"explanation":"Una segunda infracción en un cruce a nivel de ferrocarril dentro de tres años resulta en una descalificación de 120 días en Dakota del Sur. Una tercera dentro de tres años resulta en una descalificación de un año. Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8."},"53":{"q":"¿Cuál es el período de descalificación por una TERCERA infracción en un cruce a nivel de ferrocarril y carretera dentro de 3 años en Dakota del Sur?","options":["1 año","120 días","180 días","60 días"],"explanation":"Una tercera infracción en un cruce a nivel de ferrocarril dentro de un período de tres años resulta en una descalificación de la CDL de un año en Dakota del Sur. Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8 (49 CFR 383.51)."},"54":{"q":"¿Cuál es la descalificación mínima por una PRIMERA infracción de una orden de fuera de servicio (out-of-service) por parte de un conductor con CDL de Dakota del Sur (sin hazmat ni pasajeros)?","options":["180 días","90 días","60 días","30 días"],"explanation":"Una primera condena por infringir una orden de fuera de servicio resulta en una descalificación de al menos 180 días (hasta un año) en Dakota del Sur. El mínimo aumenta a 3 años si hubo hazmat/pasajeros involucrados. Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8."},"55":{"q":"Un conductor con CDL de Dakota del Sur comete una SEGUNDA infracción de una orden de fuera de servicio dentro de 10 años (sin hazmat ni pasajeros). ¿Cuál es el período de descalificación?","options":["2 años","1 año","180 días","3 años"],"explanation":"Una segunda infracción de una orden de fuera de servicio en incidentes distintos dentro de 10 años resulta en una descalificación de 2 años en Dakota del Sur. Una tercera dentro de 10 años es de 3 años. Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8 (49 CFR 383.51)."},"56":{"q":"Usar un CMV en la comisión de un delito grave que involucra la fabricación o distribución de una sustancia controlada resulta en ¿qué descalificación en Dakota del Sur?","options":["De por vida sin reinstalación","1 año","3 años","10 años y luego reinstalación"],"explanation":"Usar un CMV para cometer un delito grave que involucra la fabricación, distribución o suministro de una sustancia controlada resulta en una descalificación de la CDL de por vida SIN posibilidad de reinstalación en Dakota del Sur. Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8 (49 CFR 383.51)."},"57":{"q":"Bajo las normas federales aplicadas en Dakota del Sur, ¿cuántas condenas por enviar mensajes de texto mientras se conduce un CMV dentro de 3 años provocan una descalificación de 120 días?","options":["3 o más","2","5","4"],"explanation":"Dos infracciones por enviar mensajes de texto dentro de tres años provocan una descalificación de 60 días y tres o más provocan una descalificación de 120 días para los conductores con CDL de Dakota del Sur. Enviar mensajes de texto mientras se conduce un CMV también es una infracción de tránsito grave. Fuente: South Dakota CDL Manual (49 CFR 392.80 / 383.51)."},"58":{"q":"Para un conductor con CDL de Dakota del Sur, usar un teléfono móvil de mano mientras opera un CMV se describe mejor como ¿qué tipo de infracción?","options":["Una infracción de tránsito grave","Una infracción mayor (descalificación de 1 año)","Una infracción de orden de fuera de servicio","Una infracción de equipo no reportable"],"explanation":"Usar un teléfono móvil de mano mientras se conduce un CMV es una infracción de tránsito grave en Dakota del Sur; dos dentro de 3 años provocan una descalificación de 60 días y tres provocan 120 días. Fuente: South Dakota CDL Manual (49 CFR 392.82 / 383.51)."},"59":{"q":"¿Dentro de cuántos días debe un titular de CDL de Dakota del Sur notificar a su empleador después de ser condenado por una infracción de tránsito (que no sea de estacionamiento) en cualquier vehículo?","options":["30 días","10 días","15 días","60 días"],"explanation":"Dakota del Sur requiere que un titular de CDL notifique a su empleador dentro de los 30 días de una condena por cualquier infracción de tránsito (excepto estacionamiento), en cualquier estado y en cualquier vehículo. Fuente: South Dakota CDL Manual / Motor Carrier Handbook Cap. 8."},"60":{"q":"Según la ley \"Cámbiate de Carril\" (Move Over) de Dakota del Sur (actualizada el 1 de julio de 2025), ¿a qué distancia delante de un vehículo detenido que muestra luces de advertencia ámbar, amarillas o azules debe el conductor comenzar a responder?","options":["100 feet","200 feet","300 feet","500 feet"],"explanation":"La SDCL 32-31-6.1 exige que los conductores tomen medidas al menos 300 feet antes del vehículo. Fuente: SDCL 32-31-6.1; ley Move Over del SDDOT (vigente el 1 de julio de 2025)."},"61":{"q":"En una carretera de varios carriles de Dakota del Sur, ¿qué exige la ley Move Over al acercarse a un vehículo detenido en el acotamiento con las luces de advertencia encendidas?","options":["Detenerse por completo hasta que se apaguen las luces","Cambiarse al carril más alejado del vehículo y avanzar con precaución","Reducir a 30 mph y permanecer en el carril derecho","Tocar el claxon y pasar al límite de velocidad indicado"],"explanation":"En una vía con dos o más carriles en el mismo sentido, la SDCL 32-31-6.1 exige que el conductor se cambie al carril más alejado del vehículo detenido al menos 300 feet antes de él y avance con precaución. Fuente: SDCL 32-31-6.1; SDDOT."},"62":{"q":"En una carretera de dos carriles de Dakota del Sur donde no es posible cambiarse de carril, ¿cuánto debe reducir un conductor su velocidad por debajo del límite indicado, como mínimo, al pasar un vehículo con luces de advertencia en el acotamiento, según la ley Move Over?","options":["Al menos 10 mph por debajo del límite indicado","Al menos 15 mph por debajo del límite indicado","Al menos 20 mph por debajo del límite indicado","Al menos 25 mph por debajo del límite indicado"],"explanation":"En una vía de dos carriles, la SDCL 32-31-6.1 exige reducir a una velocidad de al menos 20 mph menos que el límite indicado (o 5 mph si el límite es de 20 mph o menos). Fuente: SDCL 32-31-6.1; SDDOT."},"63":{"q":"¿Qué categorías de vehículos detenidos están protegidas por la ley ampliada Move Over de Dakota del Sur?","options":["Solo vehículos identificados de las fuerzas del orden","Solo ambulancias y camiones de bomberos","Cualquier vehículo en el acotamiento que muestre luces ámbar, amarillas o azules intermitentes, incluidas grúas, vehículos de mantenimiento y vehículos averiados","Solo vehículos que muestren luces de emergencia rojas y azules"],"explanation":"La ampliación del 1 de julio de 2025 de la SDCL 32-31-6.1 cubre cualquier vehículo en el acotamiento que muestre luces de advertencia ámbar, amarillas o azules intermitentes, incluidas grúas, mantenimiento de carreteras y automovilistas averiados. Fuente: SDCL 32-31-6.1; SDDOT."},"64":{"q":"En una carretera de dos carriles de Dakota del Sur, al encontrarse con un autobús escolar o rebasarlo cuando este tiene sus luces de advertencia ámbar encendidas, ¿a cuánto debe reducir su velocidad un conductor, como máximo?","options":["35 mph","25 mph","20 mph","15 mph"],"explanation":"La SDCL 32-32-6 exige que un automovilista reduzca su velocidad a 15 mph o menos cuando las luces de precaución ámbar de un autobús escolar están encendidas. Fuente: SDCL 32-32-6."},"65":{"q":"Cuando un autobús escolar de Dakota del Sur está detenido en una vía de dos carriles con sus luces ROJAS intermitentes encendidas, ¿a qué distancia mínima del autobús debe detenerse un conductor que se acerca?","options":["10 feet","15 feet","20 feet","30 feet"],"explanation":"La SDCL 32-32-6 exige que los automovilistas detengan el vehículo por completo al menos a 15 feet del autobús escolar y permanezcan detenidos hasta que las luces rojas dejen de parpadear. Fuente: SDCL 32-32-6."},"66":{"q":"Según la ley de Dakota del Sur, ¿en qué tipo de vía puede un conductor que circula en sentido CONTRARIO continuar sin detenerse ante un autobús escolar que está detenido con las luces rojas intermitentes?","options":["Cualquier carretera con una línea central pintada","Una carretera con dos o más carriles de circulación en cada sentido","Cualquier vía con un límite indicado superior a 45 mph","Solo una autopista interestatal con acceso totalmente controlado"],"explanation":"La SDCL 32-32-6 exime de detenerse ante un autobús escolar con luces rojas intermitentes a un conductor que se acerca en sentido contrario en una carretera con dos o más carriles de circulación en cada sentido. Fuente: SDCL 32-32-6."},"67":{"q":"¿A qué distancia antes de una parada debe el conductor de un autobús escolar de Dakota del Sur activar las luces de precaución ámbar?","options":["No menos de 100 ni más de 300 feet","No menos de 200 ni más de 400 feet","No menos de 300 ni más de 500 feet","No menos de 500 ni más de 700 feet"],"explanation":"La SDCL 32-32-5.2 exige que las luces de precaución ámbar estén encendidas no menos de 300 feet ni más de 500 feet antes del punto donde se recoge o deja a los alumnos. Fuente: SDCL 32-32-5.2."},"68":{"q":"En las autopistas interestatales rurales de Dakota del Sur señalizadas al máximo, ¿cuál es el límite de velocidad para un camión con remolque (tractor-trailer) en comparación con un automóvil de pasajeros?","options":["Camiones 65 mph; automóviles 80 mph","Camiones 70 mph; automóviles 75 mph","Camiones 75 mph; automóviles 80 mph","Camiones 80 mph; automóviles 80 mph (el mismo límite)"],"explanation":"Dakota del Sur establece 80 mph en la mayoría de las interestatales rurales y aplica el mismo límite a camiones y automóviles; no hay un límite de velocidad más bajo separado para camiones. Fuente: SDCL cap. 32-25; reglamentos de velocidad del SDDOT."},"69":{"q":"En Dakota del Sur, un Vehículo de Combinación Más Larga (LCV) que circula por la interestatal no puede exceder qué velocidad máxima?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"La Regla Administrativa de Dakota del Sur 70:03:01:61 limita los Vehículos de Combinación Más Larga a un máximo de 65 mph en las autopistas interestatales, incluso donde el límite indicado sea mayor. Fuente: ARSD 70:03:01:61."},"70":{"q":"En Dakota del Sur, cuando un vehículo con materiales peligrosos que lleva carteles (placards) se acerca a un cruce ferroviario donde debe detenerse, ¿dónde debe detenerse?","options":["A una distancia de 5 a 25 feet del riel más cercano","A una distancia de 15 a 50 feet del riel más cercano","A una distancia de 25 a 75 feet del riel más cercano","A una distancia de 50 a 100 feet del riel más cercano"],"explanation":"Un vehículo con carteles debe detenerse a una distancia de 15 a 50 feet del riel más cercano, y luego mirar y escuchar antes de cruzar. Fuente: Manual CDL de SD; 49 CFR 392.10."},"71":{"q":"Al cruzar vías ferroviarias en Dakota del Sur, ¿qué NO debe hacer el conductor de un autobús o de un vehículo con carteles?","options":["Mirar y escuchar para detectar trenes","Cambiar de marcha mientras está sobre las vías","Usar una marcha baja para mantener la potencia","Asegurarse de que haya espacio para librar las vías"],"explanation":"Los conductores no deben cambiar de marcha mientras cruzan las vías, para evitar quedarse parados en el cruce; deben cruzar en una marcha que no necesite cambiarse. Fuente: Manual CDL de SD; 49 CFR 392.10/392.11."},"72":{"q":"¿En cuál cruce ferroviario un conductor de autobús de Dakota del Sur generalmente NO está obligado a hacer la parada obligatoria?","options":["Un cruce controlado por un oficial de policía o una persona que dirige el tráfico para que pase","Un cruce de varias vías en campo abierto","Un cruce sin barreras automáticas","Un cruce en una pendiente pronunciada"],"explanation":"La parada obligatoria no es necesaria cuando un oficial de policía o una persona dirige el tráfico, en un cruce exento/abandonado o de ramal industrial, o cuando un semáforo en verde controla el cruce. Fuente: Manual CDL de SD; 49 CFR 392.10."},"73":{"q":"¿Cuántos triángulos reflectantes de advertencia debe llevar y colocar un conductor comercial de Dakota del Sur cuando se detiene al costado de la vía?","options":["Un triángulo","Dos triángulos","Tres triángulos","Cuatro triángulos"],"explanation":"Un CMV debe llevar y desplegar tres triángulos reflectantes (o dispositivos equivalentes), colocados dentro de los 10 minutos posteriores a la detención. Fuente: Manual CDL de SD; 49 CFR 392.22."},"74":{"q":"En una carretera de dos carriles y doble sentido de Dakota del Sur, ¿dónde deben colocarse los tres triángulos de advertencia cuando un camión está detenido?","options":["Los tres a unos 100 feet detrás del vehículo","A unos 10 feet, 100 feet y 200 feet detrás del vehículo","Dentro de los 10 feet del lado del tráfico, y a unos 100 feet adelante y 100 feet detrás del vehículo","A unos 50 feet adelante, al lado y detrás del vehículo"],"explanation":"En una vía de dos carriles y doble sentido, coloque un triángulo dentro de los 10 feet del lado del tráfico, uno a unos 100 feet detrás y uno a unos 100 feet adelante del vehículo. Fuente: Manual CDL de SD; 49 CFR 392.22."},"75":{"q":"En una carretera dividida o de un solo sentido de Dakota del Sur, ¿dónde se colocan los tres triángulos de advertencia detrás de un camión detenido?","options":["A 10, 50 y 100 feet","A 10, 100 y 200 feet","A 25, 100 y 300 feet","A 50, 150 y 250 feet"],"explanation":"En una vía dividida o de un solo sentido, coloque los triángulos a unos 10 feet, 100 feet y 200 feet en dirección al tráfico que se aproxima, detrás del vehículo. Fuente: Manual CDL de SD; 49 CFR 392.22."},"76":{"q":"Según la regla de Dakota del Sur de mantenerse a la derecha, ¿cuándo debe un conductor usar el carril o la parte derecha de la vía?","options":["Solo en autopistas interestatales","Cuando circula más despacio que la velocidad normal del tráfico, salvo al rebasar o cuando el carril derecho es impracticable","Solo entre el atardecer y el amanecer","Solo cuando un camión lo sigue"],"explanation":"La SDCL 32-26-1 exige conducir por la mitad derecha de la vía y, para el tráfico más lento de lo normal, mantenerse a la derecha salvo al rebasar o donde usar el carril derecho sea impracticable. Fuente: SDCL 32-26-1."},"77":{"q":"¿Cuál es el ancho máximo legal de un vehículo en Dakota del Sur antes de que se requiera un permiso para carga sobredimensionada?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"El límite de ancho legal de Dakota del Sur sin permiso es de 8 feet 6 inches (102 inches); cualquier cosa más ancha requiere un permiso para carga sobredimensionada. Fuente: reglas de permisos para sobredimensionados del SDDOT/Patrulla de Carreteras de SD; SDCL cap. 32-22."},"78":{"q":"En Dakota del Sur, ¿durante qué horario puede generalmente circular el titular de un permiso para carga sobredimensionada (ancho no divisible)?","options":["24 horas al día, cualquier día","Solo de lunes a viernes, únicamente con luz de día","Desde media hora antes del amanecer hasta media hora después del atardecer, incluidos los fines de semana","Solo entre las 9 a.m. y las 4 p.m. en días laborables"],"explanation":"Las cargas sobredimensionadas pueden circular desde media hora antes del amanecer hasta media hora después del atardecer, incluidos sábado y domingo; las cargas que solo tienen sobrepeso pueden circular de forma continua. Fuente: reglas de permisos para sobredimensionados del SDDOT/Patrulla de Carreteras de SD."},"79":{"q":"¿Qué agencia de Dakota del Sur emite las Licencias de Conducir Comerciales?","options":["El Departamento de Seguridad Pública de Dakota del Sur, Programa de Licencias de Conducir","El Departamento de Transporte de Dakota del Sur","La oficina del alguacil del condado donde reside el solicitante","La Administración Federal de Seguridad de Autotransportes (FMCSA)"],"explanation":"En Dakota del Sur, las CDL son emitidas por el Department of Public Safety a través de su Driver Licensing Program (Pierre, SD). El SD DOT se encarga de los permisos y las carreteras, no de las licencias de conducir. Fuente: SD DPS Driver Licensing / SD Truck Information (sdtruckinfo.sd.gov), Motor Carrier Handbook Cap. 8."},"80":{"q":"¿Cuál es la edad mínima para obtener una CDL de Dakota del Sur para conducir únicamente en comercio intraestatal (dentro de Dakota del Sur)?","options":["16","18","19","21"],"explanation":"Dakota del Sur permite una CDL a los 18 años para el comercio intraestatal; el comercio interestatal (cruzando líneas estatales) requiere tener 21 años. Fuente: SD Motor Carrier Handbook Cap. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"81":{"q":"¿Cuál es la edad mínima para obtener una CDL de Dakota del Sur para el comercio interestatal (conducir cruzando líneas estatales)?","options":["18","19","20","21"],"explanation":"Conducir en comercio interestatal requiere una edad mínima de 21 años en Dakota del Sur; los conductores de 18 a 20 años están limitados a operaciones intraestatales. Fuente: SD Motor Carrier Handbook Cap. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"82":{"q":"¿Cuánto tiempo es válido un Permiso de Aprendiz Comercial (CLP) de Dakota del Sur?","options":["30 días","6 meses","1 año","2 años"],"explanation":"Un CLP de Dakota del Sur se emite por un período de un año para la capacitación práctica al volante en vías públicas. Fuente: SD Motor Carrier Handbook Cap. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"83":{"q":"En Dakota del Sur, ¿cuánto tiempo después de emitido un Permiso de Aprendiz Comercial debe esperar un solicitante antes de presentar el examen de habilidades de la CDL?","options":["No se requiere ningún período de espera","Al menos 7 días","Al menos 14 días","Al menos 30 días"],"explanation":"Hay un período de espera de 14 días entre la fecha en que se emite el CLP y la fecha en que se puede realizar el examen de habilidades. Fuente: SD Motor Carrier Handbook Cap. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov); refleja la norma federal 49 CFR 383.25."},"84":{"q":"¿Entre cuántas categorías de autocertificación debe elegir un solicitante de CDL de Dakota del Sur respecto al tipo de comercio y los requisitos médicos?","options":["Dos","Tres","Cuatro","Cinco"],"explanation":"Hay cuatro categorías de autocertificación: Interestatal No Exento (NI), Interestatal Exento (EI), Intraestatal No Exento (NA) e Intraestatal Exento (EA). Fuente: SD DPS CDL Medical Certification; 49 CFR 383.71."},"85":{"q":"Un conductor de Dakota del Sur que opera cruzando líneas estatales y está obligado a cumplir los estándares federales de calificación física del DOT se autocertifica en qué categoría?","options":["Interestatal No Exento (NI)","Interestatal Exento (EI)","Intraestatal No Exento (NA)","Intraestatal Exento (EA)"],"explanation":"Interestatal No Exento (NI) significa que el conductor opera en comercio interestatal y debe cumplir los requisitos del certificado médico federal del DOT (un certificado vigente del examinador médico). Fuente: SD DPS CDL Medical Certification; 49 CFR 383.71."},"86":{"q":"Cuando un solicitante de CDL de Dakota del Sur se autocertifica como Interestatal No Exento, ¿qué documento debe mantenerse archivado con el estado para seguir siendo válido?","options":["Una exención de visión de un oftalmólogo","Un certificado vigente del examinador médico del DOT","Una declaración jurada firmada por el empleador","Una bitácora de conducción notariada"],"explanation":"Los conductores no exentos deben mantener un certificado válido del examinador médico (tarjeta médica del DOT) archivado con el Driver Licensing Program; sin él, la CDL se degrada. Fuente: SD DPS CDL Medical Certification."},"87":{"q":"¿Quién está autorizado para realizar el examen físico del certificado médico del DOT de un titular de CDL de Dakota del Sur?","options":["Cualquier médico con licencia que el conductor elija","Un examinador médico incluido en el National Registry of Certified Medical Examiners de la FMCSA","Solo un médico empleado por el SD Department of Public Safety","Un enfermero en cualquier clínica de atención de urgencias"],"explanation":"El examen debe ser realizado por un profesional médico incluido en el National Registry of Certified Medical Examiners de la FMCSA. Fuente: SD Motor Carrier Handbook Cap. 8, CDL Qualifications (sdtruckinfo.sd.gov); National Registry (nationalregistry.fmcsa.dot.gov)."},"88":{"q":"Después del examen físico del DOT de un titular de CDL de Dakota del Sur, ¿cómo llega generalmente el certificado del examinador médico al Driver Licensing Program del estado?","options":["El conductor debe entregarlo en mano en un juzgado","El examinador lo envía electrónicamente al Driver Licensing dentro de los 2 días hábiles a través del National Registry","Solo lo envía por correo el empleador del conductor","Es automáticamente válido sin ninguna presentación"],"explanation":"Los examinadores médicos certificados envían el certificado electrónicamente al Driver Licensing de Dakota del Sur dentro de los 2 días hábiles a través del National Registry de la FMCSA; los conductores también pueden enviar una copia por fax, correo electrónico o correo postal. Fuente: SD DPS / SD Truck Information (sdtruckinfo.sd.gov)."},"89":{"q":"¿Cuál es el período máximo durante el cual puede ser válido el certificado del examinador médico del DOT para un titular de CDL de Dakota del Sur?","options":["6 meses","1 año","2 años","5 años"],"explanation":"Un certificado del examinador médico es válido por hasta dos años, y puede emitirse por un período más corto según el estado de salud del conductor. Fuente: SD Motor Carrier Handbook Cap. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 391.43."},"90":{"q":"¿Qué examen de conocimientos debe aprobar TODO solicitante de CDL de Dakota del Sur, sin importar la clase de vehículo o los endosos?","options":["El examen de frenos de aire","El examen de conocimientos generales","El examen de materiales peligrosos","El examen de dobles/triples"],"explanation":"El examen de conocimientos generales lo presentan todos los solicitantes; los demás exámenes solo se requieren para vehículos o endosos específicos. Fuente: SD Motor Carrier Handbook Cap. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"91":{"q":"El examen de habilidades de la CDL de Dakota del Sur consta de cuáles tres partes, presentadas en orden?","options":["Examen escrito, prueba de visión y examen de manejo","Inspección previaje, control básico del vehículo y manejo en carretera","Examen de frenos de aire, examen de acoplamiento y examen de retroceso","Examen de conocimientos, examen en simulador y examen de manejo nocturno"],"explanation":"El examen de habilidades tiene tres partes: la inspección previaje (del vehículo), las maniobras básicas de control del vehículo y el examen de manejo en carretera. Fuente: SD Motor Carrier Handbook Cap. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"92":{"q":"Durante la parte de control básico del vehículo del examen de habilidades de la CDL de Dakota del Sur, ¿qué se le pide principalmente demostrar al solicitante?","options":["Recitar todo el manual de la CDL de memoria","Mover el vehículo hacia adelante, hacia atrás y girarlo dentro de un área definida marcada con conos","Reparar un sistema de frenos","Cargar y asegurar carga peligrosa"],"explanation":"El control básico del vehículo evalúa la capacidad del conductor para mover el vehículo hacia adelante y hacia atrás y girarlo dentro de un área definida marcada con conos o barreras. Fuente: SD Motor Carrier Handbook Cap. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"93":{"q":"En la parte de inspección previaje del examen de habilidades de la CDL de Dakota del Sur, ¿qué debe hacer el solicitante?","options":["Manejar entre el tráfico de la carretera","Identificar los componentes del vehículo que inspeccionaría y explicar qué está revisando y por qué","Demostrar únicamente el estacionamiento en paralelo","Aprobar un examen escrito de materiales peligrosos por separado"],"explanation":"La inspección previaje requiere que el conductor demuestre la capacidad de evaluar la seguridad del vehículo, identificando los elementos de la inspección y explicando qué revisaría y por qué. Fuente: SD Motor Carrier Handbook Cap. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"94":{"q":"En Dakota del Sur, si un solicitante reprueba un examen de conocimientos o de habilidades de la CDL, ¿cuándo es lo más pronto que puede volver a examinarse?","options":["Inmediatamente, el mismo día","No antes del siguiente día hábil","Después de un período de espera de 30 días","Después de 6 meses completos"],"explanation":"Si reprueba cualquiera de los exámenes, no puede volver a examinarse antes del siguiente día hábil; puede esperar más tiempo si desea estudiar o practicar más. Fuente: SD Motor Carrier Handbook Cap. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"95":{"q":"En Dakota del Sur, ¿cuántas oportunidades para examinarse cubre cada cuota de examen dentro de un período de seis meses?","options":["Una","Dos","Tres","Ilimitadas"],"explanation":"Se permite a los solicitantes tres oportunidades para examinarse por cada cuota pagada dentro de un período de seis meses. Los montos exactos de las cuotas pueden cambiar, por lo que conviene basarse en las reglas del proceso y no en las cifras en dólares. Fuente: SD Motor Carrier Handbook Cap. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)."},"96":{"q":"Según la norma federal de Capacitación de Conductores de Nivel Inicial (ELDT) que Dakota del Sur aplica, ¿dónde debe completar un solicitante de CDL por primera vez la capacitación requerida?","options":["Cualquier curso en línea de su elección","Un proveedor de capacitación incluido en el Training Provider Registry (TPR) de la FMCSA","Un curso ofrecido únicamente por el SD DPS","No se requiere capacitación formal antes del examen"],"explanation":"La ELDT (vigente el 7 de febrero de 2022) exige que los solicitantes de nivel inicial completen capacitación teórica y práctica al volante con un proveedor incluido en el Training Provider Registry de la FMCSA antes de presentar el examen de habilidades de la CDL (o, en el caso de HazMat, el examen de conocimientos). Fuente: norma ELDT de la FMCSA (49 CFR Part 380), aplicada por el SD DPS."},"97":{"q":"¿A qué solicitantes se aplica el requisito federal de ELDT al obtener una CDL de Dakota del Sur?","options":["Solo a conductores mayores de 65 años","A solicitantes que obtienen por primera vez una CDL de Clase A o B, que mejoran de clase, o que buscan por primera vez un endoso de autobús escolar, de pasajeros o de HazMat","Solo a solicitantes que transfieren su licencia desde otro estado","Solo a conductores que renuevan una CDL existente"],"explanation":"La ELDT se aplica a quienes obtienen por primera vez una CDL de Clase A o B, mejoran de clase (p. ej., de B a A), u obtienen por primera vez un endoso de autobús escolar, de pasajeros o de materiales peligrosos; es un requisito único, no para las renovaciones de rutina. Fuente: norma ELDT de la FMCSA (49 CFR Part 380), aplicada por el SD DPS."},"98":{"q":"¿Cuánto tiempo es válida una Licencia de Conducir Comercial de Dakota del Sur antes de que deba renovarse?","options":["1 año","2 años","4 años","5 años"],"explanation":"Una CDL de Dakota del Sur es válida por cinco años y vence el día del cumpleaños del titular; los titulares pueden renovarla hasta 180 días antes del vencimiento, generalmente en persona en una estación de exámenes del DPS con una prueba de visión. Fuente: SD DPS Driver Licensing (orientación sobre renovaciones)."}},"hi":{"0":{"q":"बिना परमिट के साउथ डकोटा के राजमार्गों पर किसी वाहन और उसके भार की अधिकतम कानूनी चौड़ाई कितनी होती है?","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"साउथ डकोटा किसी भी वाहन की, उसके भार सहित, अधिकतम चौड़ाई को 102 inches (8 feet 6 inches) तक सीमित करता है। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov।"},"1":{"q":"साउथ डकोटा के राजमार्गों पर किसी वाहन की, उसके भार सहित, अधिकतम कानूनी ऊँचाई कितनी होती है?","options":["13 feet 6 inches","13 feet","14 feet","15 feet"],"explanation":"साउथ डकोटा किसी भी वाहन की, भार सहित, अधिकतम ऊँचाई 14 feet निर्धारित करता है। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov।"},"2":{"q":"साउथ डकोटा में, गांठ बंधे हुए घास (baled hay) का भार ढोने वाला वाहन कानूनी रूप से अधिकतम कितनी ऊँचाई तक पहुँच सकता है?","options":["14 feet","14 feet 6 inches","15 feet","16 feet"],"explanation":"हालाँकि सामान्य ऊँचाई सीमा 14 feet है, साउथ डकोटा गांठ बंधे हुए घास के भार वाले वाहन को 15 feet तक ऊँचा होने की अनुमति देता है। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov।"},"3":{"q":"साउथ डकोटा के राजमार्गों पर एक single axle पर अधिकतम कानूनी भार कितना होता है?","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"साउथ डकोटा एक single axle को 20,000 pounds तक सीमित करता है, जो संघीय मानक के अनुरूप है। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov।"},"4":{"q":"साउथ डकोटा के राजमार्गों पर एक tandem axle समूह पर अधिकतम कानूनी भार कितना होता है?","options":["32,000 pounds","33,000 pounds","34,000 pounds","36,000 pounds"],"explanation":"साउथ डकोटा एक tandem axle समूह को 34,000 pounds तक सीमित करता है, जो संघीय मानक के अनुरूप है। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov।"},"5":{"q":"विशेष परमिट के बिना, साउथ डकोटा के Interstate राजमार्गों पर अनुमत अधिकतम सकल वाहन भार (gross vehicle weight) कितना होता है?","options":["73,280 pounds","80,000 pounds","90,000 pounds","105,500 pounds"],"explanation":"साउथ डकोटा के Interstate राजमार्गों पर अधिकतम सकल भार 80,000 pounds है, जब तक कि वाहन के पास वार्षिक Over 80,000 Pounds on Interstate परमिट न हो। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov।"},"6":{"q":"साउथ डकोटा में truck tractor-semitrailer संयोजन में चलने वाले एक semitrailer की अधिकतम लंबाई कितनी होती है?","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"साउथ डकोटा truck tractor-semitrailer संयोजन में चलाए जाने पर semitrailer को 53 feet तक की लंबाई की अनुमति देता है। स्रोत: SDCL 32-22-8.1 (Length limitations on trailers and semitrailers)।"},"7":{"q":"साउथ डकोटा में ढोए जा रहे भार के लिए, भार वाहन के पिछले हिस्से से कितनी दूरी तक आगे निकल सकता है?","options":["Not more than 3 feet","Not more than 4 feet","Not more than 6 feet","Not more than 8 feet"],"explanation":"भार या उसके पीछे हटने योग्य विस्तार वाहन के पिछले bumper, bed, या body से 4 feet से अधिक आगे नहीं निकल सकते। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov।"},"8":{"q":"साउथ डकोटा में, भार को ढोने वाले वाहन के अगले हिस्से से कितनी दूरी तक भार आगे निकल सकता है?","options":["Not more than 2 feet","Not more than 3 feet","Not more than 4 feet","Not more than 5 feet"],"explanation":"भार वाहन के अगले bumper, bed, या body से 3 feet से अधिक आगे नहीं निकल सकता। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov।"},"9":{"q":"साउथ डकोटा में steering axle के टायर द्वारा वहन किया जा सकने वाला अधिकतम भार, टायर की चौड़ाई के प्रति इंच के रूप में व्यक्त, कितना होता है?","options":["400 pounds per inch","500 pounds per inch","600 pounds per inch","650 pounds per inch"],"explanation":"साउथ डकोटा steering axle और dual-tire axle भार को टायर की चौड़ाई के 600 pounds per inch तक सीमित करता है। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov।"},"10":{"q":"steering या dual-tire axle के अलावा अन्य axle पर लगे टायरों के लिए, साउथ डकोटा की टायर चौड़ाई के प्रति इंच अधिकतम टायर भार सीमा क्या है?","options":["450 pounds per inch","500 pounds per inch","550 pounds per inch","600 pounds per inch"],"explanation":"साउथ डकोटा steering और dual-tire axle के अलावा अन्य axle पर लगे टायरों को टायर की चौड़ाई के 500 pounds per inch तक सीमित करता है। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov।"},"11":{"q":"साउथ डकोटा axle-समूह के भार को सीमित करने के लिए संघीय Bridge Gross Weight Formula का उपयोग करता है। यह formula किन कारकों के आधार पर अधिकतम भार निर्धारित करता है?","options":["केवल वाहन पर axle की कुल संख्या","किसी समूह के अंतिम axle के बीच की दूरी और उस समूह में axle की संख्या","वाहन का पंजीकृत भार और इंजन की horsepower","टायर की चौड़ाई और राजमार्ग की निर्धारित गति सीमा"],"explanation":"साउथ डकोटा संघीय Bridge Formula W = 500[(L x N)/(N-1) + 12N + 36] लागू करता है, जहाँ L किसी समूह के अंतिम axle के बीच की दूरी है और N उस समूह में axle की संख्या है। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov।"},"12":{"q":"एक साउथ डकोटा कृषि उत्पादक जो काटी गई फसल को खेत के 50 miles के भीतर (Interstate पर नहीं) ढो रहा है, उसे कानूनी सीमाओं से कितनी भार सहनशीलता (weight tolerance) की अनुमति है?","options":["कानूनी सीमाओं से 5 percent अधिक","कानूनी सीमाओं से 10 percent अधिक","कानूनी सीमाओं से 15 percent अधिक","कोई सहनशीलता अनुमत नहीं है"],"explanation":"साउथ डकोटा काटी गई फसल को काटे गए खेत के 50 miles के भीतर ढोते समय कानूनी भार सीमाओं से 10 percent तक अधिक की अनुमति देता है, सिवाय Interstate प्रणाली के। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov।"},"13":{"q":"साउथ डकोटा कुछ farm storage और पशुधन ढुलाई के लिए कानूनी सीमाओं से 5 percent भार सहनशीलता की अनुमति देता है। इस पर कौन सी दूरी और सड़क प्रतिबंध लागू होता है?","options":["लोडिंग के 25 miles के भीतर, Interstate सहित","लोडिंग के 50 miles के भीतर, परन्तु Interstate पर नहीं","लोडिंग के 100 miles के भीतर, Interstate सहित","राज्य में कहीं भी, परन्तु Interstate पर नहीं"],"explanation":"farm storage तक ढुलाई या पशुधन के लिए 5 percent सहनशीलता लोडिंग स्थल के 50 miles के भीतर लागू होती है और Interstate प्रणाली पर अनुमत नहीं है (और spring load restrictions के दौरान इसे बाहर रखा गया है)। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov।"},"14":{"q":"साउथ डकोटा के गैर-Interstate राजमार्गों पर, पर्याप्त axle वाले एक उचित रूप से कॉन्फ़िगर किए गए Longer Combination Vehicle द्वारा परमिट के माध्यम से अधिकतम सकल भार कितना पहुँच सकता है?","options":["80,000 pounds","105,500 pounds","129,000 pounds","164,000 pounds"],"explanation":"साउथ डकोटा कुछ Longer Combination Vehicles को, जिनमें पर्याप्त axle हों, गैर-Interstate सड़कों पर 129,000 pounds तक के सकल भार की अनुमति देता है, बशर्ते axle, टायर, और bridge formula सीमाएँ पूरी हों। स्रोत: SDCL 32-22-16/32-22-16.1 और ARSD 70:03:01:61।"},"15":{"q":"oversize/overweight वाहन परमिट के लिए आवेदन करने और प्राप्त करने के लिए कौन सी साउथ डकोटा ऑनलाइन प्रणाली का उपयोग किया जाता है?","options":["The IRP Clearinghouse","The SDAPS Permitting System","The FMCSA Portal","The UCR National Registry"],"explanation":"साउथ डकोटा में oversize और overweight परमिट SDAPS (South Dakota Automated Permitting System) ऑनलाइन portal के माध्यम से प्राप्त किए जाते हैं। स्रोत: SD Truck Information Permitting pages, sdtruckinfo.sd.gov; SDAPS at sdaps.sd.gov।"},"16":{"q":"साउथ डकोटा में राज्य राजमार्गों पर किसी भार के लिए राज्य का oversize/overweight परमिट आम तौर पर कब आवश्यक होता है?","options":["केवल जब माल खतरनाक सामग्री (hazardous material) हो","जब एक अविभाज्य (non-divisible) भार का परिवहन किया जाए जो आकार, भार, या दोनों सीमाओं से अधिक हो","26,001 pounds GVWR से अधिक किसी भी वाणिज्यिक वाहन के लिए","केवल जब साउथ डकोटा में राज्य की सीमा पार की जाए"],"explanation":"किसी ऐसे वाहन की राज्य राजमार्गों पर आवाजाही के लिए परमिट आवश्यक है जो एक अविभाज्य भार का परिवहन कर रहा हो और जो कानूनी आकार, भार, या आकार-और-भार सीमाओं से अधिक हो। स्रोत: SD Truck Information Permitting pages, sdtruckinfo.sd.gov।"},"17":{"q":"साउथ डकोटा में Over 80,000 Pounds on Interstate परमिट अतिरिक्त सकल भार की अनुमति देता है, परन्तु वाहन को फिर भी निम्न में से किससे अधिक नहीं होना चाहिए?","options":["अपने कानूनी axle भार, कानूनी टायर भार, या Bridge Formula भार से","55 miles per hour की गति से","53 feet की कुल लंबाई से","केवल दिन के उजाले के घंटों में यात्रा से"],"explanation":"Over 80,000 Pounds on Interstate परमिट किसी वाहन को अपने कानूनी axle भार, कानूनी टायर भार, या Bridge Gross Weight Formula द्वारा अनुमत भार से अधिक होने की अनुमति नहीं देता। स्रोत: SD Truck Information Permitting pages, sdtruckinfo.sd.gov; SDCL 32-22-42।"},"18":{"q":"साउथ डकोटा में, tractor-semitrailer संयोजन पर लागू होने वाली लंबाई सीमा कुल लंबाई के बजाय trailer की लंबाई से मापी जाती है। एक semitrailer-trailer संयोजन के लिए (truck-tractor को छोड़कर), अधिकतम संयुक्त लंबाई कितनी होती है?","options":["65 feet, जिसमें कोई भी इकाई 28.5 feet से अधिक न हो","75 feet, जिसमें कोई भी इकाई 40 feet से अधिक न हो","81.5 feet, जिसमें कोई भी इकाई 45 feet से अधिक न हो","85 feet, जिसमें कोई भी इकाई 48 feet से अधिक न हो"],"explanation":"एक semitrailer-semitrailer या semitrailer-trailer संयोजन (truck-tractor को छोड़कर) 81 feet 6 inches से अधिक नहीं हो सकता, बशर्ते कोई भी इकाई 45 feet से अधिक न हो। स्रोत: SDCL 32-22-8.1।"},"19":{"q":"साउथ डकोटा की farm machinery छूट के तहत, farm machinery चलाने वाला एक किसान दिन के उजाले के घंटों में 102-inch चौड़ाई सीमा से अधिक हो सकता है, सिवाय किन सड़कों पर?","options":["सभी पक्की (paved) राज्य राजमार्गों पर","Interstate राजमार्गों पर","काउंटी की कंकड़ (gravel) वाली सड़कों पर","शहर की सीमा के भीतर की सड़कों पर"],"explanation":"किसान द्वारा संचालित farm machinery की दिन के उजाले के घंटों में कोई चौड़ाई सीमा नहीं होती, सिवाय Interstate राजमार्गों के, जहाँ मानक सीमाएँ लागू होती हैं। स्रोत: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov।"},"20":{"q":"साउथ डकोटा में, INTERSTATE वाणिज्य में एक वाणिज्यिक मोटर वाहन (commercial motor vehicle) चलाने के लिए CDL प्राप्त करने की न्यूनतम आयु क्या है?","options":["18 years old","19 years old","21 years old","25 years old"],"explanation":"साउथ डकोटा संघीय नियम का पालन करता है: interstate वाणिज्य के लिए CDL प्राप्त करने हेतु चालक की आयु कम से कम 21 वर्ष होनी चाहिए। 18-20 वर्ष के चालकों को केवल intrastate संचालन के लिए CDL जारी किया जा सकता है। स्रोत: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 391.11।"},"21":{"q":"एक साउथ डकोटा आवेदक जो 18 से 20 वर्ष का है, उसे CDL जारी किया जा सकता है, परन्तु यह किस प्रकार के संचालन तक सीमित होता है?","options":["केवल intrastate वाणिज्य (साउथ डकोटा के भीतर)","केवल interstate वाणिज्य","केवल farm वाहन","केवल दिन के समय की ड्राइविंग"],"explanation":"साउथ डकोटा 18-20 वर्ष की आयु के आवेदकों को केवल intrastate वाणिज्य (साउथ डकोटा के भीतर ड्राइविंग) के लिए वैध CDL प्राप्त करने की अनुमति देता है। Interstate संचालन के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov)।"},"22":{"q":"साउथ डकोटा के CDL वर्गीकरण के तहत, कौन सा संयोजन CLASS A लाइसेंस को परिभाषित करता है?","options":["26,000 pounds से अधिक GVWR वाला कोई भी एकल वाहन","26,000 pounds से अधिक GCWR वाला वाहनों का कोई भी संयोजन जहाँ खींची गई इकाई का GVWR 10,000 pounds से अधिक हो","खतरनाक सामग्री के लिए placard लगा कोई भी वाहन","16 या अधिक यात्रियों को ले जाने के लिए डिज़ाइन किया गया कोई भी वाहन"],"explanation":"साउथ डकोटा Class A को वाहनों के किसी भी ऐसे संयोजन के रूप में परिभाषित करता है जिसका Gross Combination Weight Rating (GCWR) 26,000 lbs से अधिक हो, बशर्ते खींचे गए वाहन का GVWR 10,000 lbs से अधिक हो। स्रोत: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov)।"},"23":{"q":"साउथ डकोटा CLASS B वाणिज्यिक चालक लाइसेंस को कैसे परिभाषित करता है?","options":["26,000 pounds से अधिक GCWR वाला एक संयोजन जो 10,000 pounds से अधिक की इकाई खींच रहा हो","26,000 pounds से अधिक GVWR वाला एक एकल वाहन, या ऐसा वाहन जो 10,000 pounds से अधिक की इकाई न खींच रहा हो","खतरनाक अपशिष्ट (hazardous waste) ले जाने वाला कोई भी वाहन","10,000 pounds से कम GVWR वाला कोई भी वाहन"],"explanation":"साउथ डकोटा Class B को किसी भी ऐसे एकल वाहन के रूप में परिभाषित करता है जिसका GVWR 26,000 lbs से अधिक हो, या ऐसा कोई वाहन जो 10,000 lbs GVWR से अधिक न होने वाले वाहन को खींच रहा हो। स्रोत: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov)।"},"24":{"q":"साउथ डकोटा में, एक CLASS C CDL ऐसे वाहन पर लागू होता है जो Class A या B को पूरा नहीं करता परन्तु या तो खतरनाक सामग्री के लिए placard लगा हो या कितने लोगों को ले जाने के लिए डिज़ाइन किया गया हो?","options":["8 या अधिक, चालक सहित","12 या अधिक, चालक सहित","16 या अधिक, चालक सहित","24 या अधिक, चालक सहित"],"explanation":"साउथ डकोटा Class C को एक एकल वाहन या संयोजन के रूप में परिभाषित करता है जो Class A या B को पूरा नहीं करता और जिस पर या तो खतरनाक सामग्री के लिए placard लगाना आवश्यक हो या जो 16 या अधिक यात्रियों, चालक सहित, को ले जाने के लिए डिज़ाइन किया गया हो। स्रोत: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov)।"},"25":{"q":"साउथ डकोटा किसी ऐसे चालक के CDL पर कौन सा endorsement कोड लगाता है जो placard लगी खतरनाक सामग्री (HAZARDOUS MATERIALS) ढोता है (tank में नहीं)?","options":["N","T","H","P"],"explanation":"साउथ डकोटा placard लगी खतरनाक सामग्री के परिवहन के लिए H endorsement का उपयोग करता है। N endorsement tank वाहनों के लिए, T doubles/triples के लिए, और P यात्रियों के लिए है। स्रोत: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Ch. 8 (sdtruckinfo.sd.gov)।"},"26":{"q":"साउथ डकोटा द्वारा CDL में HazMat (H) endorsement जोड़ने से पहले, आवेदक को ज्ञान परीक्षा (knowledge test) पास करने के अतिरिक्त कौन सा संघीय चरण पूरा करना होगा?","options":["fingerprinting सहित एक TSA security threat assessment","एक 100-hour apprenticeship","एक eye surgery clearance","एक tank वाहन में अलग road test"],"explanation":"साउथ डकोटा तब तक HazMat endorsement जारी नहीं कर सकता जब तक आवेदक संघीय TSA Hazardous Materials Endorsement Threat Assessment Program पास नहीं करता, जिसके लिए लिखित ज्ञान परीक्षा के अतिरिक्त fingerprinting और एक background check आवश्यक है। स्रोत: TSA HME program; SD DPS CDL Endorsements; 49 CFR 1572।"},"27":{"q":"साउथ डकोटा का TANKER (N) endorsement उन वाहनों के लिए आवश्यक है जो स्थायी tank में 119 gallons या अधिक रेटेड तरल या गैस ढोते हैं, या ऐसे portable tank जिनकी कुल रेटेड क्षमता कम से कम कितने gallons हो?","options":["500 gallons","750 gallons","1,000 gallons","1,500 gallons"],"explanation":"साउथ डकोटा 119 gallons (450 liters) या अधिक रेटेड स्थायी tank, या 1,000 gallons या अधिक की कुल रेटेड क्षमता वाले portable tank के लिए N (tank) endorsement आवश्यक करता है। स्रोत: SD CDL Manual / SD DPS CDL Endorsements; FMCSA definition of tank vehicle, 49 CFR 383.5।"},"28":{"q":"एक साउथ डकोटा चालक जो TANK VEHICLE में खतरनाक सामग्री ढोता है, उसके पास कौन सा संयुक्त endorsement होना चाहिए?","options":["T","X","S","P"],"explanation":"साउथ डकोटा उन चालकों के लिए जो tank वाहन में खतरनाक सामग्री ढोते हैं, tank (N) और खतरनाक सामग्री (H) के संयोजन को दर्शाने के लिए X endorsement का उपयोग करता है। स्रोत: SD Motor Carrier Handbook, Ch. 8, CDL Classifications & Endorsements (sdtruckinfo.sd.gov)।"},"29":{"q":"DOUBLE या TRIPLE trailer खींचने वाले चालक के लिए साउथ डकोटा कौन सा endorsement आवश्यक करता है?","options":["P","N","T","H"],"explanation":"साउथ डकोटा double और triple trailer के लिए T endorsement आवश्यक करता है; आवेदक को एकाधिक trailer खींचने की समस्याओं पर एक विशेष ज्ञान परीक्षा पास करनी होगी। T के लिए कोई अलग skills test नहीं है। स्रोत: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Ch. 8।"},"30":{"q":"साउथ डकोटा PASSENGER (P) endorsement प्राप्त करने के लिए, एक चालक को एक विशेष ज्ञान परीक्षा पास करनी होगी और इसके अतिरिक्त क्या?","options":["एक passenger वाहन में skills test","एक 50-hour ride-along","एक TSA background check","एक bus में अलग vision test"],"explanation":"साउथ डकोटा P endorsement (16 या अधिक यात्रियों, चालक सहित, के लिए डिज़ाइन किए गए वाहन) चाहने वाले चालकों के लिए एक विशेष ज्ञान परीक्षा और एक passenger वाहन में आयोजित skills test दोनों पास करना आवश्यक करता है। स्रोत: SD DPS CDL Endorsements; SD CDL Manual।"},"31":{"q":"साउथ डकोटा में, किसी चालक को SCHOOL BUS (S) endorsement जारी किए जाने से पहले, CDL पर पहले से ही कौन सा अन्य endorsement होना चाहिए?","options":["H (HazMat) endorsement","T (doubles/triples) endorsement","P (passenger) endorsement","N (tank) endorsement"],"explanation":"साउथ डकोटा school bus (S) endorsement के लिए पूर्व-शर्त के रूप में passenger (P) endorsement आवश्यक करता है; S आवेदक को एक school bus ज्ञान परीक्षा और एक skills test भी पास करनी होगी। स्रोत: SD DPS CDL Endorsements; SD CDL Manual।"},"32":{"q":"एक साउथ डकोटा Commercial Learner's Permit (CLP) कितने समय के लिए वैध होता है?","options":["60 days","6 months","1 year","5 years"],"explanation":"एक साउथ डकोटा CLP behind-the-wheel प्रशिक्षण के लिए एक वर्ष की अवधि के लिए जारी किया जाता है। स्रोत: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 383.25।"},"33":{"q":"Commercial Learner's Permit प्राप्त करने के बाद, एक साउथ डकोटा आवेदक को CDL skills test देने के योग्य होने से पहले कितने समय प्रतीक्षा करनी होगी?","options":["कम से कम 7 days","कम से कम 14 days","कम से कम 30 days","कम से कम 90 days"],"explanation":"साउथ डकोटा संघीय नियम लागू करता है कि CDL skills (road) test देने के योग्य होने से पहले CLP को कम से कम 14 days तक धारण करना होगा। स्रोत: SD DPS Driver Licensing; 49 CFR 383.25(e)।"},"34":{"q":"साउथ डकोटा CLP पर ड्राइविंग करते समय, permit धारक के साथ एक ऐसा व्यक्ति होना चाहिए जिसके पास उचित वर्ग का वैध CDL हो और जो कहाँ बैठा हो?","options":["चालक के बगल वाली अगली सीट पर","cab में कहीं भी","एक अलग escort वाहन में","sleeper berth में"],"explanation":"एक साउथ डकोटा CLP धारक केवल तभी CMV चला सकता है जब उसके साथ उपयुक्त वर्ग/endorsements वाले वैध CDL धारक व्यक्ति हो जो चालक के बगल वाली अगली सीट पर बैठा हो। स्रोत: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications; 49 CFR 383.25(a)।"},"35":{"q":"एक साउथ डकोटा CDL आवेदक को पात्रता स्थापित करने के लिए driver exam station पर कौन से दस्तावेज़ों का सेट प्रस्तुत करना होगा?","options":["केवल एक Social Security card","पहचान/वैध उपस्थिति का प्रमाण, Social Security number, और साउथ डकोटा निवास","एक passport और एक credit card","एक high school diploma और एक vehicle title"],"explanation":"साउथ डकोटा पहचान और वैध उपस्थिति (जन्म तिथि) का प्रमाण, एक Social Security number, और साउथ डकोटा निवास साबित करने वाले दो दस्तावेज़ आवश्यक करता है; दस्तावेज़ मूल होने चाहिए, photocopy नहीं। स्रोत: SD DPS Required Driver's Licensing Documents (dps.sd.gov)।"},"36":{"q":"साउथ डकोटा में अधिकांश CDL आवेदक जिन्हें February 7, 2022 के बाद अपना CLP मिला, उन्हें कहाँ सूचीबद्ध प्रदाता से Entry-Level Driver Training (ELDT) पूरा करना होगा?","options":["किसी भी निजी trucking कंपनी की वेबसाइट","The FMCSA Training Provider Registry (TPR)","The South Dakota Secretary of State","स्थानीय county sheriff's office"],"explanation":"साउथ डकोटा में अपनाए गए संघीय ELDT नियमों के अनुसार February 7, 2022 को या उसके बाद CLP प्राप्त करने वाले आवेदकों के लिए skills test देने से पहले FMCSA Training Provider Registry (tpr.fmcsa.dot.gov) पर सूचीबद्ध किसी संस्था से theory और behind-the-wheel प्रशिक्षण आवश्यक है। स्रोत: FMCSA ELDT; SD DPS CDL information।"},"37":{"q":"एक साउथ डकोटा चालक के लिए कौन सी medical self-certification श्रेणी लागू होती है जो interstate वाणिज्य में संचालन करता है और जिसे संघीय DOT medical card आवश्यकता को पूरा करना ही होगा?","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"explanation":"Non-Excepted Interstate (NI) उन चालकों को कवर करता है जो interstate वाणिज्य में संचालन करते हैं और जिन्हें संघीय DOT physical/medical examiner's certificate आवश्यकता को पूरा करना होगा। EI excepted interstate है, NA/EA intrastate श्रेणियाँ हैं। स्रोत: 49 CFR 383.71; SD DPS Driver Licensing self-certification।"},"38":{"q":"एक साउथ डकोटा CDL या CLP आवेदक जो Non-Excepted Interstate के रूप में self-certify करता है, उसे कहाँ सूचीबद्ध परीक्षक से medical certificate प्रदान करना होगा?","options":["The FMCSA National Registry of Certified Medical Examiners","कोई भी walk-in urgent care clinic","The South Dakota Department of Health roster","चालक की पसंद का कोई अस्पताल"],"explanation":"साउथ डकोटा interstate (non-excepted) चालकों और school bus चालकों के लिए FMCSA National Registry of Certified Medical Examiners पर सूचीबद्ध किसी चिकित्सा पेशेवर से certification प्राप्त करना आवश्यक करता है, और certificate Driver Licensing के पास फ़ाइल में होना चाहिए। स्रोत: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications; 49 CFR 391.41।"},"39":{"q":"एक साउथ डकोटा Commercial Driver License (CDL) कितने वर्षों के लिए जारी किया जाता है, उससे पहले कि इसे नवीनीकृत करना आवश्यक हो?","options":["3 years","4 years","5 years","8 years"],"explanation":"साउथ डकोटा CDL को 5 वर्ष की अवधि के लिए जारी करता है, जिसके बाद लाइसेंस को नवीनीकृत करना होगा। (गैर-वाणिज्यिक SD लाइसेंस लंबी अवधि के लिए जारी किए जाते हैं, परन्तु CDL 5 years के होते हैं।) स्रोत: SD DPS Driver Licensing fees/information (dps.sd.gov)।"},"40":{"q":"साउथ डकोटा में, अधिकतम रक्त अल्कोहल सांद्रता (BAC) कितनी होती है जिस पर कोई व्यक्ति कानूनी रूप से एक वाणिज्यिक मोटर वाहन (CMV) चला सकता है?","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"साउथ डकोटा संघीय CMV मानक का पालन करता है: 0.04 percent या अधिक BAC के साथ CMV चलाना अवैध है, जो गैर-वाणिज्यिक चालकों के लिए 0.08 सीमा का आधा है। स्रोत: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Ch. 8 (49 CFR 383.51)।"},"41":{"q":"एक साउथ डकोटा CDL चालक 0.04 percent BAC से कम पता लगाने योग्य मात्रा में अल्कोहल के साथ CMV चलाते पाया जाता है। इसका तत्काल परिणाम क्या होता है?","options":["24 hours के लिए out of service रखा जाता है","एक वर्ष की CDL disqualification","60-day CDL disqualification","CDL की स्थायी हानि"],"explanation":"साउथ डकोटा में, 0.04 percent से कम किसी भी पता लगाने योग्य अल्कोहल वाले CMV चालक को disqualified करने के बजाय 24 hours के लिए out of service रखा जाता है। 0.04 या अधिक BAC एक वर्ष की disqualification ट्रिगर करता है। स्रोत: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Ch. 8।"},"42":{"q":"साउथ डकोटा के implied consent कानून के तहत, एक चालक किसी सार्वजनिक राजमार्ग पर कोई भी वाहन चलाकर किस बात के लिए सहमत होता है?","options":["अल्कोहल या ड्रग्स के लिए chemical testing के अधीन होने को","एक medical examiner's certificate रखने को","license सुनवाई के अधिकार को त्यागने को","नियोक्ता द्वारा random drug screening को"],"explanation":"साउथ डकोटा के implied consent कानून का अर्थ है कि सार्वजनिक राजमार्ग पर ड्राइविंग करने वाला कोई भी व्यक्ति अल्कोहल या ड्रग्स के लिए chemical test हेतु सहमति दे चुका है। इनकार के अपने दंड होते हैं भले ही कोई अल्कोहल न लिया गया हो। स्रोत: South Dakota CDL Manual; SDCL 32-23-10 (implied consent)।"},"43":{"q":"एक FIRST प्रमुख अपराध (major offense) के लिए (जैसे CMV में 0.04+ BAC) जिसमें placard लगी खतरनाक सामग्री शामिल न हो, एक साउथ डकोटा CDL धारक कितने समय के लिए disqualified होता है?","options":["1 year","60 days","3 years","Lifetime"],"explanation":"साउथ डकोटा में पहला प्रमुख अपराध न्यूनतम एक वर्ष की CDL disqualification का परिणाम देता है। यदि अपराध placard लगी खतरनाक सामग्री के परिवहन के दौरान हुआ तो यह अवधि बढ़कर तीन वर्ष हो जाती है। स्रोत: South Dakota CDL Manual (49 CFR 383.51)।"},"44":{"q":"placard लगाना आवश्यक खतरनाक सामग्री के परिवहन के दौरान किए गए FIRST प्रमुख अपराध के लिए एक साउथ डकोटा CDL चालक कितने समय के लिए disqualified होता है?","options":["3 years","1 year","120 days","Lifetime"],"explanation":"साउथ डकोटा में पहले प्रमुख अपराध के लिए मानक एक वर्ष की disqualification बढ़कर तीन वर्ष हो जाती है जब उल्लंघन placard लगी खतरनाक सामग्री का परिवहन करने वाले CMV का संचालन करते समय होता है। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)।"},"45":{"q":"एक अलग घटना से उत्पन्न SECOND प्रमुख अपराध के लिए साउथ डकोटा में disqualification अवधि क्या है?","options":["Lifetime","10 years","3 years","1 year"],"explanation":"एक अलग घटना से दूसरा प्रमुख अपराध (जैसे किसी भी वाहन में दूसरा DUI, परीक्षण से इनकार, या घटनास्थल छोड़ना) साउथ डकोटा में आजीवन (lifetime) CDL disqualification का परिणाम देता है, हालाँकि कुछ मामलों में 10 years के बाद पुनः बहाली संभव हो सकती है। स्रोत: South Dakota CDL Manual (49 CFR 383.51)।"},"46":{"q":"एक साउथ डकोटा CDL चालक अल्कोहल के लिए chemical test के अधीन होने से इनकार करता है। न्यूनतम disqualification अवधि क्या है?","options":["कम से कम 1 year","60 days","90 days","30 days"],"explanation":"आवश्यक अल्कोहल/ड्रग परीक्षण के अधीन होने से इनकार को साउथ डकोटा में एक प्रमुख अपराध माना जाता है और इसका परिणाम कम से कम एक वर्ष की disqualification होती है, जो 0.04+ BAC के समान है। चालक शराब न पीने पर भी CDL खो सकता है। स्रोत: South Dakota CDL Manual; SDCL implied consent provisions।"},"47":{"q":"3 वर्ष की अवधि के भीतर दो गंभीर यातायात उल्लंघनों (serious traffic violations) की दोषसिद्धि पर एक साउथ डकोटा CDL चालक कितने समय के लिए disqualified होता है?","options":["60 days","30 days","120 days","1 year"],"explanation":"तीन वर्ष के भीतर अलग-अलग घटनाओं में दो गंभीर यातायात उल्लंघनों का परिणाम साउथ डकोटा में 60-day disqualification होता है। तीन वर्ष के भीतर तीसरा 120 days जोड़ता है। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)।"},"48":{"q":"3 वर्ष की अवधि के भीतर तीन गंभीर यातायात उल्लंघनों की दोषसिद्धि पर एक साउथ डकोटा CDL चालक कितने समय के लिए disqualified होता है?","options":["120 days","60 days","90 days","1 year"],"explanation":"तीन वर्ष के भीतर अलग-अलग घटनाओं में तीसरे गंभीर यातायात उल्लंघन का परिणाम साउथ डकोटा में 120-day disqualification होता है (दूसरे के लिए 60 days के अतिरिक्त)। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8।"},"49":{"q":"एक साउथ डकोटा CDL धारक के लिए निम्न में से किसे SERIOUS यातायात उल्लंघन के रूप में वर्गीकृत किया जाता है?","options":["निर्धारित सीमा से 15 mph या अधिक तेज़ गति","0.04 या अधिक BAC के साथ ड्राइविंग","chemical test से इनकार करना","किसी दुर्घटना के घटनास्थल को छोड़ना"],"explanation":"साउथ डकोटा में, सीमा से 15 mph या अधिक तेज़ गति एक गंभीर यातायात उल्लंघन है। सूचीबद्ध अन्य अपराध MAJOR अपराध हैं जो एक वर्ष या आजीवन disqualification रखते हैं, गंभीर-उल्लंघन श्रेणी नहीं। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8।"},"50":{"q":"CDL प्रयोजनों के लिए साउथ डकोटा के गंभीर यातायात उल्लंघनों में निम्न में से किस उल्लंघन की गणना नहीं की जाती?","options":["0.04+ BAC के साथ CMV चलाना","किसी अन्य वाहन का बहुत निकट से अनुसरण करना","अनुचित या अनियमित lane change","CDL रखे बिना CMV चलाना"],"explanation":"0.04+ BAC के साथ CMV चलाना एक MAJOR अपराध है (एक वर्ष की disqualification), गंभीर यातायात उल्लंघन नहीं। बहुत निकट से अनुसरण करना, अनुचित lane change, और CDL के बिना CMV चलाना गंभीर यातायात उल्लंघन हैं। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8।"},"51":{"q":"एक साउथ डकोटा CDL चालक द्वारा FIRST railroad-highway grade crossing उल्लंघन के लिए disqualification अवधि क्या है?","options":["60 days","30 days","120 days","1 year"],"explanation":"पहले railroad-highway grade crossing उल्लंघन का परिणाम साउथ डकोटा में 60-day disqualification होता है। तीन वर्ष के भीतर दूसरा 120 days और तीसरा एक वर्ष होता है। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)।"},"52":{"q":"एक साउथ डकोटा CDL चालक के लिए 3 वर्ष के भीतर SECOND railroad-highway grade crossing उल्लंघन के लिए disqualification अवधि क्या है?","options":["120 days","60 days","90 days","1 year"],"explanation":"तीन वर्ष के भीतर दूसरे railroad-grade-crossing उल्लंघन का परिणाम साउथ डकोटा में 120-day disqualification होता है। तीन वर्ष के भीतर तीसरे का परिणाम एक वर्ष की disqualification होता है। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8।"},"53":{"q":"साउथ डकोटा में 3 वर्ष के भीतर THIRD railroad-highway grade crossing उल्लंघन के लिए disqualification अवधि क्या है?","options":["1 year","120 days","180 days","60 days"],"explanation":"तीन वर्ष की अवधि के भीतर तीसरे railroad-grade-crossing उल्लंघन का परिणाम साउथ डकोटा में एक वर्ष की CDL disqualification होता है। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)।"},"54":{"q":"एक साउथ डकोटा CDL चालक द्वारा out-of-service order के FIRST उल्लंघन के लिए न्यूनतम disqualification क्या है (कोई hazmat या यात्री नहीं)?","options":["180 days","90 days","60 days","30 days"],"explanation":"out-of-service order के उल्लंघन के लिए पहली दोषसिद्धि का परिणाम साउथ डकोटा में कम से कम 180 days (एक वर्ष तक) की disqualification होता है। यदि hazmat/यात्री शामिल थे तो न्यूनतम बढ़कर 3 years हो जाता है। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8।"},"55":{"q":"एक साउथ डकोटा CDL चालक 10 वर्ष के भीतर SECOND out-of-service order उल्लंघन करता है (कोई hazmat या यात्री नहीं)। disqualification अवधि क्या है?","options":["2 years","1 year","180 days","3 years"],"explanation":"10 वर्ष के भीतर अलग-अलग घटनाओं में दूसरे out-of-service order उल्लंघन का परिणाम साउथ डकोटा में 2-year disqualification होता है। 10 वर्ष के भीतर तीसरा 3 years होता है। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)।"},"56":{"q":"किसी नियंत्रित पदार्थ (controlled substance) के निर्माण या वितरण से जुड़े अपराध (felony) को करने में CMV का उपयोग करने का साउथ डकोटा में क्या disqualification परिणाम होता है?","options":["आजीवन, बिना किसी पुनर्बहाली के","1 year","3 years","10 years फिर पुनर्बहाली"],"explanation":"किसी नियंत्रित पदार्थ के निर्माण, वितरण, या वितरण से जुड़े अपराध (felony) को करने के लिए CMV का उपयोग करने का परिणाम साउथ डकोटा में पुनर्बहाली की कोई संभावना के बिना आजीवन CDL disqualification होता है। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)।"},"57":{"q":"साउथ डकोटा में लागू संघीय नियमों के तहत, CMV चलाते समय 3 वर्ष के भीतर कितनी texting दोषसिद्धियाँ 120-day disqualification ट्रिगर करती हैं?","options":["3 या अधिक","2","5","4"],"explanation":"तीन वर्ष के भीतर दो texting उल्लंघन 60-day disqualification और तीन या अधिक साउथ डकोटा CDL चालकों के लिए 120-day disqualification का कारण बनते हैं। CMV चलाते समय texting भी एक गंभीर यातायात उल्लंघन है। स्रोत: South Dakota CDL Manual (49 CFR 392.80 / 383.51)।"},"58":{"q":"एक साउथ डकोटा CDL चालक के लिए, CMV चलाते समय hand-held mobile telephone का उपयोग करना किस प्रकार के उल्लंघन के रूप में सबसे अच्छा वर्णित होता है?","options":["एक गंभीर यातायात उल्लंघन","एक प्रमुख अपराध (1-year disqualification)","एक out-of-service order उल्लंघन","एक गैर-रिपोर्ट योग्य उपकरण उल्लंघन"],"explanation":"CMV चलाते समय hand-held mobile phone का उपयोग करना साउथ डकोटा में एक गंभीर यातायात उल्लंघन है; 3 वर्ष के भीतर दो 60-day disqualification और तीन 120 days का कारण बनते हैं। स्रोत: South Dakota CDL Manual (49 CFR 392.82 / 383.51)।"},"59":{"q":"किसी भी वाहन में यातायात उल्लंघन (parking के अलावा) की दोषसिद्धि के बाद एक साउथ डकोटा CDL धारक को कितने दिनों के भीतर अपने नियोक्ता को सूचित करना होगा?","options":["30 days","10 days","15 days","60 days"],"explanation":"साउथ डकोटा एक CDL धारक को किसी भी राज्य में और किसी भी वाहन में किसी भी यातायात उल्लंघन (parking को छोड़कर) की दोषसिद्धि के 30 days के भीतर अपने नियोक्ता को सूचित करना आवश्यक करता है। स्रोत: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8।"},"60":{"q":"साउथ डकोटा के मूव ओवर कानून (1 जुलाई 2025 को अद्यतन) के तहत, एम्बर, पीली या नीली चेतावनी लाइट दिखाने वाले रुके हुए वाहन से कितनी दूरी पहले चालक को प्रतिक्रिया देना शुरू कर देना चाहिए?","options":["100 feet","200 feet","300 feet","500 feet"],"explanation":"SDCL 32-31-6.1 के अनुसार चालकों को वाहन से कम से कम 300 feet पहले कार्रवाई करनी आवश्यक है। स्रोत: SDCL 32-31-6.1; SDDOT मूव ओवर कानून (प्रभावी 1 जुलाई 2025)।"},"61":{"q":"साउथ डकोटा के बहु-लेन राजमार्ग पर, जब चेतावनी लाइट चमकाते हुए शोल्डर पर रुके वाहन के पास पहुँचा जाए तो मूव ओवर कानून क्या आवश्यक करता है?","options":["लाइट बंद होने तक पूरी तरह रुक जाएँ","वाहन से सबसे दूर वाली लेन में मर्ज करें और सावधानी से आगे बढ़ें","30 mph तक धीमे हो जाएँ और दाहिनी लेन में बने रहें","हॉर्न बजाएँ और निर्धारित सीमा पर पार करें"],"explanation":"एक ही दिशा में दो या अधिक लेन वाली सड़क पर, SDCL 32-31-6.1 के अनुसार चालक को रुके हुए वाहन से कम से कम 300 feet पहले उससे सबसे दूर वाली लेन में मर्ज करना और सावधानी से आगे बढ़ना आवश्यक है। स्रोत: SDCL 32-31-6.1; SDDOT।"},"62":{"q":"साउथ डकोटा के दो-लेन राजमार्ग पर जहाँ हटना संभव नहीं है, शोल्डर पर चेतावनी लाइट वाले वाहन को पार करते समय मूव ओवर कानून के अनुसार चालक को निर्धारित गति सीमा से कम से कम कितना नीचे धीमा होना आवश्यक है?","options":["निर्धारित सीमा से कम से कम 10 mph नीचे","निर्धारित सीमा से कम से कम 15 mph नीचे","निर्धारित सीमा से कम से कम 20 mph नीचे","निर्धारित सीमा से कम से कम 25 mph नीचे"],"explanation":"दो-लेन सड़क पर, SDCL 32-31-6.1 के अनुसार निर्धारित सीमा से कम से कम 20 mph कम गति तक धीमा होना आवश्यक है (या यदि सीमा 20 mph या उससे कम है तो 5 mph)। स्रोत: SDCL 32-31-6.1; SDDOT।"},"63":{"q":"साउथ डकोटा के विस्तारित मूव ओवर कानून द्वारा रुके हुए वाहनों की कौन-सी श्रेणियाँ संरक्षित हैं?","options":["केवल चिह्नित कानून-प्रवर्तन वाहन","केवल एम्बुलेंस और फायर ट्रक","शोल्डर पर चमकती एम्बर, पीली या नीली लाइट दिखाने वाला कोई भी वाहन, जिसमें टो ट्रक, रखरखाव वाहन और खराब वाहन शामिल हैं","केवल लाल और नीली आपातकालीन लाइट दिखाने वाले वाहन"],"explanation":"SDCL 32-31-6.1 के 1 जुलाई 2025 के विस्तार में शोल्डर पर चमकती एम्बर, पीली या नीली चेतावनी लाइट दिखाने वाला कोई भी वाहन शामिल है, जिसमें टो ट्रक, राजमार्ग रखरखाव और खराब वाहन चालक शामिल हैं। स्रोत: SDCL 32-31-6.1; SDDOT।"},"64":{"q":"साउथ डकोटा के दो-लेन राजमार्ग पर, जब किसी स्कूल बस से मिला या उसे ओवरटेक किया जाए जिसकी एम्बर चेतावनी लाइट चमक रही हों, तो चालक को गति घटाकर कितने से अधिक नहीं रखनी चाहिए?","options":["35 mph","25 mph","20 mph","15 mph"],"explanation":"SDCL 32-32-6 के अनुसार जब किसी स्कूल बस की एम्बर सावधानी लाइट चमक रही हों तो चालक को गति घटाकर 15 mph या उससे कम करनी आवश्यक है। स्रोत: SDCL 32-32-6।"},"65":{"q":"जब कोई साउथ डकोटा स्कूल बस दो-लेन सड़क पर अपनी लाल सिग्नल लाइट चमकाते हुए रुकी हो, तो पास आ रहे चालक को बस से कम से कम कितनी दूरी पर रुकना चाहिए?","options":["10 feet","15 feet","20 feet","30 feet"],"explanation":"SDCL 32-32-6 के अनुसार चालकों को वाहन को स्कूल बस से कम से कम 15 feet की दूरी पर पूरी तरह रोकना और लाल लाइट के चमकना बंद होने तक रुके रहना आवश्यक है। स्रोत: SDCL 32-32-6।"},"66":{"q":"साउथ डकोटा कानून के तहत, किस प्रकार की सड़क पर विपरीत दिशा में चल रहा चालक लाल लाइट चमकाते हुए रुकी स्कूल बस के लिए बिना रुके आगे बढ़ सकता है?","options":["रंगी हुई केंद्र रेखा वाला कोई भी राजमार्ग","प्रत्येक दिशा में दो या अधिक यात्रा लेन प्रदान करने वाला राजमार्ग","45 mph से अधिक निर्धारित सीमा वाली कोई भी सड़क","केवल पूरी तरह पहुँच-नियंत्रित इंटरस्टेट"],"explanation":"SDCL 32-32-6 प्रत्येक दिशा में दो या अधिक यात्रा लेन वाले राजमार्ग पर विपरीत दिशा से आ रहे चालक को लाल लाइट चमकाते हुए स्कूल बस के लिए रुकने से छूट देता है। स्रोत: SDCL 32-32-6।"},"67":{"q":"रुकने से कितनी दूरी पहले साउथ डकोटा स्कूल बस संचालक को एम्बर सावधानी लाइट सक्रिय करनी चाहिए?","options":["100 से कम नहीं और 300 feet से अधिक नहीं","200 से कम नहीं और 400 feet से अधिक नहीं","300 से कम नहीं और 500 feet से अधिक नहीं","500 से कम नहीं और 700 feet से अधिक नहीं"],"explanation":"SDCL 32-32-5.2 के अनुसार एम्बर सावधानी लाइट उस स्थान से 300 feet से कम नहीं और 500 feet से अधिक नहीं पहले जलनी आवश्यक है जहाँ छात्रों को चढ़ाया या उतारा जाता है। स्रोत: SDCL 32-32-5.2।"},"68":{"q":"साउथ डकोटा के अधिकतम पर निर्धारित ग्रामीण इंटरस्टेट राजमार्गों पर, एक ट्रैक्टर-ट्रेलर की गति सीमा यात्री कार की तुलना में क्या है?","options":["ट्रक 65 mph; कार 80 mph","ट्रक 70 mph; कार 75 mph","ट्रक 75 mph; कार 80 mph","ट्रक 80 mph; कार 80 mph (समान सीमा)"],"explanation":"साउथ डकोटा अधिकांश ग्रामीण इंटरस्टेट पर 80 mph निर्धारित करता है और ट्रकों व कारों पर समान सीमा लागू करता है; ट्रकों के लिए कोई अलग कम गति सीमा नहीं है। स्रोत: SDCL ch. 32-25; SDDOT गति विनियम।"},"69":{"q":"साउथ डकोटा में, इंटरस्टेट पर संचालित होने वाला Longer Combination Vehicle (LCV) किस अधिकतम गति से अधिक नहीं हो सकता?","options":["55 mph","60 mph","65 mph","70 mph"],"explanation":"South Dakota Administrative Rule 70:03:01:61 Longer Combination Vehicles को इंटरस्टेट राजमार्गों पर अधिकतम 65 mph तक सीमित करता है, भले ही निर्धारित सीमा अधिक हो। स्रोत: ARSD 70:03:01:61।"},"70":{"q":"साउथ डकोटा में, जब किसी प्लैकार्ड लगे खतरनाक-सामग्री वाहन को रुकना आवश्यक हो और वह रेलमार्ग क्रॉसिंग के पास पहुँचे, तो उसे कहाँ रुकना चाहिए?","options":["निकटतम रेल से 5 से 25 feet के भीतर","निकटतम रेल से 15 से 50 feet के भीतर","निकटतम रेल से 25 से 75 feet के भीतर","निकटतम रेल से 50 से 100 feet के भीतर"],"explanation":"एक प्लैकार्ड लगे वाहन को निकटतम रेल से 15 से 50 feet के भीतर रुकना चाहिए, फिर पार करने से पहले देखना और सुनना चाहिए। स्रोत: SD CDL Manual; 49 CFR 392.10।"},"71":{"q":"साउथ डकोटा में रेलमार्ग पटरियों को पार करते समय, बस या प्लैकार्ड लगे वाहन के चालक को क्या नहीं करना चाहिए?","options":["ट्रेनों के लिए देखना और सुनना","पटरियों पर रहते हुए गियर बदलना","शक्ति बनाए रखने के लिए कम गियर का उपयोग करना","सुनिश्चित करना कि पटरियों को पार करने के लिए जगह है"],"explanation":"चालकों को पटरियाँ पार करते समय गियर नहीं बदलना चाहिए ताकि क्रॉसिंग पर वाहन बंद न हो जाए; ऐसे गियर में पार करें जिसे बदलने की आवश्यकता न हो। स्रोत: SD CDL Manual; 49 CFR 392.10/392.11।"},"72":{"q":"किस रेलमार्ग क्रॉसिंग पर साउथ डकोटा बस चालक को आम तौर पर अनिवार्य रोक बनाने की आवश्यकता नहीं होती?","options":["यातायात को आगे निर्देशित कर रहे पुलिस अधिकारी या फ्लैगर द्वारा नियंत्रित क्रॉसिंग","खुले देहात में बहु-ट्रैक क्रॉसिंग","बिना स्वचालित गेट वाला क्रॉसिंग","तीव्र ढलान पर क्रॉसिंग"],"explanation":"अनिवार्य रोक की आवश्यकता वहाँ नहीं है जहाँ कोई पुलिस अधिकारी या फ्लैगर यातायात को निर्देशित कर रहा हो, छूट-प्राप्त/परित्यक्त या औद्योगिक-स्पर क्रॉसिंग पर, या जब हरा यातायात सिग्नल क्रॉसिंग को नियंत्रित करता हो। स्रोत: SD CDL Manual; 49 CFR 392.10।"},"73":{"q":"साउथ डकोटा वाणिज्यिक चालक को सड़क किनारे रुकने पर कितने परावर्तक चेतावनी त्रिकोण ले जाने और रखने चाहिए?","options":["एक त्रिकोण","दो त्रिकोण","तीन त्रिकोण","चार त्रिकोण"],"explanation":"एक CMV को तीन परावर्तक त्रिकोण (या समकक्ष उपकरण) ले जाने और तैनात करने चाहिए, जिन्हें रुकने के 10 मिनट के भीतर रखा जाए। स्रोत: SD CDL Manual; 49 CFR 392.22।"},"74":{"q":"दो-लेन, दो-तरफा साउथ डकोटा राजमार्ग पर, जब कोई ट्रक रुका हो तो तीन चेतावनी त्रिकोण कहाँ रखे जाने चाहिए?","options":["तीनों लगभग 100 feet वाहन के पीछे","लगभग 10 feet, 100 feet, और 200 feet वाहन के पीछे","यातायात की ओर 10 feet के भीतर, और वाहन के लगभग 100 feet आगे और 100 feet पीछे","वाहन के लगभग 50 feet आगे, बगल में, और पीछे"],"explanation":"दो-लेन, दो-तरफा सड़क पर, एक त्रिकोण यातायात की ओर 10 feet के भीतर और एक लगभग 100 feet पीछे और एक लगभग 100 feet वाहन के आगे रखें। स्रोत: SD CDL Manual; 49 CFR 392.22।"},"75":{"q":"साउथ डकोटा विभाजित या एक-तरफा राजमार्ग पर, रुके हुए ट्रक के पीछे तीन चेतावनी त्रिकोण कहाँ रखे जाते हैं?","options":["10, 50, और 100 feet पर","10, 100, और 200 feet पर","25, 100, और 300 feet पर","50, 150, और 250 feet पर"],"explanation":"विभाजित या एक-तरफा सड़क पर, त्रिकोणों को वाहन के पीछे आ रहे यातायात की ओर लगभग 10 feet, 100 feet, और 200 feet पर रखें। स्रोत: SD CDL Manual; 49 CFR 392.22।"},"76":{"q":"साउथ डकोटा के दाएँ-रखें नियम के तहत, चालक को सड़क की दाहिनी लेन या हिस्से का उपयोग कब करना चाहिए?","options":["केवल इंटरस्टेट राजमार्गों पर","जब यातायात की सामान्य गति से धीमे चल रहे हों, सिवाय ओवरटेक करते समय या जब दाहिनी लेन अव्यावहारिक हो","केवल सूर्यास्त और सूर्योदय के बीच","केवल जब कोई ट्रक पीछे आ रहा हो"],"explanation":"SDCL 32-26-1 के अनुसार सड़क के दाहिने आधे हिस्से पर चलना आवश्यक है और सामान्य से धीमे यातायात के लिए, ओवरटेक करते समय या जहाँ दाहिनी लेन का उपयोग अव्यावहारिक हो, उसके अलावा दाहिनी ओर रहना आवश्यक है। स्रोत: SDCL 32-26-1।"},"77":{"q":"साउथ डकोटा में ओवरसाइज परमिट आवश्यक होने से पहले अधिकतम कानूनी वाहन चौड़ाई क्या है?","options":["8 feet 0 inches","8 feet 6 inches","9 feet 0 inches","10 feet 0 inches"],"explanation":"साउथ डकोटा की बिना परमिट के कानूनी चौड़ाई सीमा 8 feet 6 inches (102 inches) है; इससे चौड़ी किसी भी चीज़ के लिए ओवरसाइज परमिट आवश्यक है। स्रोत: SDDOT/SD Highway Patrol ओवरसाइज परमिट नियम; SDCL ch. 32-22।"},"78":{"q":"साउथ डकोटा में, किन घंटों के दौरान ओवरसाइज-लोड (अविभाज्य चौड़ाई) परमिट धारक आम तौर पर यात्रा कर सकता है?","options":["दिन में 24 घंटे, किसी भी दिन","केवल सोमवार से शुक्रवार, केवल दिन के उजाले में","सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद तक, सप्ताहांत सहित","केवल कार्यदिवसों पर सुबह 9 बजे से शाम 4 बजे के बीच"],"explanation":"ओवरसाइज लोड सूर्योदय से आधा घंटा पहले से सूर्यास्त के आधा घंटा बाद तक चल सकते हैं, जिसमें शनिवार और रविवार शामिल हैं; केवल-ओवरवेट लोड लगातार चल सकते हैं। स्रोत: SDDOT/SD Highway Patrol ओवरसाइज परमिट नियम।"},"79":{"q":"कौन-सी साउथ डकोटा एजेंसी Commercial Driver Licenses जारी करती है?","options":["South Dakota Department of Public Safety, Driver Licensing Program","South Dakota Department of Transportation","आवेदक जहाँ रहता है उस काउंटी का शेरिफ कार्यालय","Federal Motor Carrier Safety Administration"],"explanation":"साउथ डकोटा में, CDL को Department of Public Safety द्वारा इसके Driver Licensing Program (Pierre, SD) के माध्यम से जारी किया जाता है। SD DOT परमिट और सड़कों को संभालता है, चालक लाइसेंसिंग को नहीं। स्रोत: SD DPS Driver Licensing / SD Truck Information (sdtruckinfo.sd.gov), Motor Carrier Handbook Ch. 8।"},"80":{"q":"केवल अंतरराज्यीय वाणिज्य (साउथ डकोटा के भीतर) में गाड़ी चलाने के लिए साउथ डकोटा CDL प्राप्त करने हेतु न्यूनतम आयु क्या है?","options":["16","18","19","21"],"explanation":"साउथ डकोटा अंतरराज्यीय वाणिज्य (intrastate) के लिए 18 वर्ष की आयु में CDL की अनुमति देता है; अंतरराज्यीय सीमा-पार (interstate) वाणिज्य के लिए 21 वर्ष की आयु आवश्यक है। स्रोत: SD Motor Carrier Handbook Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov)।"},"81":{"q":"अंतरराज्यीय वाणिज्य (राज्य सीमाओं के पार गाड़ी चलाना) के लिए साउथ डकोटा CDL प्राप्त करने हेतु न्यूनतम आयु क्या है?","options":["18","19","20","21"],"explanation":"अंतरराज्यीय वाणिज्य (interstate) में गाड़ी चलाने के लिए साउथ डकोटा में न्यूनतम 21 वर्ष की आयु आवश्यक है; 18 से 20 वर्ष के चालक अंतरराज्यीय (intrastate) संचालन तक सीमित हैं। स्रोत: SD Motor Carrier Handbook Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov)।"},"82":{"q":"साउथ डकोटा Commercial Learner's Permit (CLP) कितने समय तक मान्य रहता है?","options":["30 days","6 months","1 year","2 years"],"explanation":"साउथ डकोटा CLP सार्वजनिक सड़कों पर व्हील-पीछे प्रशिक्षण के लिए एक-वर्ष की अवधि के लिए जारी किया जाता है। स्रोत: SD Motor Carrier Handbook Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov)।"},"83":{"q":"साउथ डकोटा में, Commercial Learner's Permit जारी होने के कितने समय बाद आवेदक को CDL कौशल परीक्षा देने से पहले प्रतीक्षा करनी चाहिए?","options":["कोई प्रतीक्षा अवधि आवश्यक नहीं","कम से कम 7 days","कम से कम 14 days","कम से कम 30 days"],"explanation":"CLP जारी होने की तारीख और कौशल परीक्षा पूरी की जा सकने वाली तारीख के बीच 14 दिन की प्रतीक्षा अवधि होती है। स्रोत: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov); संघीय 49 CFR 383.25 को दर्शाता है।"},"84":{"q":"वाणिज्य के प्रकार और चिकित्सा आवश्यकताओं के संबंध में साउथ डकोटा CDL आवेदक को कितनी स्व-प्रमाणन श्रेणियों में से चुनना चाहिए?","options":["दो","तीन","चार","पाँच"],"explanation":"चार स्व-प्रमाणन श्रेणियाँ हैं: Non-excepted Interstate (NI), Excepted Interstate (EI), Non-excepted Intrastate (NA), और Excepted Intrastate (EA)। स्रोत: SD DPS CDL Medical Certification; 49 CFR 383.71।"},"85":{"q":"एक साउथ डकोटा चालक जो राज्य सीमाओं के पार संचालन करता है और जिसे संघीय DOT शारीरिक योग्यता मानकों को पूरा करना आवश्यक है, किस श्रेणी के रूप में स्व-प्रमाणित करता है?","options":["Non-excepted Interstate (NI)","Excepted Interstate (EI)","Non-excepted Intrastate (NA)","Excepted Intrastate (EA)"],"explanation":"Non-excepted Interstate (NI) का अर्थ है कि चालक अंतरराज्यीय वाणिज्य में संचालन करता है और उसे संघीय DOT चिकित्सा प्रमाणपत्र आवश्यकताओं (एक वर्तमान चिकित्सा परीक्षक का प्रमाणपत्र) को पूरा करना होगा। स्रोत: SD DPS CDL Medical Certification; 49 CFR 383.71।"},"86":{"q":"जब कोई साउथ डकोटा CDL आवेदक Non-excepted Interstate के रूप में स्व-प्रमाणित करता है, तो मान्य बने रहने के लिए राज्य के पास कौन-सा दस्तावेज़ फाइल पर रखा जाना चाहिए?","options":["किसी नेत्र चिकित्सक से दृष्टि छूट","एक वर्तमान DOT चिकित्सा परीक्षक का प्रमाणपत्र","एक हस्ताक्षरित नियोक्ता शपथपत्र","एक नोटरीकृत ड्राइविंग लॉग"],"explanation":"Non-excepted चालकों को Driver Licensing Program के पास फाइल पर एक मान्य चिकित्सा परीक्षक का प्रमाणपत्र (DOT चिकित्सा कार्ड) बनाए रखना चाहिए; इसके बिना CDL डाउनग्रेड कर दिया जाता है। स्रोत: SD DPS CDL Medical Certification।"},"87":{"q":"साउथ डकोटा CDL धारक के DOT चिकित्सा प्रमाणपत्र के लिए शारीरिक परीक्षा करने हेतु कौन अधिकृत है?","options":["चालक की पसंद का कोई भी लाइसेंस प्राप्त चिकित्सक","FMCSA National Registry of Certified Medical Examiners में सूचीबद्ध एक चिकित्सा परीक्षक","केवल SD Department of Public Safety द्वारा नियुक्त एक चिकित्सक","किसी भी अर्जेंट केयर क्लिनिक की एक नर्स"],"explanation":"परीक्षा FMCSA National Registry of Certified Medical Examiners में सूचीबद्ध एक चिकित्सा पेशेवर द्वारा की जानी चाहिए। स्रोत: SD Motor Carrier Handbook Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); National Registry (nationalregistry.fmcsa.dot.gov)।"},"88":{"q":"साउथ डकोटा CDL धारक के DOT शारीरिक परीक्षा के बाद, चिकित्सा परीक्षक का प्रमाणपत्र आम तौर पर राज्य के Driver Licensing Program तक कैसे पहुँचता है?","options":["चालक को इसे किसी न्यायालय में स्वयं पहुँचाना चाहिए","परीक्षक इसे National Registry के माध्यम से 2 business days के भीतर Driver Licensing को इलेक्ट्रॉनिक रूप से प्रस्तुत करता है","इसे केवल चालक के नियोक्ता द्वारा मेल किया जाता है","यह बिना किसी प्रस्तुति के स्वतः मान्य होता है"],"explanation":"प्रमाणित चिकित्सा परीक्षक FMCSA National Registry के माध्यम से प्रमाणपत्र को 2 business days के भीतर South Dakota Driver Licensing को इलेक्ट्रॉनिक रूप से प्रस्तुत करते हैं; चालक फैक्स, ईमेल या मेल द्वारा भी एक प्रति प्रस्तुत कर सकते हैं। स्रोत: SD DPS / SD Truck Information (sdtruckinfo.sd.gov)।"},"89":{"q":"साउथ डकोटा CDL धारक के लिए DOT चिकित्सा परीक्षक का प्रमाणपत्र अधिकतम कितनी अवधि तक मान्य हो सकता है?","options":["6 months","1 year","2 years","5 years"],"explanation":"एक चिकित्सा परीक्षक का प्रमाणपत्र अधिकतम दो वर्ष तक मान्य होता है, और चालक की चिकित्सा स्थिति के आधार पर कम अवधि के लिए जारी किया जा सकता है। स्रोत: SD Motor Carrier Handbook Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 391.43।"},"90":{"q":"वाहन वर्ग या एंडोर्समेंट की परवाह किए बिना, प्रत्येक साउथ डकोटा CDL आवेदक को कौन-सी ज्ञान परीक्षा पास करनी चाहिए?","options":["एयर ब्रेक परीक्षा","सामान्य ज्ञान परीक्षा","खतरनाक सामग्री परीक्षा","डबल्स/ट्रिपल्स परीक्षा"],"explanation":"सामान्य ज्ञान परीक्षा सभी आवेदकों द्वारा दी जाती है; अन्य परीक्षाएँ केवल विशिष्ट वाहनों या एंडोर्समेंट के लिए आवश्यक हैं। स्रोत: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)।"},"91":{"q":"साउथ डकोटा CDL कौशल परीक्षा में कौन-से तीन भाग होते हैं, क्रम में दिए गए?","options":["लिखित परीक्षा, दृष्टि जाँच, और सड़क परीक्षा","प्री-ट्रिप निरीक्षण, बुनियादी वाहन नियंत्रण, और सड़क पर ड्राइविंग","एयर ब्रेक परीक्षा, कपलिंग परीक्षा, और बैकिंग परीक्षा","ज्ञान परीक्षा, सिमुलेटर परीक्षा, और रात-ड्राइविंग परीक्षा"],"explanation":"कौशल परीक्षा के तीन भाग होते हैं: प्री-ट्रिप (वाहन) निरीक्षण, बुनियादी वाहन नियंत्रण युक्तियाँ, और सड़क पर ड्राइविंग परीक्षा। स्रोत: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)।"},"92":{"q":"साउथ डकोटा CDL कौशल परीक्षा के बुनियादी वाहन नियंत्रण भाग के दौरान, आवेदक से मुख्य रूप से क्या प्रदर्शित करने को कहा जाता है?","options":["पूरे CDL मैनुअल को स्मृति से सुनाना","वाहन को आगे, पीछे ले जाना, और इसे कोन से चिह्नित एक निर्धारित क्षेत्र के भीतर मोड़ना","एक ब्रेक प्रणाली की मरम्मत करना","खतरनाक माल को लोड और सुरक्षित करना"],"explanation":"बुनियादी वाहन नियंत्रण चालक की वाहन को आगे और पीछे ले जाने और इसे कोन या बाधाओं से चिह्नित एक निर्धारित क्षेत्र के भीतर मोड़ने की क्षमता का मूल्यांकन करता है। स्रोत: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)।"},"93":{"q":"साउथ डकोटा CDL कौशल परीक्षा के प्री-ट्रिप निरीक्षण भाग में, आवेदक को क्या करना चाहिए?","options":["राजमार्ग यातायात में गाड़ी चलाना","जिन वाहन घटकों का वे निरीक्षण करेंगे उन्हें पहचानना और यह समझाना कि वे क्या जाँच रहे हैं और क्यों","केवल समानांतर पार्किंग प्रदर्शित करना","एक अलग लिखित हैज़मैट परीक्षा पास करना"],"explanation":"प्री-ट्रिप निरीक्षण के लिए चालक को वाहन सुरक्षा का मूल्यांकन करने की क्षमता प्रदर्शित करनी होती है, निरीक्षण मदों को पहचानना और यह समझाना कि वे क्या जाँचेंगे और क्यों। स्रोत: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)।"},"94":{"q":"साउथ डकोटा में, यदि कोई आवेदक CDL ज्ञान या कौशल परीक्षा में असफल हो जाता है, तो वे सबसे जल्दी कब पुनः परीक्षा दे सकते हैं?","options":["तुरंत, उसी दिन","अगले कार्यदिवस से पहले नहीं","30-दिन की प्रतीक्षा अवधि के बाद","पूरे 6 महीने के बाद"],"explanation":"यदि आप किसी भी परीक्षा में असफल होते हैं तो आप अगले कार्यदिवस से पहले पुनः परीक्षा नहीं दे सकते; यदि आप अधिक अध्ययन या अभ्यास चाहते हैं तो अधिक प्रतीक्षा कर सकते हैं। स्रोत: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)।"},"95":{"q":"साउथ डकोटा में, प्रत्येक परीक्षा शुल्क छह-महीने की अवधि के भीतर परीक्षा देने के कितने अवसरों को कवर करता है?","options":["एक","दो","तीन","असीमित"],"explanation":"आवेदकों को छह-महीने की अवधि के भीतर प्रत्येक भुगतान किए गए शुल्क के लिए परीक्षा देने के तीन अवसर दिए जाते हैं। सटीक शुल्क राशि बदल सकती है, इसलिए डॉलर आँकड़ों के बजाय प्रक्रिया नियमों पर भरोसा किया जाना चाहिए। स्रोत: SD Motor Carrier Handbook Ch. 8, Commercial Driver License Tests (sdtruckinfo.sd.gov)।"},"96":{"q":"साउथ डकोटा द्वारा लागू संघीय Entry-Level Driver Training (ELDT) नियम के तहत, पहली बार CDL आवेदक को आवश्यक प्रशिक्षण कहाँ पूरा करना चाहिए?","options":["अपनी पसंद का कोई भी ऑनलाइन कोर्स","FMCSA Training Provider Registry (TPR) में सूचीबद्ध एक प्रशिक्षण प्रदाता","केवल SD DPS द्वारा प्रदान किया जाने वाला कोर्स","परीक्षा से पहले कोई औपचारिक प्रशिक्षण आवश्यक नहीं"],"explanation":"ELDT (7 फरवरी 2022 से प्रभावी) के अनुसार प्रवेश-स्तर के आवेदकों को CDL कौशल परीक्षा (या, हैज़मैट के लिए, ज्ञान परीक्षा) देने से पहले FMCSA Training Provider Registry के एक प्रदाता से सिद्धांत और व्हील-पीछे प्रशिक्षण पूरा करना आवश्यक है। स्रोत: FMCSA ELDT नियम (49 CFR Part 380), SD DPS द्वारा लागू।"},"97":{"q":"साउथ डकोटा CDL प्राप्त करते समय संघीय ELDT आवश्यकता किन आवेदकों पर लागू होती है?","options":["केवल 65 वर्ष से अधिक आयु के चालक","पहली बार Class A या B CDL प्राप्त करने वाले, वर्ग अपग्रेड करने वाले, या पहली बार स्कूल बस, यात्री, या हैज़मैट एंडोर्समेंट चाहने वाले आवेदक","केवल राज्य-बाहर स्थानांतरण आवेदक","केवल मौजूदा CDL नवीनीकृत करने वाले चालक"],"explanation":"ELDT उन पर लागू होता है जो पहला Class A या B CDL प्राप्त कर रहे हैं, अपग्रेड कर रहे हैं (जैसे, B से A), या पहली बार स्कूल बस, यात्री, या खतरनाक सामग्री एंडोर्समेंट प्राप्त कर रहे हैं; यह एक-बार की आवश्यकता है, नियमित नवीनीकरण के लिए नहीं। स्रोत: FMCSA ELDT नियम (49 CFR Part 380), SD DPS द्वारा लागू।"},"98":{"q":"साउथ डकोटा Commercial Driver License नवीनीकृत किए जाने से पहले कितने समय तक मान्य रहता है?","options":["1 year","2 years","4 years","5 years"],"explanation":"एक साउथ डकोटा CDL पाँच वर्ष के लिए मान्य होता है और धारक के जन्मदिन पर समाप्त हो जाता है; धारक समाप्ति से 180 days पहले तक नवीनीकृत कर सकते हैं, आम तौर पर दृष्टि जाँच के साथ DPS परीक्षा केंद्र पर व्यक्तिगत रूप से। स्रोत: SD DPS Driver Licensing (नवीनीकरण मार्गदर्शन)।"}},"ar":{"0":{"q":"ما هو الحد الأقصى القانوني لعرض المركبة وحمولتها على طرق ساوث داكوتا السريعة بدون تصريح؟","options":["96 inches (8 feet)","102 inches (8 feet 6 inches)","108 inches (9 feet)","120 inches (10 feet)"],"explanation":"تحدد ساوث داكوتا الحد الأقصى لعرض أي مركبة، بما في ذلك حمولتها، بـ 102 inches (8 feet 6 inches). المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"1":{"q":"ما هو الحد الأقصى القانوني لارتفاع المركبة بما في ذلك حمولتها على طرق ساوث داكوتا السريعة؟","options":["13 feet 6 inches","13 feet","14 feet","15 feet"],"explanation":"تحدد ساوث داكوتا الحد الأقصى لارتفاع أي مركبة، بما في ذلك الحمولة، بـ 14 feet. المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"2":{"q":"في ساوث داكوتا، ما هو الحد الأقصى للارتفاع الذي يمكن أن تصل إليه قانونياً مركبة تحمل حمولة من بالات التبن؟","options":["14 feet","14 feet 6 inches","15 feet","16 feet"],"explanation":"في حين أن الحد العام للارتفاع هو 14 feet، تسمح ساوث داكوتا للمركبة التي تحمل حمولة من بالات التبن بأن يصل ارتفاعها إلى 15 feet. المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"3":{"q":"ما هو الحد الأقصى القانوني للوزن على المحور الفردي على طرق ساوث داكوتا السريعة؟","options":["18,000 pounds","20,000 pounds","22,400 pounds","34,000 pounds"],"explanation":"تحدد ساوث داكوتا وزن المحور الفردي بـ 20,000 pounds، بما يتوافق مع المعيار الفيدرالي. المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"4":{"q":"ما هو الحد الأقصى القانوني للوزن على مجموعة المحور المزدوج (التاندم) على طرق ساوث داكوتا السريعة؟","options":["32,000 pounds","33,000 pounds","34,000 pounds","36,000 pounds"],"explanation":"تحدد ساوث داكوتا وزن مجموعة المحور المزدوج (التاندم) بـ 34,000 pounds، بما يتوافق مع المعيار الفيدرالي. المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"5":{"q":"بدون تصريح خاص، ما هو الحد الأقصى لإجمالي وزن المركبة المسموح به على الطرق السريعة بين الولايات (Interstate) في ساوث داكوتا؟","options":["73,280 pounds","80,000 pounds","90,000 pounds","105,500 pounds"],"explanation":"الحد الأقصى لإجمالي الوزن على الطرق السريعة بين الولايات في ساوث داكوتا هو 80,000 pounds ما لم تكن المركبة حاصلة على تصريح سنوي Over 80,000 Pounds on Interstate. المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"6":{"q":"ما هو الحد الأقصى لطول نصف المقطورة (semitrailer) العاملة ضمن تركيبة شاحنة جر ونصف مقطورة في ساوث داكوتا؟","options":["48 feet","53 feet","57 feet","60 feet"],"explanation":"تسمح ساوث داكوتا بنصف مقطورة يصل طولها إلى 53 feet عند تشغيلها ضمن تركيبة شاحنة جر ونصف مقطورة. المصدر: SDCL 32-22-8.1 (Length limitations on trailers and semitrailers)."},"7":{"q":"بالنسبة لحمولة يتم نقلها في ساوث داكوتا، إلى أي مدى يمكن أن تمتد الحمولة خلف الجزء الخلفي من المركبة؟","options":["Not more than 3 feet","Not more than 4 feet","Not more than 6 feet","Not more than 8 feet"],"explanation":"لا يجوز أن تمتد الحمولة أو امتداداتها القابلة للسحب أكثر من 4 feet خلف المصد الخلفي أو الصندوق أو هيكل المركبة. المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"8":{"q":"في ساوث داكوتا، إلى أي مدى يمكن أن تمتد الحمولة خلف الجزء الأمامي من المركبة التي تحملها؟","options":["Not more than 2 feet","Not more than 3 feet","Not more than 4 feet","Not more than 5 feet"],"explanation":"لا يجوز أن تمتد الحمولة أكثر من 3 feet أمام المصد الأمامي أو الصندوق أو هيكل المركبة. المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"9":{"q":"ما هو الحد الأقصى للوزن الذي يمكن أن يتحمله إطار محور التوجيه في ساوث داكوتا، معبراً عنه لكل بوصة من عرض الإطار؟","options":["400 pounds per inch","500 pounds per inch","600 pounds per inch","650 pounds per inch"],"explanation":"تحدد ساوث داكوتا أحمال محور التوجيه ومحور الإطارات المزدوجة بـ 600 pounds per inch من عرض الإطار. المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"10":{"q":"بالنسبة للإطارات المركبة على محاور غير محاور التوجيه أو محاور الإطارات المزدوجة، ما هو الحد الأقصى لوزن الإطار لكل بوصة من عرض الإطار في ساوث داكوتا؟","options":["450 pounds per inch","500 pounds per inch","550 pounds per inch","600 pounds per inch"],"explanation":"تحدد ساوث داكوتا الإطارات على المحاور غير محاور التوجيه ومحاور الإطارات المزدوجة بـ 500 pounds per inch من عرض الإطار. المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"11":{"q":"تستخدم ساوث داكوتا صيغة وزن الجسر الإجمالي الفيدرالية (Bridge Gross Weight Formula) لتحديد وزن مجموعة المحاور. تحدد الصيغة الوزن الأقصى بناءً على أي من العوامل التالية؟","options":["العدد الإجمالي لمحاور المركبة فقط","المسافة بين المحاور الطرفية للمجموعة وعدد المحاور في تلك المجموعة","الوزن المسجل للمركبة وقوة المحرك الحصانية","عرض الإطار وحد السرعة المعلن للطريق السريع"],"explanation":"تطبق ساوث داكوتا صيغة الجسر الفيدرالية W = 500[(L x N)/(N-1) + 12N + 36]، حيث L هي المسافة بين المحاور الطرفية للمجموعة وN هو عدد المحاور في تلك المجموعة. المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"12":{"q":"يُسمح لمنتج زراعي في ساوث داكوتا ينقل محصولاً مَحصوداً ضمن مسافة 50 ميلاً من الحقل (وليس على طريق Interstate) بأي تسامح في الوزن يتجاوز الحدود القانونية؟","options":["5 percent over legal limits","10 percent over legal limits","15 percent over legal limits","لا يُسمح بأي تسامح"],"explanation":"تسمح ساوث داكوتا بما يصل إلى 10 percent فوق حدود الوزن القانونية عند نقل محصول محصود ضمن مسافة 50 ميلاً من الحقل المحصود، باستثناء نظام الطرق بين الولايات (Interstate). المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"13":{"q":"تسمح ساوث داكوتا بتسامح في الوزن قدره 5 percent فوق الحدود القانونية لبعض عمليات النقل إلى مخازن المزارع ونقل الماشية. ما هي قيود المسافة والطريق التي تنطبق؟","options":["ضمن 25 ميلاً من التحميل، بما في ذلك الطرق بين الولايات (Interstates)","ضمن 50 ميلاً من التحميل، ولكن ليس على الطرق بين الولايات (Interstates)","ضمن 100 ميل من التحميل، بما في ذلك الطرق بين الولايات (Interstates)","في أي مكان في الولاية، ولكن ليس على الطرق بين الولايات (Interstates)"],"explanation":"ينطبق تسامح الـ 5 percent للنقل إلى مخزن المزرعة أو لنقل الماشية ضمن مسافة 50 ميلاً من موقع التحميل ولا يُسمح به على نظام الطرق بين الولايات (Interstate) (ويُستثنى خلال قيود الحمولة الربيعية). المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Weight Regulations), sdtruckinfo.sd.gov."},"14":{"q":"على الطرق السريعة غير الـ Interstate في ساوث داكوتا، ما هو الحد الأقصى لإجمالي الوزن الذي يمكن أن تصل إليه بموجب تصريح مركبة تركيبية أطول (Longer Combination Vehicle) مُهيأة بشكل صحيح ولديها محاور كافية؟","options":["80,000 pounds","105,500 pounds","129,000 pounds","164,000 pounds"],"explanation":"تسمح ساوث داكوتا لبعض المركبات التركيبية الأطول (Longer Combination Vehicles) التي تمتلك محاور كافية بأن يصل إجمالي وزنها إلى 129,000 pounds على الطرق غير الـ Interstate، شريطة استيفاء حدود المحور والإطار وصيغة الجسر. المصدر: SDCL 32-22-16/32-22-16.1 and ARSD 70:03:01:61."},"15":{"q":"ما هو النظام الإلكتروني في ساوث داكوتا المستخدم للتقدم بطلب والحصول على تصاريح المركبات ذات الحجم الزائد/الوزن الزائد؟","options":["The IRP Clearinghouse","The SDAPS Permitting System","The FMCSA Portal","The UCR National Registry"],"explanation":"يتم الحصول على تصاريح الحجم الزائد والوزن الزائد في ساوث داكوتا من خلال البوابة الإلكترونية SDAPS (South Dakota Automated Permitting System). المصدر: SD Truck Information Permitting pages, sdtruckinfo.sd.gov; SDAPS at sdaps.sd.gov."},"16":{"q":"متى يكون تصريح الحجم الزائد/الوزن الزائد الصادر عن ولاية ساوث داكوتا مطلوباً بشكل عام لحمولة على الطرق السريعة للولاية؟","options":["فقط عندما تكون الحمولة مواد خطرة","عند نقل حمولة غير قابلة للتقسيم تتجاوز حدود الحجم أو الوزن أو كليهما","لأي مركبة تجارية يزيد تصنيف وزنها الإجمالي GVWR عن 26,001 pounds","فقط عند عبور حدود ولاية إلى داخل ساوث داكوتا"],"explanation":"يُطلب التصريح لنقل مركبة على الطرق السريعة للولاية تحمل حمولة غير قابلة للتقسيم تتجاوز الحدود القانونية للحجم أو الوزن أو الحجم والوزن معاً. المصدر: SD Truck Information Permitting pages, sdtruckinfo.sd.gov."},"17":{"q":"يسمح تصريح Over 80,000 Pounds on Interstate في ساوث داكوتا بوزن إجمالي إضافي، ولكن لا يزال يجب على المركبة ألا تتجاوز أياً مما يلي؟","options":["وزن محورها القانوني، أو وزن إطارها القانوني، أو وزن صيغة الجسر (Bridge Formula)","سرعة 55 miles per hour","طول إجمالي قدره 53 feet","السفر خلال ساعات النهار فقط"],"explanation":"لا يسمح تصريح Over 80,000 Pounds on Interstate للمركبة بتجاوز وزن محورها القانوني، أو وزن إطارها القانوني، أو الوزن المسموح به بموجب صيغة وزن الجسر الإجمالي (Bridge Gross Weight Formula). المصدر: SD Truck Information Permitting pages, sdtruckinfo.sd.gov; SDCL 32-22-42."},"18":{"q":"في ساوث داكوتا، يُقاس حد الطول الذي ينطبق على تركيبة شاحنة جر ونصف مقطورة بطول المقطورة بدلاً من الطول الإجمالي. بالنسبة لتركيبة نصف مقطورة-مقطورة (باستثناء شاحنة الجر)، ما هو الحد الأقصى للطول المجمّع؟","options":["65 feet، مع عدم تجاوز أي وحدة 28.5 feet","75 feet، مع عدم تجاوز أي وحدة 40 feet","81.5 feet، مع عدم تجاوز أي وحدة 45 feet","85 feet، مع عدم تجاوز أي وحدة 48 feet"],"explanation":"لا يجوز أن تتجاوز تركيبة نصف مقطورة-نصف مقطورة أو نصف مقطورة-مقطورة (باستثناء شاحنة الجر) 81 feet 6 inches، شريطة ألا تتجاوز أي وحدة 45 feet. المصدر: SDCL 32-22-8.1."},"19":{"q":"بموجب إعفاء الآلات الزراعية في ساوث داكوتا، يجوز للمزارع الذي يشغّل آلات زراعية أن يتجاوز حد العرض البالغ 102 inches خلال ساعات النهار، باستثناء أي من الطرق التالية؟","options":["جميع الطرق السريعة المعبّدة للولاية","الطرق السريعة بين الولايات (Interstate)","طرق المقاطعات الحصوية","الطرق داخل حدود المدينة"],"explanation":"ليس للآلات الزراعية التي يشغّلها مزارع أي حد للعرض خلال ساعات النهار، باستثناء الطرق السريعة بين الولايات (Interstate)، حيث تنطبق الحدود القياسية. المصدر: SD Commercial and Agricultural Vehicle Handbook, Chapter 5 (Vehicle Size Regulations), sdtruckinfo.sd.gov."},"20":{"q":"في ساوث داكوتا، ما هو الحد الأدنى للعمر للحصول على CDL لتشغيل مركبة آلية تجارية في التجارة بين الولايات (INTERSTATE)؟","options":["18 years old","19 years old","21 years old","25 years old"],"explanation":"تتبع ساوث داكوتا القاعدة الفيدرالية: يجب أن يكون عمر السائق 21 سنة على الأقل للحصول على CDL للتجارة بين الولايات. يمكن إصدار CDL للسائقين من 18-20 لتشغيل داخل الولاية فقط. المصدر: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 391.11."},"21":{"q":"يجوز إصدار CDL لمتقدم في ساوث داكوتا تتراوح أعماره بين 18 و20 عاماً، ولكنه مقيد بأي نوع من التشغيل؟","options":["التجارة داخل الولاية فقط (Intrastate) (ضمن ساوث داكوتا)","التجارة بين الولايات فقط (Interstate)","المركبات الزراعية فقط","القيادة النهارية فقط"],"explanation":"تسمح ساوث داكوتا للمتقدمين الذين تتراوح أعمارهم بين 18-20 بالحصول على CDL صالح للتجارة داخل الولاية فقط (القيادة ضمن ساوث داكوتا). يتطلب التشغيل بين الولايات سن 21 عاماً. المصدر: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov)."},"22":{"q":"بموجب تصنيفات CDL في ساوث داكوتا، أي تركيبة تُعرّف رخصة الفئة A (CLASS A)؟","options":["أي مركبة فردية يتجاوز تصنيف وزنها الإجمالي GVWR قيمة 26,000 pounds","أي تركيبة من المركبات يتجاوز تصنيف وزنها الإجمالي المجمّع GCWR قيمة 26,000 pounds حيث تتجاوز الوحدة المقطورة تصنيف وزنها الإجمالي GVWR قيمة 10,000 pounds","أي مركبة تحمل لوحات تحذيرية للمواد الخطرة","أي مركبة مصممة لنقل 16 راكباً أو أكثر"],"explanation":"تُعرّف ساوث داكوتا الفئة A بأنها أي تركيبة من المركبات يتجاوز تصنيف وزنها الإجمالي المجمّع (GCWR) قيمة 26,000 lbs، شريطة أن يتجاوز تصنيف الوزن الإجمالي للمركبة المقطورة GVWR قيمة 10,000 lbs. المصدر: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov)."},"23":{"q":"كيف تُعرّف ساوث داكوتا رخصة السائق التجاري من الفئة B (CLASS B)؟","options":["تركيبة يتجاوز تصنيف وزنها الإجمالي المجمّع GCWR قيمة 26,000 pounds وتقطر وحدة تتجاوز 10,000 pounds","مركبة فردية يتجاوز تصنيف وزنها الإجمالي GVWR قيمة 26,000 pounds، أو مثل هذه المركبة وهي تقطر وحدة لا تتجاوز 10,000 pounds","أي مركبة تحمل نفايات خطرة","أي مركبة يقل تصنيف وزنها الإجمالي GVWR عن 10,000 pounds"],"explanation":"تُعرّف ساوث داكوتا الفئة B بأنها أي مركبة فردية يتجاوز تصنيف وزنها الإجمالي GVWR قيمة 26,000 lbs، أو أي مركبة من هذا القبيل تقطر مركبة لا يتجاوز تصنيف وزنها الإجمالي GVWR قيمة 10,000 lbs. المصدر: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov)."},"24":{"q":"في ساوث داكوتا، تنطبق رخصة CDL من الفئة C (CLASS C) على مركبة لا تستوفي شروط الفئة A أو B ولكنها إما تحمل لوحات تحذيرية للمواد الخطرة أو مصممة لنقل كم شخصاً؟","options":["8 أو أكثر، بما في ذلك السائق","12 أو أكثر، بما في ذلك السائق","16 أو أكثر، بما في ذلك السائق","24 أو أكثر، بما في ذلك السائق"],"explanation":"تُعرّف ساوث داكوتا الفئة C بأنها مركبة فردية أو تركيبة لا تستوفي شروط الفئة A أو B ويُطلب منها إما حمل لوحات تحذيرية للمواد الخطرة أو أنها مصممة لنقل 16 راكباً أو أكثر، بما في ذلك السائق. المصدر: SD Motor Carrier Handbook, Ch. 8, CDL Classifications (sdtruckinfo.sd.gov)."},"25":{"q":"أي رمز تصديق (endorsement) تضعه ساوث داكوتا على CDL للسائق الذي ينقل مواد خطرة (HAZARDOUS MATERIALS) تحمل لوحات تحذيرية (وليست في خزان)؟","options":["N","T","H","P"],"explanation":"تستخدم ساوث داكوتا تصديق H لنقل المواد الخطرة الحاملة للوحات تحذيرية. تصديق N مخصص لمركبات الخزانات، وT للمقطورات المزدوجة/الثلاثية، وP للركاب. المصدر: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Ch. 8 (sdtruckinfo.sd.gov)."},"26":{"q":"قبل أن تضيف ساوث داكوتا تصديق المواد الخطرة HazMat (H) إلى CDL، يجب على المتقدم إكمال أي خطوة فيدرالية بالإضافة إلى اجتياز اختبار المعرفة؟","options":["تقييم تهديد أمني من TSA يشمل أخذ البصمات","تدريب مهني لمدة 100 ساعة","موافقة طبية بعد جراحة عيون","اختبار طريق منفصل في مركبة خزان"],"explanation":"لا يمكن لساوث داكوتا إصدار تصديق المواد الخطرة HazMat حتى يجتاز المتقدم برنامج تقييم تهديد تصديق المواد الخطرة الفيدرالي التابع لـ TSA، والذي يتطلب أخذ البصمات وفحص الخلفية، بالإضافة إلى اختبار المعرفة الكتابي. المصدر: TSA HME program; SD DPS CDL Endorsements; 49 CFR 1572."},"27":{"q":"تصديق الخزان (N) في ساوث داكوتا مطلوب للمركبات التي تنقل سوائل أو غازات في خزان دائم مصنّف بسعة 119 gallons أو أكثر، أو خزانات محمولة بسعة مصنّفة إجمالية لا تقل عن كم جالوناً؟","options":["500 gallons","750 gallons","1,000 gallons","1,500 gallons"],"explanation":"تتطلب ساوث داكوتا تصديق الخزان (N) للخزانات الدائمة المصنّفة بسعة 119 gallons (450 liters) أو أكثر، أو الخزانات المحمولة بسعة مصنّفة إجمالية تبلغ 1,000 gallons أو أكثر. المصدر: SD CDL Manual / SD DPS CDL Endorsements; FMCSA definition of tank vehicle, 49 CFR 383.5."},"28":{"q":"السائق في ساوث داكوتا الذي ينقل مواد خطرة في مركبة خزان (IN A TANK VEHICLE) ينبغي أن يحمل أي تصديق مدمج؟","options":["T","X","S","P"],"explanation":"تستخدم ساوث داكوتا تصديق X لتمثيل تركيبة تصديق الخزان (N) والمواد الخطرة (H) للسائقين الذين ينقلون مواد خطرة في مركبة خزان. المصدر: SD Motor Carrier Handbook, Ch. 8, CDL Classifications & Endorsements (sdtruckinfo.sd.gov)."},"29":{"q":"أي تصديق تتطلبه ساوث داكوتا للسائق الذي يقطر مقطورات مزدوجة أو ثلاثية (DOUBLE or TRIPLE)؟","options":["P","N","T","H"],"explanation":"تتطلب ساوث داكوتا تصديق T للمقطورات المزدوجة والثلاثية؛ يجب على المتقدم اجتياز اختبار معرفة خاص حول مشكلات قطر المقطورات المتعددة. لا يوجد اختبار مهارات منفصل لتصديق T. المصدر: SD DPS CDL Endorsements; SD Motor Carrier Handbook, Ch. 8."},"30":{"q":"للحصول على تصديق الركاب (P) في ساوث داكوتا، يجب على السائق اجتياز اختبار معرفة خاص وماذا أيضاً؟","options":["اختبار مهارات في مركبة ركاب","مرافقة في القيادة لمدة 50 ساعة","فحص خلفية من TSA","اختبار رؤية منفصل في حافلة"],"explanation":"تتطلب ساوث داكوتا من السائقين الذين يسعون للحصول على تصديق P (مركبات مصممة لـ 16 راكباً أو أكثر بما في ذلك السائق) اجتياز كل من اختبار معرفة خاص واختبار مهارات يُجرى في مركبة ركاب. المصدر: SD DPS CDL Endorsements; SD CDL Manual."},"31":{"q":"في ساوث داكوتا، قبل أن يتم إصدار تصديق الحافلة المدرسية (S) للسائق، يجب أن يحمل CDL مسبقاً أي تصديق آخر؟","options":["تصديق H (المواد الخطرة HazMat)","تصديق T (المقطورات المزدوجة/الثلاثية)","تصديق P (الركاب)","تصديق N (الخزان)"],"explanation":"تتطلب ساوث داكوتا تصديق الركاب (P) كشرط مسبق لتصديق الحافلة المدرسية (S)؛ يجب على المتقدم لتصديق S أيضاً اجتياز اختبار معرفة الحافلة المدرسية واختبار مهارات. المصدر: SD DPS CDL Endorsements; SD CDL Manual."},"32":{"q":"لكم من الوقت يكون تصريح المتعلم التجاري (CLP) في ساوث داكوتا صالحاً؟","options":["60 days","6 months","1 year","5 years"],"explanation":"يُصدر CLP في ساوث داكوتا لمدة سنة واحدة للتدريب خلف عجلة القيادة. المصدر: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications (sdtruckinfo.sd.gov); 49 CFR 383.25."},"33":{"q":"بعد الحصول على تصريح المتعلم التجاري (CLP)، كم يجب أن ينتظر المتقدم في ساوث داكوتا قبل أن يصبح مؤهلاً لإجراء اختبار مهارات CDL؟","options":["At least 7 days","At least 14 days","At least 30 days","At least 90 days"],"explanation":"تطبق ساوث داكوتا القاعدة الفيدرالية التي تنص على أنه يجب الاحتفاظ بـ CLP لمدة 14 days على الأقل قبل أن يصبح حامله مؤهلاً لإجراء اختبار مهارات CDL (اختبار الطريق). المصدر: SD DPS Driver Licensing; 49 CFR 383.25(e)."},"34":{"q":"أثناء القيادة بموجب CLP في ساوث داكوتا، يجب أن يكون حامل التصريح برفقة شخص يحمل CDL صالحاً من الفئة المناسبة ويجلس أين؟","options":["في المقعد الأمامي بجوار السائق","في أي مكان في الكابينة","في مركبة مرافقة منفصلة","في مقصورة النوم"],"explanation":"يجوز لحامل CLP في ساوث داكوتا تشغيل مركبة آلية تجارية فقط عندما يكون برفقة شخص يحمل CDL صالحاً من الفئة/التصديقات المناسبة ويشغل المقعد الأمامي بجوار السائق. المصدر: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications; 49 CFR 383.25(a)."},"35":{"q":"أي مجموعة من المستندات يجب على المتقدم لـ CDL في ساوث داكوتا تقديمها في محطة اختبار السائقين لإثبات الأهلية؟","options":["بطاقة الضمان الاجتماعي فقط","إثبات الهوية/الوجود القانوني، ورقم الضمان الاجتماعي، والإقامة في ساوث داكوتا","جواز سفر وبطاقة ائتمان","شهادة الثانوية العامة وسند ملكية مركبة"],"explanation":"تتطلب ساوث داكوتا إثبات الهوية والوجود القانوني (تاريخ الميلاد)، ورقم الضمان الاجتماعي، ومستندين يثبتان الإقامة في ساوث داكوتا؛ ويجب أن تكون المستندات أصلية وليست نسخاً مصورة. المصدر: SD DPS Required Driver's Licensing Documents (dps.sd.gov)."},"36":{"q":"معظم المتقدمين لـ CDL في ساوث داكوتا الذين حصلوا على CLP بعد February 7, 2022 يجب عليهم إكمال تدريب السائق المبتدئ (ELDT) من مزود مدرج أين؟","options":["الموقع الإلكتروني لأي شركة نقل خاصة","سجل مزودي التدريب التابع لـ FMCSA (Training Provider Registry, TPR)","وزير خارجية ولاية ساوث داكوتا (Secretary of State)","مكتب مأمور المقاطعة المحلي"],"explanation":"تتطلب قواعد ELDT الفيدرالية المعتمدة في ساوث داكوتا تدريباً نظرياً وخلف عجلة القيادة من جهة مدرجة في سجل مزودي التدريب التابع لـ FMCSA (tpr.fmcsa.dot.gov) للمتقدمين الذين حصلوا على CLP في أو بعد February 7, 2022، قبل إجراء اختبار المهارات. المصدر: FMCSA ELDT; SD DPS CDL information."},"37":{"q":"أي فئة من فئات التصديق الذاتي الطبي تنطبق على سائق في ساوث داكوتا يعمل في التجارة بين الولايات ويجب أن يستوفي متطلب البطاقة الطبية الفيدرالية DOT؟","options":["Excepted Interstate (EI)","Non-Excepted Interstate (NI)","Excepted Intrastate (EA)","Non-Excepted Intrastate (NA)"],"explanation":"تغطي فئة Non-Excepted Interstate (NI) السائقين العاملين في التجارة بين الولايات الذين يجب أن يستوفوا متطلب الشهادة الطبية/شهادة الفاحص الطبي الفيدرالية DOT. EI هي بين الولايات معفاة، وNA/EA هي فئات داخل الولاية. المصدر: 49 CFR 383.71; SD DPS Driver Licensing self-certification."},"38":{"q":"المتقدم لـ CDL أو CLP في ساوث داكوتا الذي يصدّق ذاتياً على أنه Non-Excepted Interstate يجب أن يقدم شهادة طبية من فاحص مدرج أين؟","options":["السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA (National Registry of Certified Medical Examiners)","أي عيادة رعاية عاجلة بدون موعد مسبق","قائمة وزارة الصحة في ساوث داكوتا (Department of Health)","مستشفى من اختيار السائق"],"explanation":"تتطلب ساوث داكوتا من السائقين العاملين بين الولايات (غير المعفيين) ومشغلي الحافلات المدرسية الحصول على شهادة من أخصائي طبي مدرج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA، ويجب أن تكون الشهادة محفوظة لدى جهة ترخيص السائقين (Driver Licensing). المصدر: SD Motor Carrier Handbook, Ch. 8, CDL Qualifications; 49 CFR 391.41."},"39":{"q":"لكم من السنوات تُصدر رخصة السائق التجاري (CDL) في ساوث داكوتا قبل أن يلزم تجديدها؟","options":["3 years","4 years","5 years","8 years"],"explanation":"تُصدر ساوث داكوتا رخص CDL لمدة 5 years، وبعدها يجب تجديد الرخصة. (تُصدر الرخص غير التجارية في ساوث داكوتا لمدد أطول، لكن رخص CDL مدتها 5 years.) المصدر: SD DPS Driver Licensing fees/information (dps.sd.gov)."},"40":{"q":"في ساوث داكوتا، ما هو الحد الأقصى لتركيز الكحول في الدم (BAC) الذي يجوز عنده قانونياً للشخص تشغيل مركبة آلية تجارية (CMV)؟","options":["0.04 percent","0.08 percent","0.02 percent","0.10 percent"],"explanation":"تتبع ساوث داكوتا المعيار الفيدرالي للمركبات الآلية التجارية: من غير القانوني تشغيل مركبة آلية تجارية بتركيز كحول في الدم BAC قدره 0.04 percent أو أكثر، أي نصف حد 0.08 المطبق على السائقين غير التجاريين. المصدر: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"41":{"q":"تبيّن أن سائق CDL في ساوث داكوتا يشغّل مركبة آلية تجارية بوجود كمية قابلة للكشف من الكحول أقل من 0.04 percent BAC. ما هي العاقبة الفورية؟","options":["إيقاف عن الخدمة لمدة 24 hours","إلغاء أهلية CDL لمدة سنة واحدة","إلغاء أهلية CDL لمدة 60 يوماً","فقدان دائم لـ CDL"],"explanation":"في ساوث داكوتا، يُوقَف سائق المركبة الآلية التجارية الذي لديه أي كحول قابل للكشف أقل من 0.04 percent عن الخدمة لمدة 24 hours بدلاً من إلغاء أهليته. أما تركيز BAC قدره 0.04 أو أكثر فيؤدي إلى إلغاء أهلية لمدة سنة واحدة. المصدر: South Dakota CDL Manual / SD Truck Information Motor Carrier Handbook Ch. 8."},"42":{"q":"بموجب قانون الموافقة الضمنية (implied consent) في ساوث داكوتا، على ماذا يوافق السائق بمجرد تشغيله أي مركبة على طريق عام؟","options":["الخضوع لاختبار كيميائي للكحول أو المخدرات","حمل شهادة فاحص طبي","التنازل عن الحق في جلسة استماع بشأن الرخصة","الفحص العشوائي للمخدرات من قبل صاحب العمل"],"explanation":"يعني قانون الموافقة الضمنية في ساوث داكوتا أن أي شخص يقود على طريق عام قد وافق على إجراء اختبار كيميائي للكحول أو المخدرات. ويحمل الرفض عقوباته الخاصة حتى لو لم يتم تناول أي كحول. المصدر: South Dakota CDL Manual; SDCL 32-23-10 (implied consent)."},"43":{"q":"بالنسبة لأول مخالفة كبرى (major offense) (مثل تركيز BAC قدره 0.04+ في مركبة آلية تجارية) لا تتعلق بمواد خطرة تحمل لوحات تحذيرية، لكم من الوقت تُلغى أهلية حامل CDL في ساوث داكوتا؟","options":["1 year","60 days","3 years","مدى الحياة"],"explanation":"تؤدي أول مخالفة كبرى في ساوث داكوتا إلى إلغاء أهلية CDL لمدة سنة واحدة كحد أدنى. وترتفع المدة إلى ثلاث سنوات إذا وقعت المخالفة أثناء نقل مواد خطرة تحمل لوحات تحذيرية. المصدر: South Dakota CDL Manual (49 CFR 383.51)."},"44":{"q":"لكم من الوقت تُلغى أهلية سائق CDL في ساوث داكوتا بسبب أول مخالفة كبرى ارتُكبت أثناء نقل مواد خطرة يُطلب أن تحمل لوحات تحذيرية؟","options":["3 years","1 year","120 days","مدى الحياة"],"explanation":"في ساوث داكوتا، يُرفع إلغاء الأهلية القياسي لمدة سنة واحدة لأول مخالفة كبرى إلى ثلاث سنوات عندما تقع المخالفة أثناء تشغيل مركبة آلية تجارية تنقل مواد خطرة تحمل لوحات تحذيرية. المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"45":{"q":"ما هي مدة إلغاء الأهلية في ساوث داكوتا لثاني مخالفة كبرى ناشئة عن حادثة منفصلة؟","options":["مدى الحياة","10 years","3 years","1 year"],"explanation":"تؤدي ثاني مخالفة كبرى (مثل قيادة ثانية تحت تأثير الكحول DUI في أي مركبة، أو رفض الاختبار، أو مغادرة مكان الحادث) ناشئة عن حادثة منفصلة إلى إلغاء أهلية CDL مدى الحياة في ساوث داكوتا، رغم أن إعادة المنح قد تكون ممكنة بعد 10 years في بعض الحالات. المصدر: South Dakota CDL Manual (49 CFR 383.51)."},"46":{"q":"يرفض سائق CDL في ساوث داكوتا الخضوع لاختبار كيميائي للكحول. ما هي الحد الأدنى لمدة إلغاء الأهلية؟","options":["At least 1 year","60 days","90 days","30 days"],"explanation":"يُعامَل رفض الخضوع لاختبار الكحول/المخدرات المطلوب كمخالفة كبرى في ساوث داكوتا ويؤدي إلى إلغاء أهلية لمدة سنة واحدة على الأقل، مثل تركيز BAC قدره 0.04+. ويمكن أن يفقد السائق CDL حتى لو لم يكن قد شرب. المصدر: South Dakota CDL Manual; SDCL implied consent provisions."},"47":{"q":"لكم من الوقت تُلغى أهلية سائق CDL في ساوث داكوتا عند الإدانة بمخالفتين مروريتين خطيرتين (serious traffic violations) خلال فترة 3 سنوات؟","options":["60 days","30 days","120 days","1 year"],"explanation":"تؤدي مخالفتان مروريتان خطيرتان في حادثتين منفصلتين خلال ثلاث سنوات إلى إلغاء أهلية لمدة 60 days في ساوث داكوتا. وتضيف مخالفة ثالثة خلال ثلاث سنوات 120 days. المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"48":{"q":"لكم من الوقت تُلغى أهلية سائق CDL في ساوث داكوتا عند الإدانة بثلاث مخالفات مرورية خطيرة خلال فترة 3 سنوات؟","options":["120 days","60 days","90 days","1 year"],"explanation":"تؤدي ثالث مخالفة مرورية خطيرة في حوادث منفصلة خلال ثلاث سنوات إلى إلغاء أهلية لمدة 120 days في ساوث داكوتا (بالإضافة إلى الـ 60 days للمخالفة الثانية). المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"49":{"q":"أي مما يلي يُصنّف كمخالفة مرورية خطيرة (SERIOUS) لحامل CDL في ساوث داكوتا؟","options":["تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد المعلن","القيادة بتركيز BAC قدره 0.04 أو أكثر","رفض اختبار كيميائي","مغادرة مكان حادث"],"explanation":"في ساوث داكوتا، يُعد تجاوز السرعة بمقدار 15 mph أو أكثر فوق الحد مخالفة مرورية خطيرة. أما المخالفات الأخرى المذكورة فهي مخالفات كبرى (MAJOR) تحمل إلغاء أهلية لمدة سنة واحدة أو مدى الحياة، وليست ضمن فئة المخالفة الخطيرة. المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"50":{"q":"أي مخالفة لا تُعد ضمن المخالفات المرورية الخطيرة في ساوث داكوتا لأغراض CDL؟","options":["تشغيل مركبة آلية تجارية بتركيز BAC قدره 0.04+","اتباع مركبة أخرى عن قرب شديد","تغيير المسار بشكل غير سليم أو متقلب","قيادة مركبة آلية تجارية دون حمل CDL"],"explanation":"يُعد تشغيل مركبة آلية تجارية بتركيز BAC قدره 0.04+ مخالفة كبرى (MAJOR) (إلغاء أهلية لمدة سنة واحدة)، وليست مخالفة مرورية خطيرة. أما الاتباع عن قرب شديد، وتغيير المسار غير السليم، وقيادة مركبة آلية تجارية دون CDL فهي مخالفات مرورية خطيرة. المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"51":{"q":"ما هي مدة إلغاء الأهلية لأول مخالفة عند تقاطع السكة الحديدية مع الطريق السريع (railroad-highway grade crossing) من قبل سائق CDL في ساوث داكوتا؟","options":["60 days","30 days","120 days","1 year"],"explanation":"تؤدي أول مخالفة عند تقاطع السكة الحديدية مع الطريق السريع إلى إلغاء أهلية لمدة 60 days في ساوث داكوتا. والمخالفة الثانية خلال ثلاث سنوات تكون 120 days والثالثة سنة واحدة. المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"52":{"q":"ما هي مدة إلغاء الأهلية لثاني مخالفة عند تقاطع السكة الحديدية مع الطريق السريع خلال 3 سنوات لسائق CDL في ساوث داكوتا؟","options":["120 days","60 days","90 days","1 year"],"explanation":"تؤدي ثاني مخالفة عند تقاطع السكة الحديدية مع الطريق خلال ثلاث سنوات إلى إلغاء أهلية لمدة 120 days في ساوث داكوتا. والمخالفة الثالثة خلال ثلاث سنوات تؤدي إلى إلغاء أهلية لمدة سنة واحدة. المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"53":{"q":"ما هي مدة إلغاء الأهلية لثالث مخالفة عند تقاطع السكة الحديدية مع الطريق السريع خلال 3 سنوات في ساوث داكوتا؟","options":["1 year","120 days","180 days","60 days"],"explanation":"تؤدي ثالث مخالفة عند تقاطع السكة الحديدية مع الطريق خلال فترة ثلاث سنوات إلى إلغاء أهلية CDL لمدة سنة واحدة في ساوث داكوتا. المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"54":{"q":"ما هو الحد الأدنى لإلغاء الأهلية لأول مخالفة لأمر الإيقاف عن الخدمة (out-of-service order) من قبل سائق CDL في ساوث داكوتا (بدون مواد خطرة أو ركاب)؟","options":["180 days","90 days","60 days","30 days"],"explanation":"تؤدي أول إدانة بمخالفة أمر الإيقاف عن الخدمة إلى إلغاء أهلية لمدة 180 days على الأقل (تصل إلى سنة واحدة) في ساوث داكوتا. ويرتفع الحد الأدنى إلى 3 سنوات إذا كانت هناك مواد خطرة/ركاب. المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"55":{"q":"يرتكب سائق CDL في ساوث داكوتا ثاني مخالفة لأمر الإيقاف عن الخدمة خلال 10 سنوات (بدون مواد خطرة أو ركاب). ما هي مدة إلغاء الأهلية؟","options":["2 years","1 year","180 days","3 years"],"explanation":"تؤدي ثاني مخالفة لأمر الإيقاف عن الخدمة في حوادث منفصلة خلال 10 سنوات إلى إلغاء أهلية لمدة سنتين (2 years) في ساوث داكوتا. والمخالفة الثالثة خلال 10 سنوات تكون 3 سنوات (3 years). المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"56":{"q":"استخدام مركبة آلية تجارية في ارتكاب جناية تتعلق بتصنيع أو توزيع مادة خاضعة للرقابة يؤدي إلى أي إلغاء للأهلية في ساوث داكوتا؟","options":["مدى الحياة دون إعادة منح","1 year","3 years","10 سنوات ثم إعادة المنح"],"explanation":"يؤدي استخدام مركبة آلية تجارية لارتكاب جناية تتعلق بتصنيع أو توزيع أو صرف مادة خاضعة للرقابة إلى إلغاء أهلية CDL مدى الحياة دون إمكانية إعادة المنح إطلاقاً في ساوث داكوتا. المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8 (49 CFR 383.51)."},"57":{"q":"بموجب القواعد الفيدرالية المطبقة في ساوث داكوتا، كم عدد إدانات إرسال الرسائل النصية (texting) أثناء قيادة مركبة آلية تجارية خلال 3 سنوات التي تؤدي إلى إلغاء أهلية لمدة 120 يوماً؟","options":["3 or more","2","5","4"],"explanation":"تؤدي مخالفتان لإرسال الرسائل النصية خلال ثلاث سنوات إلى إلغاء أهلية لمدة 60 days، وثلاث مخالفات أو أكثر إلى إلغاء أهلية لمدة 120 days لسائقي CDL في ساوث داكوتا. كما يُعد إرسال الرسائل النصية أثناء قيادة مركبة آلية تجارية مخالفة مرورية خطيرة. المصدر: South Dakota CDL Manual (49 CFR 392.80 / 383.51)."},"58":{"q":"بالنسبة لسائق CDL في ساوث داكوتا، استخدام هاتف محمول يدوي أثناء تشغيل مركبة آلية تجارية يُوصف على أفضل وجه بأنه أي نوع من المخالفات؟","options":["مخالفة مرورية خطيرة","مخالفة كبرى (إلغاء أهلية لمدة سنة واحدة)","مخالفة لأمر الإيقاف عن الخدمة","مخالفة معدات غير قابلة للإبلاغ"],"explanation":"يُعد استخدام هاتف محمول يدوي أثناء قيادة مركبة آلية تجارية مخالفة مرورية خطيرة في ساوث داكوتا؛ مخالفتان خلال 3 سنوات تؤديان إلى إلغاء أهلية لمدة 60 days وثلاث مخالفات تؤدي إلى 120 days. المصدر: South Dakota CDL Manual (49 CFR 392.82 / 383.51)."},"59":{"q":"خلال كم يوماً يجب على حامل CDL في ساوث داكوتا إخطار صاحب عمله بعد الإدانة بمخالفة مرورية (بخلاف الوقوف) في أي مركبة؟","options":["30 days","10 days","15 days","60 days"],"explanation":"تتطلب ساوث داكوتا من حامل CDL إخطار صاحب عمله خلال 30 days من الإدانة بأي مخالفة مرورية (باستثناء الوقوف)، في أي ولاية وفي أي مركبة. المصدر: South Dakota CDL Manual / Motor Carrier Handbook Ch. 8."},"60":{"q":"بموجب قانون \"التنحّي جانبًا\" (Move Over) في ولاية ساوث داكوتا (المُحدَّث في 1 يوليو 2025)، على أي مسافة قبل مركبة متوقفة تعرض أضواء تحذيرية كهرمانية أو صفراء أو زرقاء يجب على السائق البدء في الاستجابة؟","options":["100 قدم","200 قدم","300 قدم","500 قدم"],"explanation":"يُلزِم القسم SDCL 32-31-6.1 السائقين باتخاذ إجراء على بُعد 300 قدم على الأقل قبل المركبة. المصدر: SDCL 32-31-6.1؛ قانون SDDOT للتنحّي جانبًا (سارٍ اعتبارًا من 1 يوليو 2025)."},"61":{"q":"على طريق سريع متعدد الحارات في ساوث داكوتا، ماذا يتطلب قانون التنحّي جانبًا عند الاقتراب من مركبة متوقفة على الكتف مع وميض أضواء التحذير؟","options":["التوقف تمامًا حتى يتم إطفاء الأضواء","الانتقال إلى الحارة الأبعد عن المركبة والمتابعة بحذر","التباطؤ إلى 30 ميلاً في الساعة والبقاء في الحارة اليمنى","استخدام البوق والمرور بالسرعة المُعلنة"],"explanation":"على طريق به حارتان أو أكثر في نفس الاتجاه، يُلزِم القسم SDCL 32-31-6.1 السائق بالانتقال إلى الحارة الأبعد عن المركبة المتوقفة على بُعد 300 قدم على الأقل قبلها والمتابعة بحذر. المصدر: SDCL 32-31-6.1؛ SDDOT."},"62":{"q":"على طريق سريع ذي حارتين في ساوث داكوتا حيث يتعذّر التنحّي جانبًا، يتطلب قانون التنحّي جانبًا من السائق التباطؤ بمقدار لا يقل عن كم تحت حد السرعة المُعلن عند المرور بمركبة عليها أضواء تحذيرية على الكتف؟","options":["10 ميل في الساعة على الأقل تحت الحد المُعلن","15 ميلاً في الساعة على الأقل تحت الحد المُعلن","20 ميلاً في الساعة على الأقل تحت الحد المُعلن","25 ميلاً في الساعة على الأقل تحت الحد المُعلن"],"explanation":"على طريق ذي حارتين، يُلزِم القسم SDCL 32-31-6.1 بالتباطؤ إلى سرعة تقل بمقدار 20 ميلاً في الساعة على الأقل عن الحد المُعلن (أو 5 ميل في الساعة إذا كان الحد 20 ميلاً في الساعة أو أقل). المصدر: SDCL 32-31-6.1؛ SDDOT."},"63":{"q":"ما فئات المركبات المتوقفة المشمولة بالحماية بموجب قانون التنحّي جانبًا المُوسَّع في ساوث داكوتا؟","options":["مركبات إنفاذ القانون المُميَّزة فقط","سيارات الإسعاف وشاحنات الإطفاء فقط","أي مركبة على الكتف تعرض أضواء وامضة كهرمانية أو صفراء أو زرقاء، بما في ذلك شاحنات السحب ومركبات الصيانة والمركبات المعطّلة","المركبات التي تعرض أضواء طوارئ حمراء وزرقاء فقط"],"explanation":"يشمل توسيع 1 يوليو 2025 للقسم SDCL 32-31-6.1 أي مركبة على الكتف تعرض أضواء تحذيرية وامضة كهرمانية أو صفراء أو زرقاء، بما في ذلك شاحنات السحب وصيانة الطرق السريعة والسائقون المعطّلون. المصدر: SDCL 32-31-6.1؛ SDDOT."},"64":{"q":"على طريق سريع ذي حارتين في ساوث داكوتا، عند مقابلة أو تجاوز حافلة مدرسية تومض أضواؤها التحذيرية الكهرمانية، يجب على السائق خفض السرعة إلى ما لا يزيد عن كم؟","options":["35 ميلاً في الساعة","25 ميلاً في الساعة","20 ميلاً في الساعة","15 ميلاً في الساعة"],"explanation":"يتطلب القسم SDCL 32-32-6 من السائق خفض السرعة إلى 15 ميلاً في الساعة أو أقل عندما تومض أضواء التنبيه الكهرمانية للحافلة المدرسية. المصدر: SDCL 32-32-6."},"65":{"q":"عندما تتوقف حافلة مدرسية في ساوث داكوتا على طريق ذي حارتين مع وميض أضواء الإشارة الحمراء، يجب على السائق المُقترِب التوقف على بُعد لا يقل عن كم من الحافلة؟","options":["10 أقدام","15 قدمًا","20 قدمًا","30 قدمًا"],"explanation":"يتطلب القسم SDCL 32-32-6 من السائقين إيقاف المركبة توقفًا تامًا على بُعد 15 قدمًا على الأقل من الحافلة المدرسية والبقاء متوقفين حتى يتوقف وميض الأضواء الحمراء. المصدر: SDCL 32-32-6."},"66":{"q":"بموجب قانون ساوث داكوتا، على أي نوع من الطرق يجوز للسائق المتجه في الاتجاه المعاكس المتابعة دون التوقف لحافلة مدرسية متوقفة مع وميض أضواء حمراء؟","options":["أي طريق سريع به خط منتصف مرسوم","طريق سريع يوفر حارتين أو أكثر للسير في كل اتجاه","أي طريق بحد سرعة مُعلن يزيد عن 45 ميلاً في الساعة","فقط طريق سريع بين الولايات خاضع للتحكم الكامل في الوصول"],"explanation":"يعفي القسم SDCL 32-32-6 السائق المُقترِب من الاتجاه المعاكس على طريق سريع به حارتان أو أكثر للسير في كل اتجاه من التوقف لحافلة مدرسية مع وميض أضواء حمراء. المصدر: SDCL 32-32-6."},"67":{"q":"على أي مسافة قبل التوقف يجب على مُشغِّل الحافلة المدرسية في ساوث داكوتا تشغيل أضواء التنبيه الكهرمانية؟","options":["لا تقل عن 100 ولا تزيد عن 300 قدم","لا تقل عن 200 ولا تزيد عن 400 قدم","لا تقل عن 300 ولا تزيد عن 500 قدم","لا تقل عن 500 ولا تزيد عن 700 قدم"],"explanation":"يتطلب القسم SDCL 32-32-5.2 أن تكون أضواء التنبيه الكهرمانية مُضاءة على مسافة لا تقل عن 300 قدم ولا تزيد عن 500 قدم قبل النقطة التي يُستقبَل أو يُنزَل فيها التلاميذ. المصدر: SDCL 32-32-5.2."},"68":{"q":"على الطرق السريعة الريفية بين الولايات في ساوث داكوتا المُعلنة بالحد الأقصى، ما حد السرعة لمقطورة الجرار مقارنةً بسيارة الركاب؟","options":["الشاحنات 65 ميلاً في الساعة؛ السيارات 80 ميلاً في الساعة","الشاحنات 70 ميلاً في الساعة؛ السيارات 75 ميلاً في الساعة","الشاحنات 75 ميلاً في الساعة؛ السيارات 80 ميلاً في الساعة","الشاحنات 80 ميلاً في الساعة؛ السيارات 80 ميلاً في الساعة (الحد نفسه)"],"explanation":"تُعلِن ساوث داكوتا حدًا قدره 80 ميلاً في الساعة على معظم الطرق الريفية بين الولايات وتطبّق الحد نفسه على الشاحنات والسيارات؛ ولا يوجد حد سرعة أدنى منفصل للشاحنات. المصدر: SDCL الفصل 32-25؛ لوائح السرعة لـ SDDOT."},"69":{"q":"في ساوث داكوتا، لا يجوز للمركبة المركّبة الأطول (LCV) العاملة على الطريق بين الولايات أن تتجاوز أي سرعة قصوى؟","options":["55 ميلاً في الساعة","60 ميلاً في الساعة","65 ميلاً في الساعة","70 ميلاً في الساعة"],"explanation":"تُقيِّد القاعدة الإدارية لولاية ساوث داكوتا 70:03:01:61 المركبات المركّبة الأطول بحد أقصى قدره 65 ميلاً في الساعة على الطرق السريعة بين الولايات، حتى حيث يكون الحد المُعلن أعلى. المصدر: ARSD 70:03:01:61."},"70":{"q":"في ساوث داكوتا، عندما تقترب مركبة تحمل لوحات مواد خطرة من معبر سكة حديد يجب التوقف عنده، أين يجب أن تتوقف؟","options":["في حدود 5 إلى 25 قدمًا من أقرب قضيب","في حدود 15 إلى 50 قدمًا من أقرب قضيب","في حدود 25 إلى 75 قدمًا من أقرب قضيب","في حدود 50 إلى 100 قدم من أقرب قضيب"],"explanation":"يجب على المركبة التي تحمل لوحات التوقف في حدود 15 إلى 50 قدمًا من أقرب قضيب، ثم النظر والإنصات قبل العبور. المصدر: دليل CDL لساوث داكوتا؛ 49 CFR 392.10."},"71":{"q":"أثناء عبور قضبان السكة الحديد في ساوث داكوتا، ما الذي يجب على سائق الحافلة أو المركبة التي تحمل لوحات ألا يفعله؟","options":["النظر والإنصات للقطارات","تغيير التروس أثناء وجوده على القضبان","استخدام ترس منخفض للحفاظ على القوة","التأكد من وجود مساحة لتجاوز القضبان"],"explanation":"يجب على السائقين عدم تغيير التروس أثناء عبور القضبان، تجنبًا لتعطّل المحرك على المعبر؛ اعبر بترس لا يحتاج إلى تغيير. المصدر: دليل CDL لساوث داكوتا؛ 49 CFR 392.10/392.11."},"72":{"q":"عند أي معبر سكة حديد لا يُطلب عمومًا من سائق الحافلة في ساوث داكوتا التوقف الإلزامي؟","options":["معبر يتحكم فيه ضابط شرطة أو مُوجِّه يُسيِّر حركة المرور عبره","معبر متعدد القضبان في منطقة ريفية مفتوحة","معبر بلا بوابات أوتوماتيكية","معبر على منحدر هابط شديد"],"explanation":"لا يُطلب التوقف الإلزامي حيث يُوجِّه ضابط شرطة أو مُوجِّه حركة المرور، أو عند معبر مُعفى/مهجور أو معبر فرعي صناعي، أو عندما تتحكم إشارة مرور خضراء في المعبر. المصدر: دليل CDL لساوث داكوتا؛ 49 CFR 392.10."},"73":{"q":"كم عدد المثلثات التحذيرية العاكسة التي يجب على السائق التجاري في ساوث داكوتا حملها ووضعها عند التوقف على جانب الطريق؟","options":["مثلث واحد","مثلثان","ثلاثة مثلثات","أربعة مثلثات"],"explanation":"يجب على المركبة التجارية (CMV) حمل ونشر ثلاثة مثلثات عاكسة (أو أجهزة مكافئة)، توضع في غضون 10 دقائق من التوقف. المصدر: دليل CDL لساوث داكوتا؛ 49 CFR 392.22."},"74":{"q":"على طريق سريع ذي حارتين باتجاهين في ساوث داكوتا، أين يجب وضع المثلثات التحذيرية الثلاثة عند توقف شاحنة؟","options":["جميع المثلثات الثلاثة على بُعد نحو 100 قدم خلف المركبة","على بُعد نحو 10 أقدام و100 قدم و200 قدم خلف المركبة","في حدود 10 أقدام على جانب حركة المرور، ونحو 100 قدم أمام المركبة و100 قدم خلفها","على بُعد نحو 50 قدمًا أمام المركبة وبجانبها وخلفها"],"explanation":"على طريق ذي حارتين باتجاهين، ضع مثلثًا واحدًا في حدود 10 أقدام على جانب حركة المرور وواحدًا على بُعد نحو 100 قدم خلف المركبة وواحدًا على بُعد نحو 100 قدم أمامها. المصدر: دليل CDL لساوث داكوتا؛ 49 CFR 392.22."},"75":{"q":"على طريق سريع مقسوم أو باتجاه واحد في ساوث داكوتا، أين توضع المثلثات التحذيرية الثلاثة خلف شاحنة متوقفة؟","options":["على بُعد 10 و50 و100 قدم","على بُعد 10 و100 و200 قدم","على بُعد 25 و100 و300 قدم","على بُعد 50 و150 و250 قدمًا"],"explanation":"على طريق مقسوم أو باتجاه واحد، ضع المثلثات على بُعد نحو 10 أقدام و100 قدم و200 قدم باتجاه حركة المرور المُقترِبة خلف المركبة. المصدر: دليل CDL لساوث داكوتا؛ 49 CFR 392.22."},"76":{"q":"بموجب قاعدة الالتزام باليمين في ساوث داكوتا، متى يجب على السائق استخدام الحارة اليمنى أو الجزء الأيمن من الطريق؟","options":["فقط على الطرق السريعة بين الولايات","عند السير بسرعة أبطأ من السرعة الطبيعية لحركة المرور، باستثناء عند التجاوز أو عندما يكون استخدام الحارة اليمنى غير عملي","فقط بين غروب الشمس وشروقها","فقط عندما تتبعه شاحنة"],"explanation":"يتطلب القسم SDCL 32-26-1 القيادة على النصف الأيمن من الطريق، وبالنسبة لحركة المرور الأبطأ من الطبيعية، الالتزام باليمين باستثناء عند التجاوز أو حيث يكون استخدام الحارة اليمنى غير عملي. المصدر: SDCL 32-26-1."},"77":{"q":"ما الحد الأقصى القانوني لعرض المركبة في ساوث داكوتا قبل أن يصبح تصريح الحمولة الزائدة الحجم مطلوبًا؟","options":["8 أقدام و0 بوصة","8 أقدام و6 بوصات","9 أقدام و0 بوصة","10 أقدام و0 بوصة"],"explanation":"حد العرض القانوني في ساوث داكوتا بدون تصريح هو 8 أقدام و6 بوصات (102 بوصة)؛ وأي شيء أعرض يتطلب تصريح حمولة زائدة الحجم. المصدر: قواعد تصريح الحمولة الزائدة الحجم لـ SDDOT/دورية ساوث داكوتا للطرق السريعة؛ SDCL الفصل 32-22."},"78":{"q":"في ساوث داكوتا، خلال أي ساعات يجوز عمومًا لحامل تصريح الحمولة الزائدة الحجم (العرض غير القابل للتجزئة) السفر؟","options":["24 ساعة في اليوم، في أي يوم","فقط من الإثنين إلى الجمعة، في ضوء النهار فقط","من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها، بما في ذلك عطلات نهاية الأسبوع","فقط بين الساعة 9 صباحًا و4 عصرًا في أيام الأسبوع"],"explanation":"يجوز للحمولات الزائدة الحجم التحرك من نصف ساعة قبل شروق الشمس إلى نصف ساعة بعد غروبها، بما في ذلك السبت والأحد؛ أما الحمولات الزائدة الوزن فقط فيجوز لها التحرك باستمرار. المصدر: قواعد تصريح الحمولة الزائدة الحجم لـ SDDOT/دورية ساوث داكوتا للطرق السريعة."},"79":{"q":"أي وكالة في ساوث داكوتا تُصدِر رخص القيادة التجارية؟","options":["دائرة السلامة العامة في ساوث داكوتا، برنامج ترخيص السائقين","دائرة النقل في ساوث داكوتا","مكتب عمدة المقاطعة التي يقيم فيها مقدّم الطلب","الإدارة الفيدرالية لسلامة الناقلات بالمحركات"],"explanation":"في ساوث داكوتا، تُصدر رخص CDL من قِبل دائرة السلامة العامة (DPS) من خلال برنامج ترخيص السائقين التابع لها (بيير، ساوث داكوتا). تتولى SD DOT التصاريح والطرق، وليس ترخيص السائقين. المصدر: ترخيص السائقين في SD DPS / معلومات شاحنات ساوث داكوتا (sdtruckinfo.sd.gov)، دليل الناقل بالمحركات الفصل 8."},"80":{"q":"ما الحد الأدنى للسن للحصول على رخصة CDL في ساوث داكوتا للقيادة فقط في التجارة داخل الولاية (ضمن ساوث داكوتا)؟","options":["16","18","19","21"],"explanation":"تسمح ساوث داكوتا برخصة CDL في سن 18 للتجارة داخل الولاية؛ أما التجارة بين الولايات (عبر حدود الولايات) فتتطلب سن 21. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، مؤهلات CDL (sdtruckinfo.sd.gov)."},"81":{"q":"ما الحد الأدنى للسن للحصول على رخصة CDL في ساوث داكوتا للتجارة بين الولايات (القيادة عبر حدود الولايات)؟","options":["18","19","20","21"],"explanation":"تتطلب القيادة في التجارة بين الولايات حدًا أدنى للسن قدره 21 في ساوث داكوتا؛ ويقتصر السائقون من سن 18 إلى 20 على العمليات داخل الولاية. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، مؤهلات CDL (sdtruckinfo.sd.gov)."},"82":{"q":"ما مدة صلاحية تصريح المتعلّم التجاري (CLP) في ساوث داكوتا؟","options":["30 يومًا","6 أشهر","سنة واحدة","سنتان"],"explanation":"يُصدَر تصريح CLP في ساوث داكوتا لمدة سنة واحدة للتدريب خلف المقود على الطرق العامة. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، مؤهلات CDL (sdtruckinfo.sd.gov)."},"83":{"q":"في ساوث داكوتا، كم يجب أن ينتظر مقدّم الطلب بعد إصدار تصريح المتعلّم التجاري قبل إجراء اختبار مهارات CDL؟","options":["لا يُطلب أي فترة انتظار","7 أيام على الأقل","14 يومًا على الأقل","30 يومًا على الأقل"],"explanation":"هناك فترة انتظار مدتها 14 يومًا بين تاريخ إصدار تصريح CLP والتاريخ الذي يمكن فيه إكمال اختبار المهارات. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، اختبارات رخصة القيادة التجارية (sdtruckinfo.sd.gov)؛ يعكس القانون الفيدرالي 49 CFR 383.25."},"84":{"q":"من بين كم فئة من فئات الإقرار الذاتي يجب على مقدّم طلب CDL في ساوث داكوتا الاختيار فيما يتعلق بنوع التجارة والمتطلبات الطبية؟","options":["اثنتان","ثلاث","أربع","خمس"],"explanation":"هناك أربع فئات للإقرار الذاتي: غير المُعفى بين الولايات (NI)، والمُعفى بين الولايات (EI)، وغير المُعفى داخل الولاية (NA)، والمُعفى داخل الولاية (EA). المصدر: الإقرار الطبي لـ CDL في SD DPS؛ 49 CFR 383.71."},"85":{"q":"السائق في ساوث داكوتا الذي يعمل عبر حدود الولايات ويُطلب منه استيفاء معايير التأهيل البدني الفيدرالية لـ DOT يُقِرّ ذاتيًا بأنه ضمن أي فئة؟","options":["غير المُعفى بين الولايات (NI)","المُعفى بين الولايات (EI)","غير المُعفى داخل الولاية (NA)","المُعفى داخل الولاية (EA)"],"explanation":"تعني فئة غير المُعفى بين الولايات (NI) أن السائق يعمل في التجارة بين الولايات ويجب أن يستوفي متطلبات الشهادة الطبية الفيدرالية لـ DOT (شهادة فاحص طبي سارية). المصدر: الإقرار الطبي لـ CDL في SD DPS؛ 49 CFR 383.71."},"86":{"q":"عندما يُقِرّ مقدّم طلب CDL في ساوث داكوتا ذاتيًا بأنه غير مُعفى بين الولايات، ما المستند الذي يجب الاحتفاظ به في ملف لدى الولاية ليبقى ساريًا؟","options":["إعفاء بصري من طبيب عيون","شهادة فاحص طبي سارية لـ DOT","إقرار خطي موقّع من صاحب العمل","سجل قيادة موثّق"],"explanation":"يجب على السائقين غير المُعفين الاحتفاظ بشهادة فاحص طبي سارية (بطاقة DOT الطبية) في ملف لدى برنامج ترخيص السائقين؛ وبدونها تُخفَّض رخصة CDL. المصدر: الإقرار الطبي لـ CDL في SD DPS."},"87":{"q":"من المُخوَّل بإجراء الفحص البدني للشهادة الطبية لـ DOT لحامل رخصة CDL في ساوث داكوتا؟","options":["أي طبيب مرخّص يختاره السائق","فاحص طبي مدرَج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA","فقط طبيب يعمل لدى دائرة السلامة العامة في SD","ممرضة في أي عيادة رعاية عاجلة"],"explanation":"يجب أن يُجري الفحص أخصائي طبي مدرَج في السجل الوطني للفاحصين الطبيين المعتمدين التابع لـ FMCSA. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، مؤهلات CDL (sdtruckinfo.sd.gov)؛ السجل الوطني (nationalregistry.fmcsa.dot.gov)."},"88":{"q":"بعد الفحص البدني لـ DOT لحامل رخصة CDL في ساوث داكوتا، كيف تصل شهادة الفاحص الطبي عمومًا إلى برنامج ترخيص السائقين بالولاية؟","options":["يجب على السائق تسليمها يدويًا إلى دار المحكمة","يُرسلها الفاحص إلكترونيًا إلى ترخيص السائقين في غضون يومَي عمل عبر السجل الوطني","يُرسلها صاحب عمل السائق بالبريد فقط","تصبح سارية تلقائيًا دون أي تقديم"],"explanation":"يُقدِّم الفاحصون الطبيون المعتمدون الشهادة إلكترونيًا إلى ترخيص السائقين في ساوث داكوتا في غضون يومَي عمل عبر السجل الوطني التابع لـ FMCSA؛ ويجوز للسائقين أيضًا تقديم نسخة بالفاكس أو البريد الإلكتروني أو البريد. المصدر: SD DPS / معلومات شاحنات ساوث داكوتا (sdtruckinfo.sd.gov)."},"89":{"q":"ما الحد الأقصى للمدة التي قد تكون فيها شهادة الفاحص الطبي لـ DOT سارية لحامل رخصة CDL في ساوث داكوتا؟","options":["6 أشهر","سنة واحدة","سنتان","5 سنوات"],"explanation":"تكون شهادة الفاحص الطبي سارية لمدة تصل إلى سنتين، وقد تُصدَر لمدة أقصر اعتمادًا على الحالة الطبية للسائق. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، مؤهلات CDL (sdtruckinfo.sd.gov)؛ 49 CFR 391.43."},"90":{"q":"أي اختبار معرفة يجب أن يجتازه كل مقدّم طلب CDL في ساوث داكوتا، بغض النظر عن فئة المركبة أو التظهيرات؟","options":["اختبار المكابح الهوائية","اختبار المعرفة العامة","اختبار المواد الخطرة","اختبار المقطورات المزدوجة/الثلاثية"],"explanation":"يُجرى اختبار المعرفة العامة من قِبل جميع مقدّمي الطلبات؛ أما الاختبارات الأخرى فتُطلب فقط لمركبات أو تظهيرات محددة. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، اختبارات رخصة القيادة التجارية (sdtruckinfo.sd.gov)."},"91":{"q":"يتكوّن اختبار مهارات CDL في ساوث داكوتا من أي ثلاثة أجزاء، مُرتَّبة بالترتيب؟","options":["الامتحان الكتابي وفحص البصر واختبار الطريق","فحص ما قبل الرحلة والتحكم الأساسي في المركبة والقيادة على الطريق","اختبار المكابح الهوائية واختبار الاقتران واختبار الرجوع للخلف","اختبار المعرفة واختبار المحاكاة واختبار القيادة الليلية"],"explanation":"يتكوّن اختبار المهارات من ثلاثة أجزاء: فحص ما قبل الرحلة (فحص المركبة)، ومناورات التحكم الأساسي في المركبة، واختبار القيادة على الطريق. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، اختبارات رخصة القيادة التجارية (sdtruckinfo.sd.gov)."},"92":{"q":"خلال جزء التحكم الأساسي في المركبة من اختبار مهارات CDL في ساوث داكوتا، ما الذي يُطلب من مقدّم الطلب إثباته بشكل أساسي؟","options":["تلاوة دليل CDL بأكمله عن ظهر قلب","تحريك المركبة للأمام وللخلف وإدارتها ضمن منطقة محددة مُعلَّمة بالأقماع","إصلاح نظام المكابح","تحميل وتأمين الحمولات الخطرة"],"explanation":"يُقيِّم التحكم الأساسي في المركبة قدرة السائق على تحريك المركبة للأمام وللخلف وإدارتها ضمن منطقة محددة مُعلَّمة بالأقماع أو الحواجز. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، اختبارات رخصة القيادة التجارية (sdtruckinfo.sd.gov)."},"93":{"q":"في جزء فحص ما قبل الرحلة من اختبار مهارات CDL في ساوث داكوتا، ما الذي يجب على مقدّم الطلب فعله؟","options":["القيادة عبر حركة المرور على الطريق السريع","تحديد مكونات المركبة التي سيفحصها وشرح ما يتحقق منه ولماذا","إظهار الركن الموازي فقط","اجتياز امتحان كتابي منفصل للمواد الخطرة"],"explanation":"يتطلب فحص ما قبل الرحلة من السائق إثبات القدرة على تقييم سلامة المركبة، عبر تحديد عناصر الفحص وشرح ما سيتحقق منه ولماذا. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، اختبارات رخصة القيادة التجارية (sdtruckinfo.sd.gov)."},"94":{"q":"في ساوث داكوتا، إذا رسب مقدّم الطلب في اختبار المعرفة أو المهارات لـ CDL، فما أقرب وقت يمكنه فيه إعادة الاختبار؟","options":["فورًا، في اليوم نفسه","ليس قبل يوم العمل التالي","بعد فترة انتظار مدتها 30 يومًا","بعد 6 أشهر كاملة"],"explanation":"إذا رسبت في أي من الاختبارات فلا يجوز لك إعادة الاختبار قبل يوم العمل التالي؛ ويمكنك الانتظار أطول إذا أردت مزيدًا من الدراسة أو التدرب. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، اختبارات رخصة القيادة التجارية (sdtruckinfo.sd.gov)."},"95":{"q":"في ساوث داكوتا، كم عدد فرص الاختبار التي تغطيها كل رسوم اختبار خلال فترة ستة أشهر؟","options":["واحدة","اثنتان","ثلاث","غير محدودة"],"explanation":"يُسمح لمقدّمي الطلبات بثلاث فرص للاختبار مقابل كل رسوم مدفوعة خلال فترة ستة أشهر. وقد تتغير مبالغ الرسوم الدقيقة، لذا يجب الاعتماد على قواعد الإجراءات بدلاً من المبالغ بالدولار. المصدر: دليل الناقل بالمحركات لـ SD الفصل 8، اختبارات رخصة القيادة التجارية (sdtruckinfo.sd.gov)."},"96":{"q":"بموجب قاعدة تدريب السائقين المبتدئين الفيدرالية (ELDT) التي تطبّقها ساوث داكوتا، أين يجب على مقدّم طلب CDL لأول مرة إكمال التدريب المطلوب؟","options":["أي دورة عبر الإنترنت من اختياره","مزوّد تدريب مدرَج في سجل مزوّدي التدريب (TPR) التابع لـ FMCSA","دورة تُقدَّم فقط من قِبل SD DPS","لا يُطلب أي تدريب رسمي قبل الاختبار"],"explanation":"تتطلب قاعدة ELDT (السارية في 7 فبراير 2022) من المتقدمين المبتدئين إكمال التدريب النظري والتدريب خلف المقود لدى مزوّد مدرَج في سجل مزوّدي التدريب التابع لـ FMCSA قبل إجراء اختبار مهارات CDL (أو، بالنسبة للمواد الخطرة، اختبار المعرفة). المصدر: قاعدة ELDT لـ FMCSA (49 CFR الجزء 380)، تطبّقها SD DPS."},"97":{"q":"على أي مقدّمي طلبات ينطبق المتطلب الفيدرالي لـ ELDT عند الحصول على رخصة CDL في ساوث داكوتا؟","options":["فقط السائقون فوق سن 65","المتقدمون للحصول على رخصة CDL من الفئة A أو B لأول مرة، أو لترقية الفئة، أو لطلب تظهير حافلة مدرسية أو ركاب أو مواد خطرة لأول مرة","فقط المتقدمون المنقولون من خارج الولاية","فقط السائقون الذين يجدّدون رخصة CDL قائمة"],"explanation":"تنطبق قاعدة ELDT على من يحصلون على أول رخصة CDL من الفئة A أو B، أو يقومون بالترقية (مثل من B إلى A)، أو يحصلون على تظهير حافلة مدرسية أو ركاب أو مواد خطرة لأول مرة؛ وهي متطلب لمرة واحدة، وليس للتجديدات الروتينية. المصدر: قاعدة ELDT لـ FMCSA (49 CFR الجزء 380)، تطبّقها SD DPS."},"98":{"q":"ما مدة صلاحية رخصة القيادة التجارية في ساوث داكوتا قبل وجوب تجديدها؟","options":["سنة واحدة","سنتان","4 سنوات","5 سنوات"],"explanation":"تكون رخصة CDL في ساوث داكوتا سارية لمدة خمس سنوات وتنتهي صلاحيتها في عيد ميلاد حاملها؛ ويجوز للحاملين التجديد قبل انتهاء الصلاحية بمدة تصل إلى 180 يومًا، عادةً شخصيًا في محطة فحص تابعة لـ DPS مع فحص للبصر. المصدر: ترخيص السائقين في SD DPS (إرشادات التجديد)."}}};
